INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 201A', 'Financial Accounting', 'Accounting concepts and techniques essential to the administration of a business enterprise: analyzing and recording financial transactions; accounting valuation and allocation practices; preparation, analysis and interpretation of financial statements; international accounting issues.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 201B', 'Managerial Accounting', 'Introduction to managerial accounting; product costing; budgetary control and responsibility accounting; analysis and techniques for aiding management planning and control decisions; basic income tax concepts for planning business transactions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 301A', 'Intermediate Accounting', 'Accounting theory; preparation of income statements, balance sheets, and statements of cash flows and comprehensive income; IFRS (International Financial Reporting Standards); present value concepts; assets, revenue recognition and investments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 301B', 'Intermediate Accounting', 'Accounting theory; IFRS (International Financial Reporting Standards); present value concepts; liabilities and stockholders’ equity; pensions; leases; earnings per share; financial statement analysis; accounting changes and error analysis; accounting for income taxes and statement of cash flows.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 302', 'Cost Accounting', 'Accounting information for management of manufacturing and service enterprises; cost records; cost behavior and allocation; product costing and inventory valuation; flexible budgeting; standard costs; responsibility accounting; cost planning and control; and operating decision analysis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 307', 'Accounting Information Systems', 'Organization and implementation of information technology for the collection, organization and presentation of accounting information with an emphasis on enterprise resource planning systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 308', 'Concepts of Federal Income Tax Accounting', 'Federal tax system, federal income taxation relating to federal tax system, federal income taxation relating to individuals, corporations, partnerships and fiduciaries. Federal estate and gift taxes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 401', 'Advanced Accounting', 'Business combinations; meaning, usefulness and methodology of consolidated financial statements; investments and additional advanced topics; consolidated financial statements for overseas units of U.S.-based multinational companies; translations of foreign currencies, derivatives.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 402', 'Auditing', 'Auditing standards and procedures used by financial and operational auditors. Management information and computer systems, internal control, audit evidence, professional responsibilities and legal liabilities, standards of reporting financial information.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 403', 'Accounting for Governmental and Nonprofit Entities', 'Fund accounting as applied to governmental and nonprofit entities; state and federal governments, municipalities, hospitals and universities. Budgets, tax levies, revenues and appropriations, expenditures and encumbrances, various types of funds and accounting statements.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 405', 'Forensic Accounting and Fraud Examination', 'Methods to prevent and detect fraud. Current cases dealing with accounting fraud and appropriate methods to prevent or detect fraudulent behavior.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 408', 'Taxation of Business Entities', 'Additional tax knowledge on tax research, corporate taxation, partnership taxation, S Corps, transfer taxation, gift taxes and accounting for income tax. Other topics, such as SALT, may be included.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 420', 'Advanced Cost Accounting', 'Advanced topics in accounting: strategic profitability analysis; cost allocation and resources; quality and Just-In Time Inventory; and investment decisions and management control.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 422', 'Internal Audit and Control', 'Professional standards and procedures used by internal auditors. Planning, performing, communicating risk based assurance and consulting engagements. Advanced topics in control; governance, risk management, fraud and information technology. Requires departmental permission for non-Accounting undergraduate majors and all graduate students.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 445', 'Valuation Concepts and Topics for Accountants', 'Conceptual framework for valuation. Students will apply the framework in a number of settings they are likely to encounter as accounting professionals (i.e., fair value of financial assets, goodwill impairment).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 460', 'Seminar in Financial Statement Analysis', 'Analysis of demand and supply forces underlying the provision of financial statements; distributional, cross-sectional and time series properties of financial statement numbers; financial decision-making processes and the uses of financial statement information for decision making.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 463', 'Financial Controls for Entrepreneurs', 'Accounting system design for new ventures, including budgeting, purchasing, collections, payroll taxes, safeguards against error and embezzlement, financial reports, cash management and banking relationships. Casework, research and fieldwork with selected local businesses.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 495', 'Internship (1-3)', 'Planned and supervised work experience. May be repeated for a maximum of 6 units. Letter grade or credit/no credit. Requires consent of the department internship adviser and one semester in residence at the university.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 499', 'Independent Study (1-3)', 'Open to qualified undergraduate students desiring to pursue directed independent inquiry. May be repeated for a maximum of 6 units. Not open to students on academic probation. Requires permission of department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 502', 'Accounting Theory and Professional Research', 'Provides an analytical framework for managerial decision-making using accounting information. Explore solutions to professional accounting problems by researching the FASB Codification.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 503', 'Seminar in Accounting Data Analytics', 'Introduction to data extraction, analytic and data visualization tools used in business today, and techniques for Big Data analyses. Hands-on experience with several key tools used to transform raw data into actionable knowledge.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 505', 'Seminar in Auditing', 'Auditing theory and practices; professional ethics; auditing standards; Securities and Exchange Commission and stock exchange regulations; auditor’s legal liability; statement trends and techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 506', 'Seminar in Professional Accounting Communications', 'Compilation and composition of accounting reports and client presentations relating to accountants’ working papers, client engagement letters, management advisory reports and prospectuses.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 507', 'Seminar in Accounting Information Systems', 'Case studies of computer-based accounting systems used by organizations such as universities, banks, industrial corporations and CPA firms. Accounting information, reports, and internal controls.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 508', 'Seminar in Tax Planning', 'Substantive provisions of federal law; tax planning from a corporate viewpoint; case studies of the effect of federal tax law on business decisions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 510', 'Financial Accounting', 'Accumulation, organization and interpretation of financial and quantitative data relevant to the activities of corporate business enterprises; analysis of financial reports; current regulatory reporting requirements with attention to business ethics and an understanding of global reporting issues.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 511', 'Seminar in Managerial Accounting', 'Design and develop cost accounting systems; contemporary cost management concepts; measurement, analysis and use of accounting information for management decisions with attention to current ethical, global and environmental issues. Measurement, analysis and use of information contained in standard and various cost systems for industry sectors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 521', 'Advanced Management Accounting and Controls', 'Integrative aspects of accounting, financial and quantitative data for managerial decision-making; long-term, short-term profit planning; budgetary control; cost analysis; financial analysis and planning; taxation; and transfer pricing.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 572', 'Seminar in Taxation of Corporations and Shareholders Corp. II', 'Federal taxation relating to corporations; organizing, distributions, liquidations and reorganizations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 573', 'Seminar in Taxation of Property and M&A Transactions', 'Concepts, rules and issues with regard to the taxation of transactions involving different types of property. Taxation of property transactions when a buyer acquires another company.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 574', 'Seminar in Taxation of International Business Operations', 'Federal taxation relating to U.S. citizens and corporations with foreign source income and of foreign persons with U.S. source income; planning for foreign operations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 575', 'Seminar in Estate, Gift, Inheritance Taxes and Estate Planning', 'Federal and California death taxes and the planning of personal estates.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 576', 'Seminar in State and Local Taxation', 'Application of interstate income allocations; multi-state tax compact; separate apportionment accounting; foreign country sourced income. California taxes as applied to businesses and individuals.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 577', 'Seminar in Taxation of Employee Compensation', 'Federal taxation relating to employee compensation including pensions and profit sharing, stock options, ESOPs, IRAs, Keoghs, maximum tax 5-year averaging, death benefits, group term life, etc.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 578', 'Seminar in Taxation of Flow-Through Entities', 'Federal taxation relating to partnerships, estates, trusts and other special entities.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 580', 'Seminar in Taxation of S Corporations, LLCs and LLPs', 'Tax consequences of electing and operating as a Subchapter S Corporation, including entity level taxes, distributions and computation of basis. Terminating the S Corporation election and liquidations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 597', 'Accounting Capstone - Professional Research Project', 'Culminating intellectual experience to use knowledge learned. Solve complex accounting problems using analytic tools applied to real world data with guidance from faculty and professionals.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ACCT 599', 'Independent Graduate Research (1-3)', 'May be repeated for credit for a maximum of 6 units. Not open to students on academic notice. Requires approval of department chair and associate dean.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 101', 'Introduction to Ethnic Studies', 'Perspectives through which people of color have come to see themselves in terms of their own heroes, cultures and contributions to the societies in which they live and the world in general. (AFAM 101, ASAM 101, and CHIC 101 are the same course)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 107', 'Introduction to African American Studies', 'Introduction to key texts and topics in African American Studies. Interdisciplinary exploration of social conditions, political engagement, intellectual production and cultural contributions of African Americans.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 190', 'Survey of American History with Emphasis on Ethnic Minorities', 'Survey of American history from prehistoric times (before 1492) to the present with special emphasis on the role of race and ethnicity. (HIST 190, AFAM 190, ASAM 190 and CHIC 190 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 301', 'African American Food Culture', 'Dynamic relationship between African Americans, food culture and food in the U.S. from their earliest beginnings; focusing on the socio-historical, creative, economic and geographic manifestations of the relationship between food culture, identity and wellness.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 304', 'Black Families in America', 'Issues of race, class, gender, sexuality and identity within African American families. Topics will include: black single mothers and welfare, prisons, black middle class families and residential housing, black youth and activism, and LGBT family formations. (AFAM 304 and SOCI 304 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 307', 'Research and Writing in Ethnic Studies', 'Introduction to research and writing in ethnic studies. Issues of research in ethnic studies (e.g., quantitative v. qualitative analysis, reliability/validity) and specific methods of research (e.g., archives, interviews, oral history). Extensive writing. A “C” (2.0) or better is required to satisfy the upper-division writing requirement. (ASAM 307, AFAM 307 and CHIC 307 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 308', 'Black Men in America', 'The diverse and conflicting representations and theories of black masculinity in the U.S. and abroad. Explores tensions between representations and social, economic, and political realities of black men. Analyzes contemporary issues of black masculinities and the post-racial imaginary.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 310', 'Black Women in America', 'Issues in the study of black women in America, including social, political, economic and intellectual development. Historical and contemporary issues as they affect black American women. (AFAM 310 and GSS 310 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 311', 'Race and Relationships', 'How race, ethnicity, gender and class matter in everyday society, emphasizing intrapersonal relationships, racial socialization and the effects of this racial socialization in people’s lives.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 314', 'Pan-African Dance and Movement', 'Theory and practice of movement of African and Haitian peoples. Movement (dance) as quasi-language in perpetuating the life style of African cultures and cultures of African descent.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 320', 'Black Political Thought', 'The black American intellectual from slavery to contemporary times, emphasizing black contributions to American political and social thought, as well as their contributions in America’s social development.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 321', 'Activism, Engagement and Professional Development', 'Planning and community development trends in minority communities in urban, suburban and rural areas. Theoretical perspectives and practices embraced by grassroots planners. Public and private sector approaches. Topics include neighborhood planning, community development, economic development and grassroots organizing.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 322', 'Black Psychology', 'Uses psychological principles and practices to guide students’ comprehension of life as an African American. Introduction to a holistic perspective that expands ways of conceptualizing psychology from an African American world view. (AFAM 322 and PSYC 322 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 324', 'Introduction to African American Literature', 'Literary contributions by major black American authors. Contemporary black writers and the recurring themes of protest and quest for identity. (AFAM 324 and ENGL 324 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 325', 'African American Religions and Spirituality', 'African-American belief systems and denominations. Folk beliefs among Blacks, African-American religious groups and the role of the Black Church in politics and social change in the Black community. (AFAM 325 and RLST 325 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 335', 'History of Racism', 'Historical roots and current expressions of racism. How racism manifests itself through individual, social, political, economic and religious institutions and proposes methods of combating it.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 356', 'African American Music Appreciation', 'Black music in America; the sociological conditions that help produce various forms of black music. (AFAM 356 and MUS 356 are the same course)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 357', 'Blacks in the Performing Arts', 'African-American culture through the performing arts. Blacks in the entertainment industry as a means of understanding and revealing important aspects of African-American culture. (AFAM 357, MUS 357 and THTR 357 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 405', 'Black Representations in Film', 'Critical study of black images in motion pictures, past and present. The tension between historical Black consciousness, authenticity, imitation and alternative adaptations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AFAM 499', 'Independent Study (1-3)', 'May be repeated for a maximum of 6 units. Requires acceptance of the subject by department chair and instructor directing the study.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 101', 'Questioning America', 'What is American culture? Introduction to multiple methods used to understand ideas of America and American culture; explore diverse techniques to investigate questions of power, belonging and everyday life.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 201', 'Introduction to American Studies', 'With the concept of culture as a unifying principle, focus is on four separate time periods in order to provide the framework for an understanding of American civilization. Several different kinds of documents will be used to illustrate the nature and advantages of an interdisciplinary approach.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 300', 'Introduction to American Popular Culture', 'Historical exploration of popular culture in America as it reflects and contributes to the search for meaning in everyday life. Heroes, myths of success, symbols of power, images of romance, consumerism, race and sexual identity.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 301', 'American Experiences', 'American identities and beliefs, through a sampling of historical and contemporary voices from different groups of Americans. Similarities and differences in Americans¿ experiences based on class, race, ethnicity, gender, sexuality, region and other identities.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 320', 'Women in American Society', 'Socio-cultural history of women and women’s movements in American society. Emphasis on 19th and 20th centuries. Cultural models of American womanhood - maternal, domestic, sexual, social - their development and recent changes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 345', 'The American Dream', 'Interdisciplinary analysis, in settings both historical and contemporary, of the myth and reality surrounding the notion of America as a land of unparalleled and unlimited possibilities, especially in the achievement of personal material success.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 350', 'Seminar in Theory and Method of American Studies', 'Understanding and appreciation of methodology, theories of society and images of humanity as they affect American studies contributions to scholarship. Fulfills the course requirement of the university upper-division baccalaureate writing requirement for American Studies majors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 377', 'Prejudice and American Culture', 'Concepts and methods of American culture studies as tools for better understanding the origins and appeal of intolerance, past and present. Particular focus on racism, ethnic and religious bias, sexism and homophobia.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 395', 'California Cultures', 'Who can claim to be Californian? The ideals and realities of what it means to be Californian; investigating how various identities ¿ of race, class, gender, sexuality, region and generation ¿ have interacted in California¿s cultures, past and present.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 401T', 'Proseminar in American Studies', 'Relationship between theory and application. Analytic readings and research. Check the class schedule for topics being considered. May be repeated once for credit with different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 413', 'The Shifting Role and Image of the American Male', 'Effect of economic, social, political and cultural changes on American males. Emphasizes 19th and 20th centuries.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 419', 'Love in America', 'Changes in the emotional lives of American men and women from the 17th century to the present. Enduring and innovative views on the nature of love and the cultural forces that shape its legitimate and illegitimate expression.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 420', 'Childhood and Family in American Culture', 'Historical and contemporary culture study of childhood and family in America. The idea of childhood, changing concepts of child-rearing, growing up in the American past, the impact of modernization, mother and home as dominant cultural symbols.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 438', 'American Minds: Images of Sickness and Health', 'Cultural changes in American images of the healthy mind. Medical and legal views of insanity, Freud’s impact on American thought, literary treatments of madness and psychological themes in American popular culture.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 473', 'Sexual Orientations and American Culture', 'Cultural construction of the very idea of a sexual orientation. Shifting meanings of erotic attraction and involvement in America, especially regarding people of the same sex, from the colonial period to the present.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 499', 'Independent Study (1-3)', 'Supervised research projects in American Studies to be taken with the consent of instructor and department chair. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 501', 'Theory and Methods', 'The American Studies movement. Its conceptual and methodological development. The way this development was affected by and in turn reflected larger trends in the culture itself.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 502T', 'Seminar: Selected Topics', 'A particular problem or topic as a case study in the use of interdisciplinary methods in American studies. May be repeated once for credit with different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 596', 'American Studies Teaching Tutorial', 'Preparation for community college or university teaching. Small group discussion, lecture-discussion, examinations and teaching strategies. Enrollment requires approval of American Studies graduate coordinator. Course may be repeated for credit, but may only count once on a graduate study plan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 598', 'Thesis', 'Writing of a thesis based on original research and its analysis and evaluation. Requires consent of graduate coordinator.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AMST 599', 'Independent Graduate Research (1-3)', 'May be repeated for a maximum of 6 units. Requires consent of graduate coordinator.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 100', 'Non-Western Cultures and the Western Tradition', 'Changing views of people, nature and culture in Western civilization as related to the impact of non-Western influences, including the use and interpretation of data on non-Western peoples and cultures.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 101', 'Introduction to Biological Anthropology', 'Humans as biological organisms from an evolutionary perspective. Concepts, methods, findings and issues in the study of the Order primates, including the relationships among fossil monkeys, apes and humans, and the significance of genetic diversity in modern populations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 102', 'Introduction to Cultural Anthropology', 'Nature of culture and its significance. Similarities and difference in human cultures. Analyses of family, economy, subsistence, religion, art and other aspects of culture in diverse societies. Central problems of cultural comparison and interpretation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 103', 'Introduction to Archaeology', 'Relationship of archaeology, culture history and process, field methods and analysis of archaeological data; uses and abuses of archaeology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 105', 'Introduction to Anthropology', 'Introduction to basic aspects of anthropology’s sub-fields (biological anthropology, archaeological anthropology, cultural anthropology, and linguistic anthropology), and to an anthropological view of the world, which is grounded in a respect for cultural differences.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 300', 'Language and Culture', 'Language in the context of culture. The symbolic nature of language, speech as performance, non-verbal communication, gendered speech and bias in language. Language acquisition, language change and loss, and factors leading to the invention of writing.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 304', 'Traditional Cultures of the World', 'Comparative, worldwide survey of traditional, selected and well-studied ways of life using ethnographic writings and films. Examines diverse ways of life, with an emphasis on small-scale societies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 305', 'Anthropology of Religion', 'Beliefs and practices in the full human variation of religious phenomena, with an emphasis on primitive religions. Forms, functions, structures, symbolism, and history and evolution of religious systems. (ANTH 305 and RLST 305 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 306', 'Culture and Art', 'Explores different types of creative expression and arts within the cultural context of diverse societies, including such forms as painting, weaving, stories, myths, music, dance, masks, body decoration and sculpture, among others.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 308', 'Culture and Aging: Anthropological Gerontology', 'Anthropological discourse on diverse cultural conceptions of aging as they relate to gender, class, ethnic and religious categories. Cross-cultural comparison of culturally patterned time-table of life-cycle and age-grades for understanding the universals and variability in human aging.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 310', 'Urban Anthropology', 'Cross-cultural investigation of similarities and differences in urbanism with an emphasis on current theoretical and methodological perspectives in the study of social and cultural forms and processes in urban populations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 311', 'Culture and Communication', 'How meanings are created, exchanged and interpreted in both traditional and modern cultures through language, myth and religion, art and architecture, and other means of communication.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 313', 'Psychological Anthropology', 'Relationship of culture to the individual. Child-training in non-western cultures. Survey of concepts, studies and research techniques in psychological anthropology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 315', 'Culture and Nutrition', 'Interrelationships among human nutrition, basic food resources, individual development and socio-cultural organization; includes assessment of student’s nutritional status, beliefs and practices relative to other cultures.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 316', 'Anthropology of Sex and Gender', 'Human sex and gender roles in cross-cultural perspective and the role that gender plays in human social organization. Topics covered include cultural construction of gender; homosexuality, rights of women, evolution and gender. (ANTH 316 and GSS 316 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 321', 'Peoples of Native North America', 'Native peoples of North America; origins, languages, culture areas, cultural history; the impact of European contacts.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 325', 'Peoples of Central and South America', 'Cultural survey of South America. Representative cultural areas before and after contacts with Western countries.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 327', 'Origins of Civilizations', 'Development of civilization in the Old and New Worlds in primary centers such as Mesopotamia, Egypt, the Indus Valley, China, Mesoamerica and Peru, and secondary centers such as the Aegean and Europe.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 329', 'Peoples of the Caribbean', 'Various ethnic groups of the Caribbean, focusing on the description and interpretation of African, European, Asian and Amerindian cultural elements.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 332', 'Gender in Cross-Cultural Perspectives', 'Cross-cultural comparison of beliefs, values, and expectations related to gender roles in diverse societies. Changes in social definitions and perspectives of gender in the contemporary world.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 340', 'Peoples of Asia', 'Asian civilizations and cultural traditions: personality configurations in different culture areas; structure of Asian civilizations; and peasant, tribal and ethnic groups of Asia.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 342', 'Anthropology and Health', 'Uses an evolutionary, comparative and cross-cultural perspective to understand the process and conception of health in different times, places and societies. Topics include: evolutionary medicine, health beliefs, health ecology, culture and health. Computer labs utilizing eHRAF.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 343', 'Human Osteology', 'Techniques in basic identification of human skeletal remains. Aging, sexing, racing and stature reconstruction. For those interested in archaeology, hominid evolution and/or forensic science. (2 hours lecture, 3 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 344', 'Sex, Evolution and Human Nature', 'Evolutionary theory and human evolution; the primate origins of humanity, the evolution of human nature, and the evolutionary foundations of human behavior and cognition.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 347', 'Archaeology and Cultures of Pacific Islands', 'Indigenous peoples, cultures and archaeology of Pacific Islands, including Tahiti, Hawaii and Australia. Forces and processes contributing to social change in island communities and contemporary problems being faced by them.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 350', 'Culture and Education', 'Transmission of values, implicit cultural assumptions and the patterning of education in cross-cultural perspective. American culture and development problems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 423', 'The Ancient Maya', 'Archaeology and ethnohistory of the Maya area of Southern Mesoamerica. Problems of initial settlement of the area and the rise and dynamics of ancient Maya civilization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 424', 'The Aztecs and Their Predecessors', 'Archaeological survey of principal Mesoamerica pre-Columbian cultures north and west of the Maya area. Aztecs and their predecessors, religion, art, architecture, intellectual achievements and the Olmec heritage.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 401', 'Ethnographic Field Methods', 'Anthropological field research by students on various problems using participant observation techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 402', 'Museum Science', 'Methods, principles and techniques used in natural history, and small scientific and historical museums. Scope of exhibit and research collections, care and repair of specimens, acquisitions, storage and preparation of presentations in anthropological, historical, biological and paleontological museums.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 403', 'Archaeological Fieldwork', 'Excavation of a local archaeological site. Archaeological mapping, photography and recording. Laboratory methods of cataloging, preservation, description and interpretation of archaeological materials. Saturday field sessions. May be repeated once for credit as an elective. (1 hour lecture, 6 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 404', 'Analytical Methods in Archaeology', 'Employing physical data collecting techniques (e.g., photographic, paleomagnetic) in the field, and analyzing artifact collections and data from previous field operations in the laboratory. May be repeated once for credit as an elective. (1 hour lecture, 6 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 406', 'Descriptive Linguistics', 'Sounds (phonology), forms and meanings (morphology), and syntax of languages. Examples and problem-solving in various languages. (LING 406 and ANTH 406 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 414', 'Economic Anthropology', 'Ethnology and ethnography of economic life, principally in non-Western societies; operation of systems of production and distribution within diverse cultural contexts.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 415', 'Anthropology of Tourism', 'Tourism and travel as cultural practices. Domestic and international tourism; perspective of hosts and travelers; global economy and tourism; souvenirs, artifacts and symbolic landscapes; tourism as pilgrimage.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 416', 'Anthropological Linguistics', 'Nature and functions of language; language structure and change; classification of languages; use of linguistic evidence in anthropology. (ANTH 416 and LING 416 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 420', 'Visual Anthropology', 'Development of the field of visual anthropology and the changing and diverse approaches to the use of visual media in representing and interpreting other cultures.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 441', 'Human Variation', 'Processes underlying and the theories for the existence of the present variation between and within human populations. Genetics of human populations and the significance of racial classifications. (2 hours lecture, 3 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 443', 'Advanced Topics in Human Osteology', 'Analytical methods stressing morphological examination of human bone in a laboratory setting (determination of human, prehistoric; analysis of fragmented and commingled remains; basic identification and report writing; pathological conditions). For those interested in archaeology, hominid evolution and/or forensic science.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 445', 'Quantitative Methods in Anthropology', 'Develops skills and knowledge in the application of quantitative methods in anthropological research. Integrated approach to research design, data collection, data management and data analysis through hands-on training.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 451', 'Advanced Evolutionary Anthropology', 'Uses life history theory to examine the evolutionary ecology of human behavior. Human life course, resource acquisition, parenting and fertility. Computer labs utilizing eHRAF. (ANTH 451 and BIOL 451 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 453', 'Human Evolutionary Anatomy', 'Uses an evolutionary framework to conduct an in-depth and detailed examination of the structure and function of human anatomical systems, their interaction, and their evolutionary histories and how those histories affect health in modern populations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 454', 'Primate Conservation', 'Uses behavioral ecology and life history theory to understand issues surrounding conservation of non human primates. Develop theoretical background crucial to understanding the population dynamics and ecological principles driving primate conservation strategies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 480', 'History of Anthropology', 'Principal contributions of anthropologists 1850-1950; evolutionary, diffusionist, historical, particularist, configurationalist, and culture and personality approaches in anthropology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 481', 'Contemporary Anthropology', 'Anthropologists from 1950 to present; neoevolutionist, sociological, structuralist, psychological and symbolic approaches.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 490T', 'Undergraduate Seminar in Anthropology', 'Topics in anthropology. May be repeated once for credit with a different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 491', 'Internship in Anthropology', 'Career opportunities. On-the-job training under faculty supervision in museum, industry or governmental service. One or more papers required. May be repeated once for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 498', 'Museum Practicum', 'Practical experience in museum operations, using the facilities of the Anthropology Museum. Exhibit preparation, membership and funding operations, catalogue preparation and outreach activities. May be repeated once for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 499', 'Independent Study (1-3)', 'Individual research project involving either library or fieldwork. Conferences with the adviser as necessary. Results in one or more papers. May be repeated for a maximum of six units. Requires consent of adviser.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 507', 'Grammatical Analysis', 'Word formation in a variety of languages with emphasis on the terminology used to describe morphological representation on various levels; problem solving of selected language data. (LING 507 and ANTH 507 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 510', 'Research Design in Anthropology', 'Introduction to anthropological research. Develop skills in designing a research project; literature search and review; applying quantitative, qualitative and mixed methods; understanding ethical considerations in anthropology; identifying funding opportunities; proposal preparation; and oral presentation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 597', 'Project (3-6)', 'Complete a project derived from original field or laboratory research, and/or from library study. Project could also be a museum exhibit, field report or other project. A copy of the approved written component of the project must be filed in the department through the department graduate program adviser. May be repeated for credit for a maximum of 6 units. Requires consent of project adviser.', 3, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 598', 'Thesis (3-6)', 'Complete a thesis derived from original field or laboratory research, and/or from library study. A copy of the approved thesis must be submitted to the department through the department graduate program adviser, and a copy of the thesis must be approved by the University Graduate Studies Office for submission to the bookstore for binding and microfilming. May be repeated for credit for a maximum of 6 units. Requires consent of thesis adviser.', 3, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ANTH 599', 'Independent Graduate Research (1-3)', 'Individual research involving fieldwork, laboratory, or library study, and conferences with a project adviser as necessary, and resulting in one or more papers. May be repeated for credit for a maximum of 6 units. Requires consent of adviser.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 101', 'Introduction to Art', 'Historical and contemporary art forms of painting, sculpture, architecture and design. Field trips required. Not open to art majors for credit except by permission of Art Department. (3 hours lecture)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 103', 'Two-Dimensional Design', 'Art concepts, aesthetic elements and materials of two-dimensional design and visual organization. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 104', 'Three-Dimensional Design', 'Art concepts, aesthetic elements and materials of three-dimensional design and spatial organization. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 106A', 'Beginning Ceramics', 'Form as related to ceramic materials, tools and processes. Kiln loading and firing, hand building, wheel throwing and raku. (9 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 106B', 'Beginning Ceramics', 'Form as related to ceramics. Glaze batching and its application, and the presentation of ceramic technique. (9 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 107A', 'Beginning Drawing', 'Traditional and contemporary use of drawing materials integrated with visual experiences and art concepts. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 107B', 'Beginning Painting', 'Traditional and contemporary use of painting materials integrated with visual experiences and art concepts. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 117', 'Life Drawing', 'Drawing the live model. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 123', 'Descriptive Drawing', 'Descriptive drawing, rendering techniques and theories representing forms of nature. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 201A', 'Art and Civilization', 'Ideas, forms and styles of the visual arts as they developed in various cultures from prehistoric time to the present. (3 hours lecture)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 201B', 'Art and Civilization', 'Ideas, forms and styles of the visual arts as they developed in various cultures from prehistoric time to the present. (3 hours lecture)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 205A', 'Beginning Crafts', 'Traditional and contemporary concepts and processes with emphasis on design principles in the development of aesthetic forms based on function. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 205B', 'Beginning Crafts', 'Development of esthetic forms based on function, with emphasis on design principles and the creative use of hand tools and power equipment. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 207A', 'Drawing and Painting (Experimental Methods and Materials)', 'Traditional and contemporary concepts. Image-making using various materials and approaches (representation and abstraction). (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 207B', 'Drawing and Painting (Experimental Methods and Materials)', 'Traditional and contemporary concepts. Image-making using various materials and approaches (representation and abstraction). (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 216A', 'Beginning Sculpture', 'Creative use of wood and metal, power equipment and hand tools. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 216B', 'Beginning Sculpture', 'Creative use of wood and metal, power equipment and hand tools. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 223A', 'Lettering and Typography', 'History, design and use of letter forms; the rendering and use of hand-lettered forms. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 223B', 'Lettering and Typography', 'History, design and use of letter forms; techniques for rough and comprehensive layouts and introduction to computer graphics. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 223C', 'Typography into Graphic Design', 'Technology and its application to typographic and graphic design solutions. Conceptual understanding of current technology as medium and tool in the creative process. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 224', 'Introduction to Glass', 'A survey of glass working techniques in glass blowing, hot glass casting, kiln forming, and cold fabrication.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 238', 'Photo Visual Concepts', 'Introductory photography course for art majors. Includes the study of photographic vision and design, visual conceptualization and examination of the qualities of light through the use of instant and automatic cameras. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 255', 'Introduction to 3D Computer Animation', 'Fundamentals of 3D digital animation production. Introduction to the Maya interface and tools necessary to create 3D assets and explore animation principles. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 263', 'Perspective Drawing', 'Introduction to linear perspective systems used to develop and place natural and fabricated forms in space on a two-dimensional surface. Integrated with methods and techniques of rendering light, shadow and reflection on varied subject matter including the human figure. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 300', 'Writing in the Visual Arts', 'Principles, practices and objectives of writing in the visual arts. Includes descriptive, analytical and expressive essays; project and grant proposals; artist’s statements; resumes; and professional correspondence. Satisfies the classroom portion of the upper-division writing requirements for art majors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 306A', 'Advanced Ceramics', 'Traditional and contemporary use of ceramic methods, materials and concepts. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 306B', 'Advanced Ceramics', 'Traditional and contemporary use of ceramic methods, materials and concepts. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 307A', 'Drawing and Painting', 'Concepts, materials and activities in drawing and painting, emphasizing individual skills, ideas, and expression. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 310A', 'Watercolor', 'Watercolor media related to varied subject matter and design applications. Includes field trip activity. Provides skills and concepts useful for school art programs. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 311', 'Foundations of Modern Art', 'History of painting and sculpture from the French Revolution to the end of the 19th century.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 312', 'Modern Art', 'The history of painting, graphic arts and sculpture from late 19th century to World War II.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 315A', 'Jewelry', 'Designing and creating jewelry. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 315B', 'Jewelry', 'Designing and creating jewelry. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 316A', 'Sculpture', 'Sculptural materials and processes. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 316B', 'Sculpture', 'Sculptural materials and processes. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 317A', 'Life Studies, Drawing', 'Drawing from the live model. Observation and anatomy. Concepts and techniques in drawing the figure. May be repeated for credit for a maximum of 6 units. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 317B', 'Life Studies, Painting', 'Painting from the live model. Observation, structure and color. Concepts and techniques in painting the figure. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 317C', 'Sculpting Life Forms', 'Three-dimensional investigation of any life form, its characteristics and expressive possibilities. May be repeated for credit for a maximum of 6 units. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 318A', 'Drawing and Painting the Head and Hands', 'Construction and anatomy of the human head and hands, and their principal use in drawing, painting and illustration. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 320', 'History of Architecture Before the Modern Era', 'Selected monuments from Stonehenge through the late Baroque. Interrelationship between patronage, style, function, structural principles and technological developments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 323A', 'Graphic Design', 'Development and projection of ideas in relation to the technical, aesthetic and psychological aspects of advertising art. Intermediate use of computer graphics. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 323B', 'Graphic Design', 'Development and projection of ideas in relation to the technical, aesthetic and psychological aspects of advertising art. Intermediate use of computer graphics. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 324', 'Beginning Glass Casting', 'Hot glass laboratory equipment and casting techniques. Introduction to hot pour, sand and kiln casting. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 326A', 'Ceramic Sculpture', 'Concepts, materials and investigation of sculptural forms, emphasizing individual growth. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 326B', 'Ceramic Sculpture', 'Concepts, materials and investigation of sculptural forms, emphasizing individual growth. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 336', 'Moldmaking and Cast Sculpture', 'Theories and techniques of rigid and flexible moldmaking incorporated with both cold material and hot metal casting processes. Recommended for concentrations in Entertainment Art/Animation, Ceramics and Crafts; required for Sculpture majors. (9 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 338A', 'Creative Photography', 'Photographic media as a personal expression. Historical attitudes and processes; new materials and contemporary aesthetic trends. Field trips required. (9 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 338B', 'Creative Photography', 'Photographic medium as personal expression. Historical and contemporary aesthetic issues. Exploration of black and white, color and digital media. Field trips required. (9 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 346', 'Kinetic Sculpture', 'Kinetic sculpture is sculpture in motion. Theory and practice of creating sculpture that uses both motorized and nonmotorized means of activation. History of the medium and basic fabrication techniques. (9 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 347A', 'Printmaking Etching', 'Concept development, exploration and materials involved in printmaking techniques. Includes etching and aquatint. (9 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 348', 'Artists’ Books', 'Personal vision and concepts applied to the book form as art; the history and aesthetics of artists’ books. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 357', 'Woodcuts and Monotypes', 'Woodcut and monotype as a means of personal expression. Traditional, as well as contemporary materials and trends. May be repeated once for credit. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 363A', 'Illustration', 'Story, book, magazine and film illustration. May be repeated once for credit. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 363B', 'Illustration', 'Computer aided illustration. May be repeated once for credit. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 363C', 'Digital Narrative Illustration', 'Narrative illustration using advanced digital painting programs and techniques. Theory of illustration concepts, composition and current trends in story illustration as it relates to digital media. May be repeated once for credit. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 364A', 'Stained Glass', 'Architectural and autonomous stained glass design and craftsmanship. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 364B', 'Stained Glass/Kiln Working', 'Flat glass fusing and slumping. Designs are fused together in kilns and slumped over or into molds to create sculptural relief and low vessel forms. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 367', 'Elements of Sequential Art', 'Theory and practice of pictorial narrative in film story-board and graphic novel. Character and scenic design; story sketch, “breakdown” and production design. Considerations: plot, scene, exposition, transition and continuity. Individual and team projects. May be repeated once for credit. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 373', 'Cartooning and Caricature', 'Principles and practices of cartooning and caricature construction, anatomy and expression. Historical overview of the field with an emphasis on professional applications and the impact of computer graphics. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 380', 'Art and Child Development', 'Art concepts, materials and processes as they relate to child development. May include a service-learning component. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 401', 'History of Women Artists', 'Study of art made by women in the context of major art historical developments from the 10th century to the present. Analysis of images of women and the evolution of gender stereotypes in art. (3 hours lecture)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 410', 'The Digital Studio', 'Digital studio as a site for experimentation in image making and visual media expression. Computer applications for creating and manipulating images and media are fundamental for the contemporary visual artist. May be repeated once for credit. (6 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 413', 'History of Contemporary Art', 'Major art movements and aesthetic discourses grasping the shift from modern to contemporary. Artists’ writings and including geographies outside the U.S. and Europe, concentrating on concepts that challenged our understanding of what is considered “art.” ART 312 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 418', 'Seminar in Creative Photography', 'Introduces studio art majors to photographic and media criticism and theory. Provides studio artists with the necessary theoretical background and context for creating and understanding their work in our current media culture. May be taken for credit for a maximum of nine units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 424A', 'Glass Blowing', 'Advanced level; designing, analyzing and developing concepts to create contemporary glasswork. Exploring the material while expanding on technical skills and conceptual depth in glass. May be repeated once for credit. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 424B', 'Glass Blowing', 'Creating hand-blown glassware and sculpture from molten glass using traditional and contemporary tools and techniques. May be repeated once for credit. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 431', 'Renaissance Art', 'Painting, sculpture and architecture from the late 13th to 16th centuries in Italy.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 439', 'Creative Photo Studio Projects', 'Advanced technical class to perfect and refine photographic skills. Integrate technical skills with creative options. May be taken for credit for a maximum of nine units. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 441', 'Media Exploration for Teaching Art', 'Art media used in secondary school art programs today, focusing on secondary levels. Materials for art curriculum and lesson planning. Two- and three-dimensional media in subject matter applications. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 448', 'Special Studies: Artists’ Books and Art', 'Studio art course for advanced students who want to continue to explore the book form as it relates to their personal aesthetic goals. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 453', 'Exhibition Design', 'Technical and aesthetic experience in problem-solving exhibition design concepts, evaluation and design analysis. Production of exhibitions in the University Art Gallery; their selection, design, installation, lighting and supportive interpretive material. May be repeated for credit for a maximum of 6 units. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 462', 'Latin American Art History: 1400 - Present', 'History of art and architecture of select regions and nations of Latin America, from Contact to present. Major monuments and art movements. (ART 462 and CHIC 462 are the same course)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 465', 'Art of Sub-Saharan Africa', 'Art and architecture of sub-Saharan Africa from c. 300 BC to present. Relation between art and culture.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 466', 'Museum Education', 'History of museum education, its philosophy and issues. Relationship with other museum departments, outreach programs, new technology. Events organization, writing interpretive materials, budgets and grants, conducting tours. Lectures, field trips and guest speakers.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 470', 'Photography and Social History', 'Photography from ancient optical observations through 19th-century invention to 20th-century acceptance as an art form. Aesthetic movement and influential innovators. Lectures, slides and class discussion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 478', 'Studio Expanded: Other Genre', 'Various methods of expanding traditional studio approaches through the investigation of installation, performance and video art. May be repeated for credit for a maximum of 12 units, but no more than 3 units in a single semester. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 479', 'Video Art and the Moving Image', 'Contemporary and historic practices in video and the role time plays in moving image arts. Production and post-production fundamentals, including camera work, editing, audio recording, storytelling and relationships between images and sound.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 481', 'Seminar in Art History', 'Study and evaluation in one area of art history and appreciation. May be repeated once for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 483A', 'Special Studies in Graphic Design', 'Advanced use of computer graphics. Maximum of 12 units of credit (repeatable as upper-division electives), but no more than 3 units in a single semester without permission of instructor. (6 hours activity). ART 483E recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 483B', 'Visual Development and Background Painting', 'Story concepts, research, design and media for rendering and painting background environments. Historical precedents, color theory, perspective, theatrical composition, painting and drawing media, and stylization for dramatic impact as it relates to visual development. May be repeated for credit for a maximum of 6 units. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 483C', 'Special Studies in Illustration', 'May be repeated for credit for a maximum of 12 units, but no more than 3 units in any one area in a single semester without permission of instructor. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 483E', 'Computer Assisted Graphics', 'Theory and practice of design using the computer. Numerous applications of the computer through lecture demonstration, studio/laboratory experiences, guest speakers and field trips. Maximum of 12 units for credit (repeatable as upper division electives), but no more than 3 units in a single semester without permission of instructor. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 483F', 'Design for Interactive Art', 'Creating interactive art and design projects. Concentration in the advanced visual organization systems of art and design and how to apply those techniques to an interactive computer environment. May be repeated once for credit (as upper-division elective). (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 483G', 'Entertainment Graphics', 'Structure, procedure and standards of the entertainment design field. Students will work on projects from a major entertainment design group, developing concepts and designs for comparison with professional solutions. May be repeated once for credit (as upper-division elective). (6 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 483H', 'Landscape Painting and Location Drawing', 'Theory and practice of representational art as applied to landscape as subject. Researching drawing and painting concepts and their historical precedents stressed in the studio and on location. May be repeated once for credit. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 483I', 'Motion Graphics Design', 'Translating traditional graphic design into time and motion-based design. Historical precedents, film nomenclature, storyboarding, software/hardware for the creation of film titles, station/program identification (logo/logotypes), promotion graphics. May be repeated once for credit. Knowledge of film production/editing helpful. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 484A', 'Ceramics', 'May be taken for credit for a maximum of 12 units, but no more than three units in any one area in a single semester without permission of instructors. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 484B', 'Glass Blowing', 'May be taken for credit for a maximum of 12 units, but no more than three units in any one area in a single semester without permission of instructors. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 484C', 'Glass Casting', 'May be taken for credit for a maximum of 12 units, but no more than three units in any one area in a single semester without permission of instructors. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 485A', 'Special Studies in Jewelry', 'Advanced techniques and processes in the design and conceptual development of body ornamentation/jewelry. Required for the Jewelry/Metalsmithing concentration. May be repeated for a maximum of 12 units, but no more than three units in a single semester. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 485C', 'Metalsmithing', 'Advanced theories, processes and designing metal forms using varied techniques in smithing: fabrication, forging and raising. Research in contemporary and historical metalsmithing and 3-D metal forms. Required for the Jewelry and Metalsmithing concentration. May be repeated for a maximum of 12 units, but no more than three units in a single semester. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 486A', 'Modeling and Fabrication', 'May be taken for credit for a maximum of 12 units, but no more than three units in a single semester. Requires consent of instructor. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 487A', 'Senior Critique, Drawing and Painting', 'Portfolio building, individual explorations, advanced concepts, varied materials. Traditional and contemporary approaches. Improve original artworks for exhibitions, graduate study, grants, special projects, collaborations, etc. May be repeated for a maximum of 9 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 487B', 'Special Studies, Life Painting', 'Perceptual, traditional, and contemporary approaches. Improve original artworks for exhibitions, graduate study, grants, special projects, collaborations, etc. May be repeated for a maximum of 9 units. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 487C', 'BFA Capstone, Drawing and Painting', 'Portfolio building, individual explorations, advanced concepts, varied materials. Traditional and contemporary approaches. Improve original artworks for exhibitions, graduate study, grants, special projects, collaborations, etc. May be repeated for a maximum of 9 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 487D', 'Special Studies, Printmaking', 'Printmaking concepts and explorations of materials with traditional and multimedia approaches. Improve original artworks for exhibitions, graduate study, grants, special projects, collaborations, etc. (ART 487D is a continuation of ART 247, ART 347A and ART 347B) May be repeated for a maximum of 12 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 487E', 'Special Studies in Entertainment Art/Animation', 'Capstone portfolio/reel building experience. Various, defined entertainment art/animation topics. Maximum of 12 units, but no more than 3 units in any one area in a single semester without permission of instructors. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 489', 'Special Studies in Creative Photography', 'Photography as personal expression. May be repeated for credit for a maximum of 12 units, but no more than 3 units in a single semester. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 495', 'Internship in Art', 'Work in a specific art field in business or industry. May be repeated once for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 499', 'Independent Research (1-3)', 'Open to advanced students in art with consent of department chair and written consent of instructor. May be repeated for credit for a maximum of 9 units, but no more than 6 units in a single semester.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 500A', 'Graduate Seminar in Major Field', 'Directed research in the area of major emphasis. Oral and written material on historical backgrounds and developments in art as they relate to individual intent as an artist and in support of the master’s project. ART 500A and ART 500B are both required to meet the graduate writing requirement. Requires classified standing.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 500B', 'Graduate Seminar in Major Field', 'Problems and issues in art. Intellectual clarification and verbal articulation of individual intent as an artist. Oral and written material in support of the master’s project. ART 500A and ART 500B are both required to meet the graduate writing requirement. Requires classified standing; ART 500A recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 500C', 'Graphic Design Graduate Seminar', 'Directed preparatory written and visual research for the thesis document within graphic design. Taken with the chair or member of the individual graduate student’s committee.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 500D', 'Graphic Design Thesis', 'Developing a written and visual thesis within the graphic design MFA program that either proves or disproves a hypothesis. Taken with either the chair or member of the individual graduate student’s committee.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 503A', 'Graphic Design', 'Planning, development and evaluation of individual projects. May be taken for credit for a maximum of twelve units in each area, but no more than three units in any one area in a single semester without permission of instructions. Requires classified standing. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 503C', 'Illustration', 'Planning, development and evaluation of individual projects. May be taken for credit for a maximum of twelve units in each area, but no more than three units in any one area in a single semester without permission of instructions. Requires classified standing. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 503D', 'Exhibition Design', 'Provides conceptual and technical tools to materialize a curatorial idea into exhibition design. Learn the aspects involved in each phase of creating and producing an art exhibition and apply museum studies theory to critically analyze art displays.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 503H', 'Landscape Painting and Location Drawing', 'Theory and practice of representational art as applied to landscape as subject. Research of drawing and painting concepts and their historical precedents stressed in the studio and on location. May be repeated once for credit. Requires classified standing in Illustration or Drawing and Painting, or consent of instructor. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 504A', 'Ceramics', 'Planning, development and evaluation of individual projects in ceramics, glass blowing and glass casting. May be taken for credit for a maximum of twelve units in each area but no more than three units in a single semester without permission of instructors. Requires classified standing. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 504B', 'Glass Blowing', 'Planning, developing and evaluating of individual projects in glass blowing. May be repeated for credit for a maximum of 12 units, but no more than three units in a single semester without permission of instructors. Requires classified standing. (9 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 504C', 'Glass Casting', 'Planning, developing and evaluating individual projects in glass casting. May be repeated for a maximum of 12 units, but no more than three units in a single semester without permission of instructors. Requires classified standing. (9 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 505A', 'Jewelry', 'Planning, development and evaluation of individual projects listed below. May be taken for credit for a maximum of twelve units in each area, but no more than three units in a single semester. Requires classified standing. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 506A', 'Graduate Problems in Sculpture', 'Planning, developing and evaluating individual projects in sculpture. May be repeated for credit for a maximum of 12 units in each area, but no more than 3 units in a single semester without permission of instructors. Requires classified standing. (6 hours activity).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 506B', 'Graduate Problems in Sculpture', 'Planning, developing and evaluating individual projects in sculpture. May be repeated for credit for a maximum of 12 units in each area, but no more than 3 units in a single semester without permission of instructors. Requires classified standing. (6 hours activity).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 507A', 'Graduate Seminar: Painting and Image Making', 'Planning, development and evaluation of individual projects listed below. Maximum of 12 units in each area, but no more than three units in a single semester without permission of instructors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 507B', 'Graduate Studies: The Figure', 'Planning, development and evaluation of individual projects listed below. Maximum of 12 units in each area, but no more than three units in a single semester without permission of instructors. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 507C', 'Special Topics in Art', 'Planning, development and evaluation of individual projects listed below. Maximum of 12 units in each area, but no more than three units in a single semester without permission of instructors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 507D', 'Printmaking', 'Planning, developing and evaluating individual projects. May be repeated for a maximum of 12 units, but no more than three units in a single semester without permission of instructors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 508A', 'Graduate Problems in Creative Photography', 'Planning, developing and evaluating individual projects in photography. May be repeated for credit for a maximum of 12 units in each area, but no more than 3 units in a single semester without permission of instructors. Requires consent of instructor. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 508B', 'Graduate Problems in Creative Photography', 'Planning, developing and evaluating individual projects in photography. May be repeated for credit for a maximum of 12 units in each area, but no more than 3 units in a single semester without permission of instructors. Requires consent of instructor. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 510', 'Graduate Problems: The Digital Studio', 'Digital studio as a “site” for the experimentation in image making and visual media expression. Develop own projects creating and manipulating images and media through technology and computer software. May be repeated once for credit. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 511', 'Seminar on the Content and Method of Art History', 'Methods of research, analysis and theories of art historical scholarship. May be repeated once for credit. ART 511 and ART 512 are both required to meet the graduate writing requirement.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 512', 'Seminar on Selected Topics in Art History', 'Analysis and evaluation of specific works and their historical significance, including cultural, social and economic circumstances. May be repeated once for credit. ART 511 and ART 512 are both required to meet the graduate writing requirement. Requires appropriate upper-division Art course approved by instructor.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 518', 'Graduate Seminar in Creative Photography', 'Expands and deepens knowledge of photographic and media criticism and theory. Explores advanced theoretical topics and applies tools of criticism to better understand the creative process and artwork. May be repeated once for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 548', 'Graduate Problems in Artists’ Books', 'Investigation and application of principles of the book form to visual art and design, illustration, photography and printmaking media. Development of original works of art, which demonstrate competency in design, construction and fabrication of graduate quality visual books. May be repeated for credit for a maximum of 12 units. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 563C', 'Graduate Studies in Digital Narrative Illustration', 'Narrative illustration using advanced digital painting programs and techniques. Theories of illustration and story illustration, to include concepts, composition, and current trends in digital media. May be repeated once for credit. Requires classified standing in illustration, drawing and painting.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 578', 'Graduate Studio Expanded: Other Genre', 'All aspects of new genre work, including conceptual, historic and theoretical approaches. Studio disciplines that will be investigated are installation, performance art, video and public art. May be repeated for a maximum of 9 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 579', 'Graduate Video Art and the Moving Image', 'Contemporary and historic practices in video and the role time plays in moving image arts. Production and post-production fundamentals, including camera work, editing, audio recording, storytelling and relationships between images and sound. May be repeated for a maximum of 9 units. (6 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 597', 'Project (3-6)', 'Develop and present a one-person project. Must be exhibited in a department graduate gallery. May be repeated for a maximum of 6 units. Requires written consent of instructor and recommendation of the student’s graduate committee.', 3, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 598', 'Thesis', 'May be repeated for credit for a maximum of 6 units. Requires written consent of instructor and recommendation of the student’s graduate committee.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ART 599', 'Independent Graduate Research (1-3)', 'Open to graduate students in art with consent of department chair and written consent of instructor. May be repeated for credit for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ARTE 442', 'Teaching Art in the K-12 Schools', 'Objectives, methods and practices for teaching art in K-12 schools with an emphasis on secondary levels. Required before student teaching of majors in art for the Single Subject Teaching Credential.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ARTE 449S', 'Seminar in K-12 Teaching', 'Seminar in teaching a single subject in K-12 schools. Credit/No Credit only. A “B” (3.0) or better is required to receive a grade of credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 101', 'Introduction to Ethnic Studies', 'Perspectives through which people of color have come to see themselves in terms of their own heroes, cultures and contributions to the societies in which they live and the world in general. (AFAM 101, ASAM 101, and CHIC 101 are the same course)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 190', 'Survey of American History with Emphasis on Ethnic Minorities', 'Survey of American history from prehistoric times (before 1492) to the present with special emphasis on the role of race and ethnicity. (HIST 190, AFAM 190, ASAM 190 and CHIC 190 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 201', 'The History of Asian Pacific Americans', 'Origins and evolution of Asian American communities and cultures, with an emphasis upon the southern California region, through selected books, oral histories, films, outside speakers and excursions. (HIST 201 and ASAM 201 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 220', 'Vietnamese Communities in the U.S.', 'Historical and cultural overview of Vietnamese communities in the U.S., especially Orange County. The vital role of voluntary agencies, mutual assistance associations, and religious centers. Examines Vietnamese business, entertainment, family, education and hobbies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 230', 'Civic Engagement Through Asian American and Pacific Islander Studies', 'Service-learning course introducing purpose of AAPI Studies, opportunities to develop cultural competency while serving AAPI communities and structured critical reflection for determining life purpose. May be repeated for a maximum of 9 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 300', 'Introduction to Asian Pacific American Studies', 'Interdisciplinary exploration of the experiences of several Asian American groups. Addresses questions of cultural assimilation and cultural persistence, family and gender roles, and literary and popular culture representations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 307', 'Research and Writing in Ethnic Studies', 'Introduction to research and writing in ethnic studies. Issues of research in ethnic studies (e.g., quantitative v. qualitative analysis, reliability/validity) and specific methods of research (e.g., archives, interviews, oral history). Extensive writing. A “C” (2.0) or better is required to satisfy the upper-division writing requirement. (ASAM 307, AFAM 307 and CHIC 307 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 308', 'Asian American Women', 'Interdisciplinary examination of Asian and Pacific Islander American women’s experience. Compares and contrasts the experience of women from various parts of Asia and explores the social, cultural and political issues they face in the U.S. and abroad.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 325', 'Asian American Film and Video', 'Introduction to major themes in Asian American film and video history and criticism. Asian American aesthetics, history and politics will be examined in areas of film and video direction, production, writing and acting.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 327', 'Asian American Literature', 'Introduces early literary expressions of the Asian American experience. Readings include poetry, short stories, novels and autobiographies. Fundamental understanding of Asian American literary history and awareness of the cultural diversity in America. (ASAM 327 and ENGL 327 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 342', 'Asian Pacific American Families', 'Asian Pacific American families have ranged from the seemingly solitary “bachelor” to the extended “clan.” Explores these, and many other ways of being a “family,” as it has been a basic part of Asian Pacific American history and culture.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 344', 'Asian Pacific American Identities', 'Interdisciplinary explorations of the ways in which those of Pacific Islander, Southeast, South and East Asian descent have met the challenge of being American at the personal level. Social construction of racial/ethnic identities, cultural conflict, self-determination and personal growth.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 346', 'Asian American Psychology', 'Major issues in the Asian American community from a psychosocial perspective, including ethnic identity development, generational conflicts, the “model minority” myth, interracial relationships, attitudes toward mental health services and alternative healing/therapeutic approaches. (ASAM 346 and PSYC 346 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 360', 'Multiple Heritage Asian American and Pacific Islanders', 'Overview of the mixed heritage Asian American population in the U.S. Surveys the historical avenues that led to the United States and to inter-ethnic alliances. The many challenges this multi-ethnic population faces.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 362A', 'Filipina/o American Experiences', 'Introduction to Filipina/o American Studies, covering point of origin, immigration, legal barriers, economic struggles, civil rights and other current issues up to 1965.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 364', 'South Asian American Experiences', 'Interdisciplinary course exploring the experiences of South Asian Americans originally from India, Pakistan, Bangladesh or Sri Lanka. Questions regarding influence of American culture on South Asian American identity, intergenerational concerns and cultural continuity, among others.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 366', 'Korean American Experiences', 'Historical events and contemporary issues, such as Korean American immigration, identity, inter-ethnic relations, gender issues, and entrepreneurship within the context of social, political and economic conditions of Korea and the United States.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 382', 'World War II Japanese American Evacuation', 'World War II eviction and detention of people of Japanese ancestry in the United States, pivoting on the significance of this experience in the areas of civil and human rights, cross-cultural relations and international affairs. (HIST 382 and ASAM 382 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 495', 'Internship in Asian American Studies', 'One hundred twenty (120) hours practical experience in some organization serving the Asian Pacific American community. Regular meetings with faculty advisor. May be repeated once for credit. Requires approval of supervising instructor(s).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 496', 'Student-to-Student Tutorials (1-3)', 'Consult “Student-to-Student Tutorials” in this catalog for a more complete course description. May be repeated for credit for a maximum of 3 units. Requires approval of supervising instructor(s).', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ASAM 499', 'Independent Study (1-3)', 'Supervised research and/or service learning projects in Asian American Studies to be taken with consent of instructor and program coordinator. May be repeated for credit for a maximum of 6 units. Requires approval of supervising instructor(s).', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 101', 'Elements of Biology', 'Underlying principles governing life forms, processes and interactions. Elements of biology and reasoning skills for understanding scientific issues on personal, societal and global levels. For non-science majors. No credit toward biological science major.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 101L', 'Elements of Biology Laboratory', 'Laboratory experiments demonstrating principles from the lecture course. Scientific inquiry, cells, physiology, genetics, biodiversity, evolution and ecology. Hybrid sections require online and in-person activities (3 hours laboratory or fieldwork; weekend field trips and online coursework may be required). For non-science majors. Pre- or', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 102', 'Biology for Future Teachers', 'Designed especially for the prospective teacher, this activity-based course examines biological concepts in real-world contexts, such as the medical examination, genes and evolution, and the environment. Lecture and laboratory form a single unified learning experience. No credit toward biological science major. (6 hours activity)', 4, 4, FALSE, TRUE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 191A', 'Integrated Human Anatomy and Physiology A', 'Integrated introduction to human anatomy and physiology. Structure and function of the musculoskeletal, nervous and cardiorespiratory systems. For nursing majors and students interested in allied health professions; no credit toward Biological Science major. (3 hours lecture, 3 hours laboratory) (KNES 191A and BIOL 191A are the same course).', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 191B', 'Integrated Human Anatomy and Physiology B', 'Second semester of integrated concepts in human anatomy and physiology for nursing, allied health and kinesiology majors. Nutrition, water and ion balance, and homeostatic regulation by the digestive, renal, cardio-respiratory, endocrine, nervous systems. No credit toward biological science major. (3 hours lecture, 3 hours laboratory) (BIOL 191B and KNES 191B are the same course.)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 210', 'Human Anatomy and Physiology', 'Introduction to human anatomy and physiology concepts as they apply to physical activity, sport and exercise. Structure and function of the skeleto-neuromuscular and cardio-respiratory systems relative to human movement. Preparation for KNES 360, KNES 361, KNES 348, KNES 371 and major in Health Science. No credit toward biological science major. (BIOL 210 and KNES 210 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 280R', 'Research Preparatory Proseminar', 'Introduction to the culture of science and research. Read and discuss research articles, write brief reports, give oral presentations and learn about lab safety, research ethics, scientific discourse and future career prospects. May be repeated once for credit. Requires acceptance into the Research Preparatory Program (RPP) in the department of Biological Science.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 300', 'Environmental Biology and Sustainability', 'Biological consequences of human intervention in ecosystems: endangered and threatened species, pollution impact on organisms, pest control, population dynamics, genetic engineering of agricultural species, management of natural areas and urban ecosystem dynamics. No credit toward biological science major.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 301', 'Problems in Environmental Biology', 'Environmental problems in Southern California ecosystems. Effects of human activities on desert, foothill and wetland ecosystems. Offered as an intensive four-week summer field experience. Requires admission into the Southern California Ecosystems Research Program in environmental biology. (Equivalent to 1 hour lecture, 6 hours laboratory/fieldwork during a normal semester)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 302', 'General Microbiology', 'Introduction to structure and function of bacteria and viruses including beneficial and detrimental activities and interactions with other organisms. (3 hours lecture)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 303', 'Intermediate Cell Biology', 'Evidence-based examination of cells in action, roles of information, matter and energy flow as driving forces for compartmentation, protein sorting, metabolic and signaling pathways, motility and adhesion; examples taken from developmental, neural and cancer processes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 306', 'Biology of Aging', 'Biological changes in cells, tissues, organs and the whole body associated with aging. Theories of aging, with primary emphasis on mammals. No credit toward biological science major.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 309', 'Intermediate Molecular Biology', 'Molecular and genetic basis of cellular functions. Role of gene expression and protein function in metabolism, physiology, growth, development. Introduction to recombinant DNA and its uses, and to critical analysis of primary literature.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 310', 'Human Physiology', 'Human physiological systems and their relationship to human function for non-biology majors and students in kinesiology and health sciences. No credit for biological science major.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 310L', 'Human Physiology Laboratory', 'Human physiology; the cellular to organ system level of muscular, cardiovascular, respiratory and renal systems; the neural and endocrine control of these systems. Functional aspects of each organ system. No credit toward Biological Science major. (3 hours laboratory) Pre- or', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 314', 'Population and Community Ecology', 'Introduction to the quantitative description of populations and communities, as well as the use of mathematical models to understand the dynamics of populations and communities. Links comparative, experimental and theoretical approaches to understanding the abundance and distribution of organisms and their interactions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 317', 'Field Marine Biology', 'Field biology and natural history of local marine plants and animals. Identify common species and factors, determining their distributions and abundance in marine habitats. Effects of human activities on marine organisms. (2 hours lecture, 6 hours lab or fieldwork; weekend field trips may be required)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 325', 'Principles of Evolution', 'Mechanisms of evolutionary change, including mutation, selection, migration and drift. Introduces methods for studying adaptations. Sexual selection, kin selection and evolution of life history strategies. Uses modern examples, including antibiotic resistance, to illustrate the relevance of understanding evolution.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 340', 'Field Botany', 'Native flora of southern California. Identification, natural history and factors that determine the distribution of species. (1 hour lecture, 6 hours laboratory or fieldwork; weekend field trips are required)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 360', 'Biology of Human Sexuality', 'Biology of the human reproductive system, sexual differentiation, anatomy and physiology, sexual behaviors, procreation, contraception and sexually transmitted infections. No credit toward biological science major.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 361', 'Human Anatomy', 'Systems approach to the structure and function of the human body. For biological science majors and related health sciences. (2 hours lecture, 6 hours laboratory)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 362', 'General Human Physiology', 'Fundamental mechanisms of human physiology. Integrating cellular and organ system functions, emphasizing regulatory processes. For biology majors and related health sciences. (3 hours lecture, 3 hours laboratory).', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 400', 'Seminar in Biology Education', 'For students interested in biology education/science education. Discuss major topics in biology education and conduct research. (3 hours lecture/discussion)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 401', 'Biogeography', 'Evolutionary patterns and mechanisms of the distribution of plants and animals in the major habitats of the world. Current concepts and theories.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 402', 'Computer Lab in Molecular Systematics', 'Gain practical and theoretical experience with software-based methods in molecular systematics, with emphasis on Internet resources for molecular biologists, acquisition of gene protein sequences, multiple sequence alignment, PCR primer design, phylogenetic analysis and controversies in the field. (2 hours lecture, 3 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 405', 'Developmental Biology', 'Molecular and cellular processes in embryonic development encompassing mechanisms of fertilization, cell and tissue interactions, morphogenesis, organogenesis and the regulation of gene expression.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 411', 'Medical Genetics and Systems Biology', 'Advances in genetics, genomics, proteomics and systems biology. Implications for the pharmaceutical industry, the clinic and for genetic counseling. Uses of biological arrays in diagnosing and treating diseases.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 412', 'Principles of Gene Manipulation', 'Current approaches to and applications of recombinant DNA technology. Principles behind construction of recombinant molecules including vectors and enzymes, introduction into organisms, selection, expression of cloned genes and impact of research on society.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 413', 'Advances in Molecular Genetics', 'Function of genetic material and informational macromolecules. Extensive analysis of recent scientific articles in molecular genetics illustrating mutagenesis, protein synthesis, protein structure and function, biogenesis of RNA molecules, regulation of gene expression and their relationship to important biological processes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 414', 'Microbial Genetics', 'Perspective of genetics of microbial systems including background information, experimental methods, data interpretation, genetic analysis and applications to biotechnology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 417', 'Advances in Cell Biology', 'Current topics in the cell biology of cell motility, cell multiplication and regulation, membranes and permeability, cell signaling, cell-to-cell contact and extracellular matrix, and cell differentiation using current journal articles.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 418L', 'Advances in Cell Biology Lab', 'Use of current techniques like fluorescence microscopy, immunolabeling, ion-sensitive dye ratiometry, image processing and 2-D and 3-D reconstruction to study problems in cell biology, cellular developmental biology and cellular neurobiology. (6 hours laboratory)', 2, 2, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 419', 'Marine Ecology', 'Ecology of planktonic, nektonic and benthic organisms; their communities and environments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 419L', 'Marine Ecology Laboratory', 'Field and laboratory studies of planktonic, nektonic and benthic communities. (3 hours laboratory or field work; weekend field trips may be required)', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 422', 'Coastal Ecology', 'Ecology or coastal populations and communities emphasizing rocky intertidal or other marine or ocean-influenced habitats. Field and laboratory experiments and studies or ecological processes affecting species distributions and abundances. (2 hours lecture, 6 hours laboratory/field work; weekend field trips may be required)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 424', 'Immunology', 'Molecular, cellular and organismic nature of the immune process. Inflammation, phagocytosis, antigens, immunoglobulins and cell-mediated immune phenomena. Modern immunology techniques. (3 hours lecture, 6 hours laboratory)', 5, 5, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 426', 'Molecular Virology', 'Viral structure, strategies of replication and gene expression and host-virus interactions, emphasizing animal virus systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 427', 'Stem Cell Biology', 'Historical context, principles, methodology, clinical impact on society and the individual, recent relevant scientific facts and progress, controversies and perspective of stem cell biology with a focus on applications to regenerative medicine and tissue engineering. BIOL 405 or BIOL 424 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 428', 'Biology of Cancer', 'Cancer problem as a dilemma of biology. Clinical and epidemiological aspects. Current research. BIOL 424 is recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 429', 'Techniques in Stem Cell Biology', 'Introduction to cell-culture and stem cell laboratory research techniques; focus on advanced-level cell biology experiments, fundamental characteristics of stem cells and differentiation of government-approved human stem cell-lines into several phenotypes. (6 hours of laboratory and 1 hour of discussion per week.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 430', 'Advances in Microbiology', 'Current topics in microbiology virulence mechanisms, antibiotics, host-bacterium interaction, mobile DNA elements, secretion systems, select agents, differentiation and development.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 436', 'Advanced Applied Statistics', 'Linear models, including mixed models, applied to experimental and field data from current research projects. Poisson and logistic regression. Model fitting and checking; use of permutation tests as needed. Presentation of results suitable for publication (3 hours lecture, 3 hours laboratory)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 438', 'Public Health Microbiology', 'Control and epidemiology of infectious diseases of public health importance, water and sewage microbiology. Control of current problems. (2 hours lecture, 6 hours laboratory)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 441', 'Plant Taxonomy', 'Classification and evolution of vascular plants; emphasis on the flowering plants. (2 hours lecture, 6 hours laboratory or fieldwork; weekend field trips may be required.)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 443', 'Plant Ecology', 'Community and population ecology of terrestrial plants. Environmental factors and plant distribution with emphasis on California vegetation. (2 hours lecture, 6 hours laboratory or fieldwork; weekend field trips may be required).', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 444', 'Plant Physiological Ecology', 'Fundamental mechanisms of plant physiological responses to the environment with primary emphasis on whole plants and ecosystems. (2 hours lecture, 6 hours laboratory; weekend field trips may be required.) BIOL 345 recommended.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 445', 'Plant Cell Physiology', 'Cellular and molecular mechanisms of behavior, growth, transport processes and environmental responses in vascular plants. Plant cell development, nutrition, respiration, photosynthesis, hormones, photoperiodism and stress biology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 446', 'Marine Phycology', 'Biological aspects of marine algae; comparative development, morphology, taxonomy, physiology and ecology. (2 hours lecture, 6 hours laboratory or fieldwork; weekend field trips may be required.)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 448', 'Plant Molecular Biology', 'Genetic mechanisms in vascular plants controlling metabolism, growth, development and responses to biotic/abiotic environmental stresses. Molecular regulation of gene expression and transduction of internal and external signals.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 449', 'Desert Ecology', 'Adaptations, distributions and interactions of desert plants, animals and microbes, including the influences of environmental factors. (2 hours lecture, 6 hours laboratory of fieldwork; weekend field trips may be required)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 450', 'Conservation Biology', 'Current topics involving theory, concepts and techniques in the conservation of biological diversity.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 451', 'Advanced Evolutionary Anthropology', 'Uses life history theory to examine the evolutionary ecology of human behavior. Human life course, resource acquisition, parenting and fertility. Computer labs utilizing eHRAF. (ANTH 451 and BIOL 451 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 453', 'Life Science Concepts', 'Biological principles using science processes appropriate for elementary teachers. No credit for Biological Science major. (2 hours lecture, 2 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 461', 'Marine Invertebrate Biology', 'Evolution, classification, phylogeny, morphological and physiological adaptations of marine invertebrate animals. Dissect, identify and observe extant animals. (2 hours lecture, 6 hours laboratory or fieldwork; weekend field trips may be required)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 462', 'General Parasitology', 'Survey of various animal parasites emphasizing the morphology, physiology, and genetics of human protozoans and helminthes. Vectors and common parasites of domestic animals.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 466', 'Behavioral Ecology', 'Current problems in the evolution of animal behavior; the origin and maintenance of social systems and behavioral interactions of animals.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 468', 'Comparative Animal Physiology', 'Comparative study of physiological and biochemical processes among representative animals. (3 hours lecture, 3 hours laboratory, weekend field trips may be required)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 470', 'Cellular Neurobiology', 'Processes of cell communication, particularly in nervous systems. Molecular biology of neurons, model sensory and motor systems, and cellular basis for behavior.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 472A', 'Advances in Biotechnology Lab', 'First semester explores biotechnology techniques for DNA cloning and analysis: restriction enzyme action, DNA sequencing, sequence analysis by computer, plasmid cloning, genomic library production and screening, and DNA probe hybridization. (1 hour lecture/discussion, 6 hours laboratory) (BIOL 472A and CHEM 472A are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 472B', 'Advances in Biotechnology Laboratory', 'Second semester exploring biotechnology techniques for gene product analysis: DNA sequencing, site-directed mutagenesis, predicting amino acid changes, protein overproduction, enzyme function assays, protein identification/preparation by gel techniques, immunoblotting. (1 hour discussion, 6 hours laboratory) (CHEM 472B and BIOL 472B are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 473', 'Introduction to Bioinformatics', 'A research-based, problem-solving experience using the tools and algorithms of molecular and computational biology to analyze genetic and protein sequences retrieved from appropriate databases. (2 hours lecture, 3 hours computer laboratory) (BIOL 473 and CHEM 473 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 475', 'Ichthyology', 'Systematics, evolution, morphology, physiology, ecology and behavior of fishes. (2 hours lecture, 6 hours laboratory/fieldwork; weekend field trips may be required.)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 476', 'Herpetology', 'Biology, structure, physiology, ecology, distribution, identification, collection, evolution and behavior of amphibians and reptiles. (2 hours lecture, 6 hours laboratory or fieldwork; weekend field trips may be required.)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 478', 'Mammalogy', 'Systematics, evolution, morphology, physiology, ecology and behavior of mammals. (2 hours lecture, 6 hours laboratory/fieldwork; weekend field trips may be required.)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 479', 'Ornithology', 'Anatomy, physiology, evolution, behavior and ecology of birds. Laboratory and fieldwork in identification, anatomy, observational techniques and community composition. (2 hours lecture, 6 hours laboratory/fieldwork; weekend field trips may be required.)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 480', 'Advanced Topics in Undergraduate Biology (1-3)', 'Current topics, updating of concepts, recent advances and unification of the principles of biology. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 480D', 'Colloquium: Diverse Topics in Biology', 'Diverse research topics and perspectives in the biological sciences, as presented invited speakers from other universities, governmental agencies, private organizations and industry, and by CSUF biologists. May be repeated once for credit. Pre- or', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 480E', 'SCERP Proseminar', 'Increases the experience and skills of SCERP Scholars in working on problems in environmental biology. Discuss publications, and develop and present SCERP research. Offered Credit/No Credit only. May be repeated for a maximum of 6 units. Selection as a Southern California Ecosystems Research Program (SCERP) Scholar is required.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 480M', 'MARC Proseminar', 'Intended to increase the contact of MARC Fellows with minority scientists of national repute who will present seminars. Fellows will read and discuss relevant primary literature, attend the seminars, and meet with speakers before and after the seminars. May be repeated for a maximum of 4 units. Requires selection as a MARC Fellow. (BIOL 480M, CHEM 480M and PSYC 480M are the same course.)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 481', 'Advances in Evolution and Ecology', 'Current topics in evolutionary biology and ecology. Examine and analyze current literature relating to evolutionary biology, population, community and ecosystem ecology, behavioral ecology and evolutionary ecology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 482', 'Capstone Studies in Biology', 'Individualized practical experience related to the study of biology or pursuit of a biology career that reflects paradigms of the discipline. Application and integration of biological concepts and skills through library research, applied projects or community service activities.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 495', 'Biological Internship', 'Biological, ecological and health-related fields. Ninety (90) hours of practical experience in student’s chosen field of interest with public or private agencies or businesses. May not be repeated for credit. (1 hour lecture/discussion, 6 hours laboratory work experience)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 496', 'Biology Tutorials (1-3)', 'Supervised experience in biological science teaching through tutoring or assisting in a laboratory or field class. May be repeated for a maximum of 6 units. No credit toward biological science major.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 498', 'Senior Thesis (1-3)', 'Thesis committee must approve research plan at least two semesters prior to enrollment in this course. Requires preparation, presentation and defense of a formal thesis. May be repeated for a maximum of 3 units. (BIOL 498 and CHEM 498 are the same course.)', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 499L', 'Independent Laboratory Study (1-3)', 'May be repeated for a maximum of 6 units. Requires consent of instructor with whom the student wishes to pursue independent laboratory study in biology.', 1, 3, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 500A', 'Professional Aspects of Biology', 'Discussions concerning research protocol, scientific methodology and communication techniques. Ethics and social responsibilities of professional biologists. (1 hour discussion) BIOL 500A and BIOL 500B are both required to meet the graduate writing requirement.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 500B', 'Professional Aspects of Biology', 'Individualized project work and experiences in scientific writing. Required of all students upon admission to the graduate program. (3 hours project work) BIOL 500A and BIOL 500B are both required to meet the graduate writing requirement.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 500C', 'Professional Aspects of Biology: Teaching Effectiveness', 'Professional development in the scholarship of teaching biology in higher education. Biology education research, pedagogy, instructional design and assessment to prepare for biology laboratory and classroom instruction.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 505T', 'Seminar in Cellular and Molecular Biology and Physiology', 'Selected advanced topics. May be repeated for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 517T', 'Seminar in Ecological and Organismic Biology', 'Selected advanced topics. May be repeated for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 520T', 'Seminar in Microbiology', 'Selected advanced topics. May be repeated for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 580', 'Advanced Topics in Graduate Biology (1-3)', 'Current research topics, experimental design and problem solving in biological systems. May be repeated for a maximum of 8 units; only 1 unit may be used on a graduate study plan.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 580D', 'Biology Colloquium', 'Series of scholarly presentations that provide diverse research topics and perspectives in the biological sciences. Scientific presentations by biologists from CSUF and other universities, industries, governmental agencies or private organizations. May be repeated for a maximum of 3 units.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 597', 'Project (1-3)', 'Planning, preparing and completing an applied master’s degree project. Credit only for completed written project report and oral presentation both of which must be formally approved by the master’s program committee. May be repeated for a maximum of 6 units. (Not acceptable for research-based thesis master’s degree programs.)', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 598', 'Thesis (1-3)', 'Open to graduate students with consent of instructor with whom the student is conducting graduate thesis research. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BIOL 599', 'Independent Graduate Research (1-3)', 'Open to graduate students with consent of graduate faculty with whom the student wishes to pursue independent study in biology. A maximum of 6 units may be used on a graduate study plan. May be repeated for a maximum of 12 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BUAD 201', 'Business Writing', 'Core communication practices: routing business correspondence, positive, informative, negative and persuasive messages. Introduction to research and job application process.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BUAD 210', 'Understanding Business', 'Nature, dimensions and forms of business and the role of entrepreneurship in business creation and growth. Development of an understanding of contemporary business issues, including an introduction to major business functions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BUAD 301', 'Advanced Business Communication', 'Expands knowledge of business communication and develops written and oral communication skills. Study a variety of business cases that understand the function of communication in the modern business world. Analyze real-life business problems and determine when and how to communicate corporate decisions to employees, business partners and the public.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BUAD 360', 'Entertainment Money Management', 'How entertainment, tourism and hospitality firms make money: overview of existing and evolving income generation models in the various industry sectors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BUAD 495', 'Internship (1-3)', 'Planned and supervised work experience. May be repeated for a maximum of 6 units. Credit/No Credit grading only. Requires consent of the instructor and semester in residence at the university.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BUAD 499', 'Independent Study (1-3)', 'Open to qualified students desiring to pursue directed independent inquiry. May be repeated for a maximum of 6 units. Not open to students on academic notice.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BUAD 501', 'Managerial Communications', 'Investigates the entire process of case studies and formal reports. Analyze management communication problems, apply writing strategies and deliver executive presentations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('BUAD 591', 'Business Strategy Capstone', 'Tools of strategic management and their application in a business environment. Integrates business functional areas and tools by means of a business consulting project. Fulfills the terminal requirement for the MBA degree. Must be taken in the program’s final semester during which students can enroll in a maximum of nine units, including a maximum of one core course.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 100', 'Survey of Chemistry', 'The fundamental principles of chemistry; atomic and molecular structure and the application of these principles to contemporary problems. For the non-science major. One year of high school algebra recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 100L', 'Survey of Chemistry Laboratory', 'Experiments chosen to develop laboratory techniques; chemical principles and their application to environmental and societal problems. (3 hours laboratory)', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 102', 'Physical Science for Future Elementary Teachers', 'Designed especially for the prospective elementary teacher, this activity-based course examines physical science concepts in real-world contexts such as global warming, kitchen science and the automobile. Lecture and laboratory is combined into a single unified learning experience. (PHYS 102 and CHEM 102 are the same course.)', 3, 3, FALSE, TRUE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 105', 'Survey of the Molecules of Life', 'An introduction to the biochemical processes of life, including metabolism, development and disease. Recent scientific advances are discussed with emphasis placed on AIDS, cancer, diabetes and cloning. Scientific methods and ethical issues in scientific research are examined.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 111', 'Nutrition and Health', 'The basics of nutrition; diet, food additives, vitamins, hormones, drugs, disease and related biochemical topics. Current controversies, popular practices, fads and fallacies. For the non-science major.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 115', 'Introductory General Chemistry', 'Chemistry at the basic level. For students with limited background in math and chemistry who plan to take additional chemistry or other science courses. Does not fulfill chemistry requirements for majors or minors in the physical or biological sciences. (3 hours lecture)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 120A', 'General Chemistry', 'For majors and minors in the physical and biological sciences. The principles of chemistry: stoichiometry, acids, bases, redox reactions, gas laws, solid and liquid states, changes of state, modern atomic concepts, periodicity and chemical bonding. Laboratory: elementary syntheses, spectroscopy and volumetric quantitative analysis. (3 hours lecture, 3 hours laboratory, 2 hours activity)', 5, 5, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 120B', 'General Chemistry', 'For majors and minors in the physical and biological sciences, chemical thermodynamics, chemical equilibrium (gaseous, aqueous, acid-base, solubility and complexation), elementary electrochemistry and chemical kinetics. Laboratory: quantitative and qualitative analysis and elementary physical chemistry; some qualitative analysis. (3 hours lecture, 6 hours laboratory).', 5, 5, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 125', 'General Chemistry B Lecture', 'For students who do not need a second semester of general chemistry lab. Chemical thermodynamics, chemical equilibrium (gaseous, aqueous, acid-base, solubility and complexion), elementary electrochemistry and chemical kinetics. Not open to students with credit in CHEM 120B.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 190', 'Orientation to Chemistry and Biochemistry', 'Resources, opportunities and careers available in chemistry and biochemistry. Focus on successful strategies to complete the major and enter the chemistry/biochemistry workforce. Credit/No Credit only..', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 200', 'Chemistry for Nursing and Allied Health Professionals', 'Fundamental concepts of general, organic and biochemistry and their applications to the health sciences. Meets requirement for pre-nursing curriculum and can be applied to other allied health majors. High school math and one year of high school chemistry, or a passing score on the placement test for general chemistry, or completion of introductory general chemistry (CHEM 100, CHEM 100L) with a “C” (2.0) or better strongly advised. (3 hours lecture, 3 hours laboratory)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 295', 'Directed Study', 'Research in chemistry under the supervision of a chemistry department faculty member. Credit/no credit only. May be repeated once for credit. Does not count towards major. (3 hours laboratory per unit)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 301A', 'Organic Chemistry', 'Properties and reactions of aliphatic and aromatic compounds, theories of structure and reaction mechanisms. For the non-chemistry majors, or B.A. in Chemistry, B.S. in Chemistry or B.S. in Biochemistry majors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 301B', 'Organic Chemistry', 'Properties and reactions of aliphatic and aromatic compounds, theories of structure, and reaction mechanisms. For non-chemistry majors, or B.A. in Chemistry, B.S. in Chemistry or B.S. in Biochemistry majors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 306A', 'Organic Chemistry Laboratory', 'Techniques for synthesis, isolation and characterization of typical aliphatic and aromatic compounds, with applications of instrumental and spectroscopic methods. (1 hour discussion, 3 hours laboratory)', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 306B', 'Organic Chemistry Laboratory', 'Continuation of CHEM 306A for the B.A. and B.S. in chemistry major. (6 hours laboratory)', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 311', 'Nutrition and Disease', 'Relationship between nutrients and disease, with an emphasis on cancer, atherosclerosis and infectious illness. Dietary factors that modify and/or contribute to the disease process from the viewpoints of physiology, biochemistry and immunology. Not applicable to the major.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 313A', 'Environmental Pollution and Its Solutions: Air Pollution', 'Human pollution of the Earth’s atmosphere and means to ameliorate this pollution. Historical examples, current cases and future prospects. (3 hours lecture/discussion for 5 weeks)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 313B', 'Environmental Pollution and Its Solutions: Water Pollution', 'Human pollution of the Earth’s aqueous environment and means to ameliorate this pollution. Historical examples, current cases and future prospects. (3 hours lecture/discussion for 5 weeks)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 313C', 'Environmental Pollution and Its Solutions: Land Pollution', 'Human pollution of the Earth’s terrestrial environment and means to ameliorate this pollution. Historical examples, current cases and future prospects. (3 hours lecture/discussion for 5 weeks)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 315', 'Theory of Quantitative Chemistry', 'Modern analytical chemistry; aqueous and non-aqueous equilibrium calculations, electrochemistry, spectrometry and contemporary separation methods with emphasis on chromatography. PHYS 226 strongly recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 316', 'Quantitative Chemistry Laboratory', 'Modern analytical chemistry laboratory: polyprotic acids, liquid chromatography, electrochemistry, absorption spectroscopy (ultraviolet/visible, infrared, atomic). (1 hour lecture, 3 hours laboratory)', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 325', 'Inorganic Chemistry', 'The chemistry of the main group elements and an introduction to transition metal chemistry.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 355', 'Physical Chemistry Laboratory', 'Experiments in chemical synthesis, instrumental analysis and physical chemistry. Laboratory training and written presentation of theory, data and results. (1 hour lecture, 6 hours laboratory).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 361A', 'Introduction to Physical Chemistry', 'Thermodynamics and kinetics; properties of gases and solutions; molecular structure and energies and application to spectroscopic techniques; liquids, phase equilibria, thermodynamics of multicomponent systems with application to the life sciences.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 361B', 'Introduction to Physical Chemistry', 'Thermodynamics and kinetics; properties of gases and solutions; molecular structure and energies and application to spectroscopic techniques; liquids, phase equilibria, thermodynamics of multicomponent systems with application to the life sciences.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 371A', 'Physical Chemistry', 'Thermodynamics, solutions, chemical and phase equilibria, electrochemistry, transport phenomena, introduction to atomic and molecular structure, rotation and vibration spectroscopy, statistical mechanics and kinetics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 371B', 'Physical Chemistry', 'Thermodynamics, solutions, chemical and phase equilibria, electrochemistry, transport phenomena, introduction to atomic and molecular structure, rotation and vibration spectroscopy, statistical mechanics, and kinetics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 395', 'Undergraduate Research (1-3)', 'Independent research in chemistry or biochemistry under the guidance of a department faculty member. May be repeated for a maximum of 4 units. Does not count towards major. Requires one semester of experience working in a research laboratory. (3 hours per week per unit).', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 411A', 'Instrumental Analysis - Optical Spectroscopy', 'UV/visible, infrared, atomic absorption, flame emission. Students wishing an ACS certified degree must take three units of CHEM 411 courses. (1 hour lecture, 3 hours laboratory for 5 weeks)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 411B', 'Instrumental Analysis - Magnetic Resonance', 'Nuclear magnetic resonance, electron spin resonance. Students wishing an ACS certified degree must take three units of CHEM 411 courses. (1 hour lecture, 3 hours laboratory for 5 weeks)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 411C', 'Instrumental Analysis - Separations', 'High performance liquid chromatography, gas chromatography. Students wishing an ACS certified degree must take 3 units of CHEM 411 courses. (1 hour lecture, 3 hours laboratory for 5 weeks)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 411D', 'Electrochemistry', 'Voltammetry, amperometry, electrodes. ACS-certified degrees require three units of CHEM 411 courses. (1 hour lecture, 3 hours laboratory for 5 weeks)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 411G', 'Instrumental Analysis - Mass spectrometry', 'Conventional magnetic sector, quadruple, Fourier transform, tandem, and time-of-flight; hyphenated techniques including gas chromatography (GC-MS), liquid chromatography (LC-MS). Students wishing an ACS certified degree must take three units of CHEM 411 courses. (1 hour lecture, 3 hours laboratory for 5 weeks)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 421', 'Biological Chemistry', 'Biochemistry designed for biology majors and pre-health profession careers. Major areas of biochemistry, including intermediary metabolism and compounds of biochemical interest. Applying biochemistry and the biochemical foundation of health science.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 422', 'General Biochemistry Laboratory', 'Chemistry and metabolism of carbohydrates, nucleic acids and proteins; techniques of enzyme isolation and characterization; DNA isolation and manipulation; research methods. (6 hours laboratory)', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 423A', 'General Biochemistry', 'For biochemistry majors. Structural chemistry and function of biomolecules, bioenergetics and intermediary metabolism.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 423B', 'General Biochemistry', 'For biochemistry majors; structural chemistry and function of biomolecules, central and secondary metabolism; photosynthesis; nucleic acid biochemistry.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 425', 'Advanced Inorganic Chemistry', 'Bonding, structure and reactivity of transition and lanthanide elements. Molecular orbital and ligand field theory, classical metal complexes and organometallic chemistry of the transition elements.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 431', 'Advanced Organic Chemistry', 'Theoretical and physical aspects of organic chemistry. Modern concepts of structure, and reaction mechanisms.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 436', 'Atmospheric Chemistry', 'Chemistry and photochemistry of the troposphere and stratosphere, both natural and polluted. Includes fundamental reaction kinetics and mechanisms, monitoring techniques, smog chamber, field and modeling studies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 438', 'Environmental Biochemistry', 'Effects of current agricultural, industrial and mechanical practices on the composition, metabolism and health of soil, plants, animals and man, from a biochemical perspective; mechanism of action and degradation of common agricultural chemicals and industrial pollutants.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 445', 'Nutritional Biochemistry', 'Nutrition, metabolism and excretion of carbohydrates, proteins, fats, vitamins, major minerals and trace elements from a biochemical perspective. Relevant variations in dietary practices related to life stages and specific illnesses.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 472A', 'Advances in Biotechnology Lab', 'First semester explores biotechnology techniques for DNA cloning and analysis: restriction enzyme action, DNA sequencing, sequence analysis by computer, plasmid cloning, genomic library production and screening, and DNA probe hybridization. (1 hour lecture/discussion, 6 hours laboratory) (BIOL 472A and CHEM 472A are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 472B', 'Advances in Biotechnology Laboratory', 'Second semester exploring biotechnology techniques for gene product analysis: DNA sequencing, site-directed mutagenesis, predicting amino acid changes, protein overproduction, enzyme function assays, protein identification/preparation by gel techniques, immunoblotting. (1 hour discussion, 6 hours laboratory) (CHEM 472B and BIOL 472B are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 480A', 'Topics in Contemporary Chemistry', 'Research seminar dealing with topics of current interest in chemistry, such as photochemistry, biochemistry, analytical chemistry and organometallic chemistry. Credit/no credit only. Not applicable toward master’s degree. May be repeated for a maximum of 3 units.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 480M', 'MARC Proseminar', 'Intended to increase the contact of MARC Fellows with minority scientists of national repute who will present seminars. Fellows will read and discuss relevant primary literature, attend the seminars, and meet with speakers before and after the seminars. May be repeated for a maximum of 4 units. Requires selection as a MARC Fellow. (BIOL 480M, CHEM 480M and PSYC 480M are the same course.)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 480T', 'Topics in Contemporary Chemistry (1-3)', 'Special lecture topics of current interest in chemistry. May be repeated with different topics for a maximum of 6 units. (1 hour lecture per unit)', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 490', 'Internship in Chemistry and Biochemistry (1-3)', 'Internship in chemistry. Work on projects in industrial, governmental or medical laboratories. May count as career breadth requirement units for chemistry majors or substituted for CHEM 495, with permission. May be repeated for a maximum of 3 units. Does not count toward M.S. degree.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 495', 'Senior Research (1-3)', 'Methods of chemical research through a research project under the supervision of a department faculty. May be repeated for a maximum of 6 units. Only 6 units may apply toward B.A. or B.S. degree. (6 hours per week per unit)', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 498', 'Senior Thesis (1-3)', 'Thesis committee must approve research plan at least two semesters prior to enrollment in this course. Requires preparation, presentation and defense of a formal thesis. May be repeated for a maximum of 3 units. (BIOL 498 and CHEM 498 are the same course.)', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 499', 'Independent Study (1-3)', 'Special topics in chemistry selected in consultation with the instructor and approval of department chair. May be repeated for a maximum of 6 units. Only six units may apply toward B.A. or B.S. degree. In some cases, CHEM 499 can be substituted for CHEM 495 to meet degree requirements.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 505A', 'Seminar: Research Background, Methods and Objectives', 'Gain practical skills on how to deliver an oral presentation focused on describing and analyzing research background, methods and objectives. How to organize, evaluate and present scientific information in a professional manner. May be repeated for a maximum of 2 units.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 505B', 'Seminar (Presentation)', 'Student presentation of recent contributions to the chemical literature. May not be repeated for credit. (1 hour seminar)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 511', 'Advanced Analytical Chemistry', 'Theory, application and limitations of advanced analytical topics; including separations, spectroscopy, electrochemistry and contemporary methods..', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 512', 'Advanced Instrumentation', 'Spectroscopic instrumentation components and systems. Includes laser spectroscopy, mass spectroscopy, chemical sensor, process control, surface science, and microscopy methods; vacuum technology, optics, electro-optics, and electronics components; design and repair of instrumentation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 535', 'Organic Synthesis', 'Methods of synthetic organic chemistry and their application to construction of organic molecules.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 537', 'Organic Spectroscopy', 'Theory and use of infrared spectroscopy, mass spectrometry, ultraviolet-visible spectroscopy and nuclear magnetic resonance spectroscopy as methods for the identification of organic compounds.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 541', 'Protein Biochemistry', 'Protein isolation strategies and techniques; chemical/physical characterization and modeling; functional characterization (kinetics, binding, chemical modification); molecular biology, including protein expression and engineering.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 542', 'Nucleic Acid Chemistry', 'Biochemistry of nucleic acids in living systems at the molecular level. Advances and techniques used in nucleic acid research and biotechnology. Strong emphasis on critical reading, analysis and presentation of primary literature.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 543', 'Physical Biochemistry', 'Methods for measuring physical properties of proteins and nucleic acids. Thermodynamic and hydrodynamic aspects.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 546', 'Metabolism and Catalysis', 'Regulation of biosynthetic and degradative reactions in living systems. The control of enzyme activity and concentration. Mechanisms of hormone action.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 551', 'Quantum Chemistry', 'Postulates and theories of approximation methods in quantum chemistry, the electronic structure of atoms and molecules, chemical bonds, group theory and applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 552', 'Kinetics and Spectroscopy', 'Kinetics and spectroscopy of chemical and biochemical systems in the gas phase, in the liquid phase, and on surfaces.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 597', 'Project (1-3)', 'Guidance in preparing a project for the master’s degree. May be repeated for a maximum of 3 units. Requires an officially appointed project committee and consent of the department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 598', 'Thesis (1-6)', 'Guidance in preparing a thesis for the master’s degree. May be repeated for a maximum of 6 units. Requires an officially appointed thesis committee.', 1, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHEM 599', 'Independent Graduate Research (1-6)', 'May be repeated for a maximum of 12 units. A maximum of 6 units may be used on study plan.', 1, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 101', 'Introduction to Ethnic Studies', 'Perspectives through which people of color have come to see themselves in terms of their own heroes, cultures and contributions to the societies in which they live and the world in general. (AFAM 101, ASAM 101, and CHIC 101 are the same course)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 102', 'Communication Skills', 'Basic communication skills, including oral and written expression. A unit on the mechanics of writing and reporting on a term paper is included as part of the course.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 190', 'Survey of American History with Emphasis on Ethnic Minorities', 'Survey of American history from prehistoric times (before 1492) to the present with special emphasis on the role of race and ethnicity. (HIST 190, AFAM 190, ASAM 190 and CHIC 190 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 220', 'Chicana/o Identities', 'Chicana/o identities, from their indigenous beginnings to the present, through categories of gender, sexuality, race, ethnicity, national origin and class; surveying interdisciplinary, social scientific, historical and literary sources.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 302', 'Ancient Mexican Culture', 'Historical and cultural survey of the principal pre-Columbian cultures of Mexico and their significance to Mexican society.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 304', 'Music of Mexico', 'Historical survey of folk, popular and art music traditions of Mexico and music in Mexican American/Chicano society; pre-Cortesian and contemporary indigenous musical practices; relationship of music to Mexican history and culture. Listening, reading and written work. Intended for non-music majors. May be used as a music-major elective. (MUS 304 and CHIC 304 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 305', 'Chicana/o Families', 'The Chicana/o family’s development as an American social institution focusing on cross-cultural, historical and interdisciplinary perspectives.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 306', 'Barrio Studies', 'How Latina/o and Mexican-origin communities develop in urban areas and the role of collective action in the community. Requires service learning.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 307', 'Research and Writing in Ethnic Studies', 'Introduction to research and writing in ethnic studies. Issues of research in ethnic studies (e.g., quantitative v. qualitative analysis, reliability/validity) and specific methods of research (e.g., archives, interviews, oral history). Extensive writing. A “C” (2.0) or better is required to satisfy the upper-division writing requirement. (ASAM 307, AFAM 307 and CHIC 307 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 313', 'La Chicana', 'Cultural influences that the family, religion, economic status and community play upon the lifestyles, values and roles held by Chicanas. (CHIC 313 and GSS 313 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 315', 'Chicano/Latino Theatre', 'Contemporary Chicano/Latino theater in relation to its historical evolution. Plays, playwrights and theater groups expressing the Chicano/Latino experience. Extensive play reading. (CHIC 315 and THTR 315 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 325', 'Chicana and Chicano Education', 'Overview of the educational plight of Chicanas/os in the American school system from an interdisciplinary perspective. Addresses educational inequality and social justice phenomenon using various concepts, theories and methodologies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 330', 'The Evolution of Mexican Literature', 'Survey and analysis of the Nahautl, Mexican and Chicano literature from pre-Columbian period to present.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 331', 'The Chicano Child', 'The Chicano child from preschool through grade six. Emphasizes motor, physical, social, intellectual, emotional growth and development and their effect on school adjustment and achievement. Field observation of preschool and grade school children required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 332', 'The Chicano Adolescent', 'The Chicano adolescent’s social, intellectual and emotional growth and development. Bicultural pressures from the barrio, family structure, school and achievement values.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 333', 'Mexican Literature Since 1940', 'Literature of Mexico since 1940: Carlos Fuentes, Rodolfo Usigli, Xavier Villarrutia, Juan Jose Arreola, Octavio Paz, Laura Esquivel and Juan Rulfo. Other contemporary authors may be included.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 336', 'Latin American Literature', 'Major periods and texts in Latin American literature. The transnational context of Latin American literature; reading major works (in English translation) by writers from Mexico, Central and South America, the Caribbean and the Latina/o U.S.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 337', 'Contemporary Chicana/o Literature', 'Chicana and Chicano literature from the 1960s to the present. Considers texts within their cultural, historical, social and political contexts. Relates Chicana/o literature to contemporary U.S. Latina/o writing and to the creative and performing arts.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 340', 'Mexican/Chicano Intellectual Thought', 'Emergence of the Chicano movement dealing with political, economic and sociological facets. Writings of Nahautl, Spanish, Spanish-American, Chicano and contemporary writers.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 345', 'History of the Chicano', 'History of the Chicano from the pre-Columbian period to the present. The Chicanos’ changing role in the United States, their cultural identity crisis and their achievements.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 350', 'Mexican Life and Culture', 'Introduction to Mexican culture and civilization. Contemporary Mexican society with focus on social, political, environmental, cultural and historical issues. Requires travel to La Paz, Baja California, Mexico and will only be offered in summer or intercession. Letter grade or Credit/No Credit. (LTAM 350 and CHIC 350 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 353', 'Mexico Since 1906', 'Mexican Revolution of 1910, stressing the political, economic and social aspects, as well as its contributions in the fields of art, literature and social reforms.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 367', 'Religion in Latino/a Life', 'National and international expressions of Latino/a religiosity - from popular religion to Marian devotion to curanderismo - through film, historical documents, poetry, theology, art, sociology and ethnic studies. (RLST 367 and CHIC 367 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 450', 'Seminar in Contemporary Chicana/o Issues', 'Study of selected contemporary research topics in Chicana/o Studies aimed at gaining an in-depth knowledge of a particular analytical, theoretical, and/or methodological approach.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 460', 'The Chicano and Politics', 'Theory of urban politics and evaluation of issues that affect the Chicanos and American society. Evaluations and surveys will be made on political organizations in Hispanic-surnamed communities. (CHIC 460 and POSC 460 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 480', 'Chicanas/os and Immigrants', 'Mexican- and Latino-origin immigration to the U.S. at key social structural levels.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 496', 'Student to Student Tutorial (1-3)', 'Learning through teaching. Three hours of work per week expected for each semester unit of credit and may include: tutorial preparations; consulting with instructors; reporting, analyzing and evaluating tutorial experiences. Requires independent research project on topic related to tutoring area.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 499', 'Independent Study (1-3)', 'Opportunity to study independently under the guidance of the faculty on a subject of special interest and approved by instructor. May be repeated for credit for a maximum of 6 units. Requires approval by the department chair and instructor(s) in charge of directing the study.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 500', 'Chicana/Chicano Studies Paradigms and Traditions', 'Interdisciplinary approaches, methods and theories used in the study of Chicana/Chicano and Latina/Latino populations and related topics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIC 599', 'Independent Graduate Research (1-3)', 'Individual library research or empirical project, with conferences with instructor as necessary, culminating in one or more papers. May be repeated for credit. Requires permission from instructor.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 101', 'Introduction to Child and Adolescent Development', 'Overview and practical application of major developmental concepts from birth to adolescence within different biological, familial, social and cultural contexts.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 140', 'Introduction to Early Childhood', 'Learn about and plan developmentally appropriate activities in early childhood settings for children ages 0-8 and their families.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 141', 'Intermediate Seminar in Early Childhood', 'Builds on an introductory practicum as students learn about and plan developmentally appropriate activities in early childhood settings for children ages 0-8 and their families. Minimum four hours of fieldwork per week for a total of 60 hours required for the semester.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 201', 'Child, Family, and Community', 'Relationships between child, family and community members; interaction among systems; influences of gender, abilities, language, culture, race, ethnicity, socio-economic status and political factors; impact of bias and sterotyping; community resources and culturally competent practices to support families.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 215', 'Observations in Early Childhood Settings', 'Introduces the appropriate application and limits of a variety of observation methods for use with young children and in early childhood settings; several assessment tools will be studied. Hands-on observations will focus on children, interactions, and environments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 300', 'Elements of Effective Professional Communication', 'Communication norms and standards in child and adolescent studies. Fosters written and oral communication skills to support students’ professional development and their ethical and effective work with diverse children, adolescents and families. Meets upper-division writing requirement for CAS majors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 301', 'Inquiry and Methodology in Development', 'Frameworks and methods for conducting and consuming empirical research on the development of children from diverse backgrounds. Introduces scientific method, including developing research questions/hypotheses, surveying, sampling and interpreting statistics. Read, analyze and synthesize research studies retrieved from library databases.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 305', 'Advanced Assessment in Early Childhood', 'Covers advanced assessment in early childhood. Combines knowledge of child development and commonly used practices to understand the conceptual and operational definition of observation and assessment strategies as relevant to establishing quality programs for young children.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 310', 'Assessing and Observing Development', 'Purposes, methods, ethics and implications associated with assessing and observing children and adolescents from diverse populations, including use of standardized measures of development and learning. Selection of methods and measures. Appropriate interpretation of data.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 312', 'Human Growth and Development', 'Biological/physical, socio-emotional and cognitive development across the lifespan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 315', 'Child Development', 'Major concepts, principles, theories and research related to cognitive, linguistic, social, emotional and physical development from birth through adolescence; emphasizes developmentally appropriate practices.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 321', 'Advanced Study of Infant and Toddler Development', 'Normative and atypical physical, social, emotional and cognitive development for children from birth to three years of age. Child development theories, research strategies and environmental, biological, and cultural influences on the development of young children. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 322', 'Preschool-Age Development', 'Normative and atypical physical, social, emotional and cognitive development for children 3-6 years of age and implications on child care services provided for preschool-aged children with an emphasis on developmentally appropriate practices.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 325A', 'Conception Through Age 8', 'Biological, psychological, cultural and environmental influences on children¿s physical, cognitive and socioemotional development from conception through age 8. Enhance understanding of developmental research and theories that support cultural competence. Apply knowledge to promote optimal development of children.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 325B', 'Age 9 Through Adolescence', 'Biological, psychological, cultural and environmental influences on physical, cognitive and socioemotional development from age 9 through adolescence. Enhanced understanding of developmental research and theories that support cultural competence. Apply knowledge to promote optimal development of older children and adolescents.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 326', 'Optimizing Development of School Age Children', 'Conditions that impact and facilitate development during middle childhood. These include external (e.g., appropriate support and empowerment across various contexts) and internal assets (e.g., social competence and commitment to learning). Highlights strategies that promote development.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 327', 'Optimizing Development During Adolescence', 'Conditions that impact and facilitate development during adolescence including external (e.g., appropriate support and empowerment across various contexts) and internal assets (e.g., self concept, commitment to learning). Strategies that promote development.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 330', 'Adolescence and Early Adulthood', 'Human development during and following adolescence. Community resources and services for adolescents and their families. Consequences of adolescent experiences for later development.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 340', 'Parenting Today', 'Goals and patterns of parenting in context of contemporary, multicultural society; identifies changing demands of parenting infants, children and adolescents; summarizes current scholarly research on relation of parenting practices to child development outcomes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 341', 'Working with Parents of Young Children', 'Responsibilities and influences of diverse family systems from the transition to parenting through children completing primary grades. Effective collaboration and communication with parents during early childhood years with the goal of optimizing children’s development.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 345', 'Child and Adolescent Development in Diverse Family Contexts', 'Patterns and processes of child/adolescent development within families of various cultural/ethnic/social contexts. Identifies multiple theoretical and disciplinary perspectives in studying child and family developmental processes, as well as summarizing the current related scholarly literature.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 346', 'Advanced Study in Preschool Development', 'Builds on previous foundation classes to explore current issues in child development from age 2 to 6 years. Explores implications for development across the physical, socio-emotional and cognitive domains in the context of diverse families and society.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 352', 'Numeracy and Science in Early Childhood', 'Theory and research on children’s scientific inquiry and numeracy development. Integrates science and mathematics in early childhood settings through interdisciplinary thematic units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 353', 'Learning and Motivation in Early Childhood', 'Building on the foundation developmental classes, this class examines theory and research on children’s learning, cognition and motivation with an emphasis on practical applications in early childhood settings. Developmental norms, individual and cultural variations, and curricular strategies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 360', 'Adolescents and the Media', 'Summarizes current social, cultural and behavioral research on adolescents and mass media. How teens use, learn, are depicted in, and shape cultural meaning from exposure to television and other electronic media.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 365', 'Adolescent Pregnancy and Parenting', 'Reviews current knowledge base on adolescent pregnancy and the developmental implications for parent and child. Social, educational and health implications of early parenting, and articulates the resources, skills and supports needed to foster success in parenting.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 370', 'Development of African American Children and Youth', 'Understanding cognitive and socio-emotional development of African American children and youth is facilitated through comprehensive examinations of significant African and African American cultural and historical experiences. (CAS 370 and AFAM 370 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 375', 'Adolescent Identity', 'Adolescent identity within the context of soci-emotional, physical, and cognitive development. Sociocultural factors (e.g., ethnicity, peers, family) that influence individual and group identities.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 380', 'Adolescent Sexuality and Intimate Relationships', 'Current trends, potential risks, and opportunities associated with adolescents’ involvement in sexual and intimate relationships from a normative developmental perspective. Socio-ecological contexts (e.g., families, peers, culture) of adolescents’ sexual and relational attitudes/behaviors are a central focus.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 394', 'Introductory Practicum in Child and Adolescent Studies', 'Minimum 60 hours of supervised practicum experience in agencies, institutions and organizations serving children, adolescents and/or their families. Analyze experience in relation to developmental theory, professional development skills, cultural competence and developmentally appropriate practice.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 464', 'Practicum Seminar in Early Care and Education', 'Minimum 60 hours of supervised practicum experience in licensed early childhood education settings, working directly with very young children (infants through age 5). Advanced analysis in relation to developmental theory, cultural competence and developmentally appropriate practice.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 474', 'Practicum in Development in School Settings', 'Minimum 60 hours of supervised practicum experience in elementary school settings serving K-6th grade students, working directly in a classroom. Advanced analysis in relation to California Academic Content Standards, developmental theory, cultural competence and developmentally appropriate practice.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 484', 'Practicum Seminar in Adolescent and Youth Services', 'Classroom analysis of field experience focusing on linkages between theory and practice, and skills and techniques of adolescent development/youth services professionals.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 484L', 'Practicum in Adolescent and Youth Services', 'Supervised field experience in agencies, institutions and organizations serving adolescents and families. Minimum of 4 hours per week for a total of 60 hours required for the semester. Credit/No Credit grade option only. May be repeated for a maximum of 2 units.', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 490T', 'Senior Seminar in Child and Adolescent Development', 'Integrating and applying knowledge, competencies and skills acquired in prerequisite courses to a specific developmental topic (varies by section), including considerations related to biological, psychological, social and cultural factors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 494', 'Practicum in Youth and Families in Community Settings', 'Minimum 60 hours of supervised practicum experience in licensed agencies, institutions or organizations that support children, adolescents (up to early 20s) or their families. Analyze experience in relation to developmental theory, professional development skills, cultural competence and developmentally appropriate practice.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 496', 'Student-to-Student Tutorial (1-3)', 'Work on student-to-student tutorial and related tasks under the direction of a Child and Adolescent Studies faculty member. May be repeated for a maximum of 6 units. Only 3 units may be taken in a single semester. Requires consent of instructor.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CAS 499', 'Independent Study (1-3)', 'Individual research project, either library or field, under the direction of a Child and Adolescent Studies faculty member. May be repeated for a maximum of 9 units. Only 6 units may be taken in a single semester.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 201', 'Statics', 'Vectorial treatment of statics of particles and rigid bodies. Free body diagrams. Applications to problems of equilibrium (two and three dimensions) of structural and mechanical force systems. Trusses, frames and machines. Friction problems. Centroids and moments of inertia.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 104', 'Computer-Aided Architectural and Civil Engineering Drafting', 'Architectural and civil engineering drawing with the aid of computer-aided drafting techniques; grading plans, engineering drawings (including standard structural, electrical and hydraulic details) of buildings, bridges, dams and civil engineering structures. Bill of Materials. (3 hours laboratory)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 110', 'Engineering Surveying', 'Basis of plane surveying. Distance measurement using tapes and EDM. Leveling. Measurement of angles and directions. Traverse and topographic survey and computations. Applications in highway curves, construction surveys and land surveys. Principles of stadia.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 110L', 'Engineering Surveying Laboratory', 'Field practice of measurement of distance, difference of elevation, and horizontal and vertical angles using tapes, EDM, automatic levels, theodolites and total stations. (3 hours laboratory)', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 203', 'Mechanics of Materials', 'Stress and deformation analysis for axial load, torsion, flexure, and combined forces. Analysis of simple statically indeterminate structures. Deflection and stress analysis of beams. Stability of columns. Strain energy and ultimate resistance. Interactive relationships between analysis and design.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 202', 'Dynamics', 'Kinematics and kinetics of particles and rigid bodies, kinetics of rigid bodies in three dimension, Newton’s laws, work and energy, impulse and momentum. Solution of problems using vector approach.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 308', 'Engineering Analysis', 'Fundamentals and engineering applications of Fourier transforms, Laplace transforms, complex analysis, vector analysis; engineering applications. (EGCE 308, EGEC 308, EGGN 308 and EGME 308 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 341L', 'Soil Mechanics Laboratory', 'Behavior and properties of soils. Application to foundation design, liquefaction and seepage.', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 320', 'Structural Analysis', 'Forces and displacements in statically determinate and indeterminate elastic structures by force and displacement methods. Approximate methods of analysis. Matrix formulation of structural analysis and computer applications. Introduction to structural design.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 321L', 'Structural Analysis Laboratory', 'Application of structural analysis to compare theory to experimental data obtained from testing small-scale model structures and large-scale structural elements built using different construction materials. Use computer software for parametric studies of structural behavior.', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 311L', 'Civil Engineering Materials Laboratory', 'Behavior and properties of most common materials, e.g., steel, concrete, wood, masonry and asphalt. Mix design of asphalt and concrete. Determine strain and stress using strain gages. Specimen testing according to ASTM. Material properties determination. Safety, reliability and design considerations. (3 hours laboratory)', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 401', 'Engineering Economics and Professionalism', 'Development, evaluation and presentation of design alternatives for engineering systems and projects using principles of engineering economy and cost benefit analysis. Engineering profession, professional ethics and related topics. (Not available for use on graduate study plans.) (EGEC 401, EGCE 401, and EGME 401 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 325', 'Reinforced Concrete Design', 'Design for bending, shear, axial force and combined loading. Ultimate strength and serviceability requirements for beams, columns and slabs. Safety, reliability and cost considerations. Design project conforming to the latest ACI code. Apply professional computer program.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 342', 'Foundation Design', 'Footings and retaining walls. Mat and piled foundations for structures. Design project to standards of professional practice using latest codes and standards. Consideration for safety, reliability and cost. (3 hours lecture)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 330', 'Engineering Hydraulics', 'Incompressible fluid flow in closed conduits and open channels. Hydrostatics, energy and hydraulic grade lines. Momentum, friction formulas, pipelines, uniform flow and water surface profiles. Design of pipes and open channels. Computer solutions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 331L', 'Engineering Hydraulics Laboratory', 'Introduction to experimental hydraulics in open channel and pipe flows, including measurements of discharge, depth, velocity, force and friction coefficients. Hydraulic model laws and report writing. (3 hours laboratory)', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 326', 'Structural Steel Design', 'Design for bending, torsion, shear, axial forces, combined loadings. Design of built-up girders, composite construction. Design of shear and moment connections. Design project using professional practice standards. LRFD method. Safety, reliability and cost considerations. Professional computer program. (3 hours lecture)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 431L', 'Advanced Structural Laboratory', 'Fundamentals of earthquake engineering and soil structure interaction; design of lateral bracing for model buildings. (3 hours laboratory)', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 432', 'Computer-Aided Design and Analysis in Civil Engineering', 'Computer-aided analysis and design in various branches of civil engineering. Introduction of finite element methods with computer techniques. Application of professional computer programs.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 430', 'Design of Hydraulic Structures', 'Applications of hydraulic principles to design of various structures, including spillways, energy dissipaters, outlet works, storm drains, culverts and water distribution systems. Use of computers in design process.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 431', 'Engineering Hydrology', 'Hydrologic cycle with applications to hydrologic design of engineering structures. Rainfall, stream flow, ground water, surface runoff, hydrographs, flood routing, frequency distributions and design hydrographs.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 370', 'Environmental Engineering', 'Planning and controlling the environment; wastewater treatment and disposal; solid waste management; air pollution; radiation protection; housing and residential environment.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 425', 'Precast and Prestressed Concrete Design', 'Prestressed concrete design and analysis for conventional and lateral loading. Design of reinforced and prestressed structural and architectural elements. Safety and economy. Connection design for earthquake and wind loading. Design projects using professional practice standards including latest codes. (3 hours lecture)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 463L', 'Precast and Prestressed Concrete Design Lab', 'Behavior of prestressed and reinforced concrete members subjected to the different types of loadings. Observe elastic and ultimate strength behavior, deflection crack propagation and collapse. Observe prestressing operation and camber. (3 hours laboratory)', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 450', 'Project Management and Construction Engineering Practices', 'Project management practices in engineering industry; discussion of major phases of construction project management, case discussions for real projects, introduction to: earned value, risk management, contractual agreements, value engineering; project delivery methods and fundamentals for writing project specifications, scheduling basics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 350', 'Construction Engineering', 'Engineering construction planning equipment and methods. Construction management. Critical path method. Construction of buildings, bridges, highways, foundations and dams. Consideration for safety and reliability.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 581', 'Remediation of Contaminated Soil and Groundwater', 'Site assessment, green technologies, design for soil remediation systems and design for groundwater remediation systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 582', 'Wastewater Treatment and Water Reclamation', 'Principles of anoxic, aerobic and anaerobic biological processes and treatment. Stepwise development and process design equipment selection, economic evaluation, green technologies and operating guidelines for wastewater treatment.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 420', 'Design of Highrise Structural Systems', 'Structural concepts and systems for buildings and complex structures; their behavior under loads. Foundation systems. Roof, floor, walls systems. Characteristics and design concepts of complex structures and high-rise buildings. Design project. Latest building codes and computer application. Sustainability and green building. (2 hours lecture and 3 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 551', 'Construction Methods and Equipment for Heavy Construction Engineering', 'Methods and equipment for construction foundations, highways, airfields, bridges, ports, harbors, dams, nuclear power plants and industrial facilities. Quality control and construction failures.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 494A', 'Senior Design', 'Real-world culminating design experience in a multidisciplinary civil engineering project. Use of professional practice codes and standards; realistic cost and safety constraints.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 494B', 'Senior Design', 'Civil engineering design using professional practice standards and realistic constraints. Professional documentation and presentation of results. Formal written reports and oral presentations describing the design project.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 415', 'Architectural Design', 'History of architectural design. Systems-based design process: aesthetic, functional, environmental and behavioral aspects. Urban planning and design. Case studies. Architectural design project to the standards of professional practice.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 497', 'Senior Projects (1-3)', 'Independent design projects. Formal report to be submitted after completion of project work. May be repeated for a maximum of 6 units. Requires adviser and department chair consent.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 499', 'Independent Study (1-3)', 'Special topics in civil engineering. Submit formal report after completing independent study. Requires adviser and department chair consent.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 501', 'Analytical Methods for the Design of Civil Engineering Systems', 'Applying linear and dynamic programming principles to the design of pipelines, irrigation systems, water-resources and traffic-flow control problems. Probabilistic network analysis. First order and advanced first order second moment reliability methods. Probabilistic design.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 510', 'The Finite Element Method', 'Formulating finite elements to analyze plane stress and strain problems, axisymmetric bodies, plates and shells. Conforming and non-conforming shape functions. Computer applications to complex structural systems under static and dynamic loads.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 575', 'Solid Waste Management, System Design and Sustainability', 'Industrial waste treatment and disposal, waste minimization, process selection, control, green technologies and resource recovery. Design of liners, gas and leachtate collection and removal systems in landfills.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 517', 'Theory of Elasticity', 'Analyze stress and strain. Equations of elasticity. Extension, torsion and flexure of beams. Two-dimensional elastostatic problems. Variational methods and energy theorems. Elementary three-dimensional elastostatic problems. Introduction to thermoelasticity and wave propagation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 522', 'Earthquake Engineering', 'Principles of seismic analysis and design for structural and non-structural elements based on current building codes. Earthquake motions, response spectra, energy absorption capacity of materials and structural components, earthquake-resistant building systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 520', 'Advanced Structural Analysis', 'Advanced applications of influence lines, matrix methods of structural analysis, introduction to the finite element method, computer-applications for advanced structural problems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 550', 'Advanced Construction Methods and Techniques', 'Advanced technologies in the construction of building, highway, bridge, dam structures and building materials and systems, such as concrete, steel, masonry and diverse methods and techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 530', 'Groundwater and Seepage', 'Satellite systems, link analysis, propagation effects, SNR/CNR calculations, modulation schemes, TDMA, FDMA and CDMA techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGCE 552', 'Preconstruction Design Evaluation', 'Cost benefit, preconstruction scheduling, and constructability modifications in design, specifications and construction methods. Value Engineering.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 101', 'Writing for Mass Media', 'Principles and practices of writing for major types of mass communications media. Content, organization, conciseness and clarity. All Fullerton campus lectures online, laboratory in classroom. Requires typing ability. (2 hours lecture, 2 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 201', 'Digital Reporting and Writing', 'Develop expertise in news reporting and writing for print, web and social media. Introduction to ethical and legal concerns for journalists; changing concepts of news; and data journalism. Pitch stories for publication by the Daily Titan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 202', 'Digital Reporting and Production', 'Develop expertise in news reporting and production for digital platforms, emphasizing visual storytelling and production. News content contribution to student media.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 233', 'Mass Communication in Modern Society', 'Internet, newspapers, magazines, film, radio and television; their significance as social instruments and economic entities in modern society.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 300', 'Visual Communication', 'Social and cultural analysis of the meaning, production and consumption of visual information in a modern media society. Still, moving, television, graphic design, cartoon and computer images will be analyzed in terms of technical, commercial and cultural considerations. Must earn a “C” or better to pass the course.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 301', 'Writing for the Entertainment Industry', 'Theory and principles of writing for the entertainment industry. Requires typing ability. (2 hours discussion, 1 hour activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 310', 'Mass Media Ethics', 'Moral and professional conduct within various communications contexts. Examine cases involved with advertising, broadcast journalism, film, photojournalism, print journalism, public relations, television and the World Wide Web.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 315', 'Mass Media and Diversity', 'Analyzes the representations of marginalized groups in mass media and popular culture. Evaluates gender, race, sexuality, religion, and other identities. Designed to make students more critical producers and consumers of the media.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 317', 'Digital Foundations', 'Develop ability to create and evaluate multimedia content. Preparation for digital portfolio graduation requirement.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 319', 'Visual Reporting', 'Image creation for publication in print and/or screen media. Convergence of the basic principles and practices of digital photography, digital imaging, graphic design and web page production for journalism-based visual problem solving.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 321', 'Studio Photography', 'Creative and effective use of images in print and/or screen publications within advertising, public relations, entertainment studies and other commercial, persuasive communication contexts.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 331', 'News Literacy', 'Provides a foundation in news literacy: using critical thinking skills to judge the reliability and credibility of information reports, whether via print, television, radio or Internet. Read and deconstruct a variety of news stories to determine their level of transparency and trustworthiness.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 332', 'Social Media, Editing and Design', 'Digital and print news editing: social media practices; copy improvement; headline writing; news photos and captions; online news production and management; design and typography principles; law and ethics. (2 hours lecture, 3 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 333', 'Mass Media Effects', 'The role mass media communications play in all human activity with heavy emphasis on the effects of mass media on the political, social and economic fabric of America.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 334', 'Feature Article Writing', 'Nonfiction writing for newspapers and magazines; sources, methods and markets.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 335', 'Public Affairs Reporting', 'Reporting public interest news such as courts, education, finance, government, police and urban problems. COMM 407 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 346', 'Principles of Entertainment and Tourism Communications', 'Structure and commercial functions of the entertainment and tourism industries. The central role of communication in industry technologies and professional practices. Career opportunities associated with these fields.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 350', 'Principles of Advertising', 'Overview of the advertising industry and its specializations. Contemporary functions, strategies, media, ethics and technology, as well as the role of integrated marketing communication.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 352', 'Advertising Media', 'Plan, execute and control advertising media programs. Basic data and characteristics of the media. Buying and selling process, techniques and methods in media planning process. Audience measurement and media analysis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 353', 'Advertising Creative Strategy and Execution I', 'Writing copy and layout advertisements, based on study of sales appeals, attention factors and illustrations. (2 hours lecture, 2 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 361', 'Principles and Ethics of Public Relations', 'Social, behavioral, psychological, ethical, economic and political foundations of public relations, and the theories of public relations as a communications discipline.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 362', 'Public Relations Writing I', 'Communications analysis, writing for business, industry and nonprofit organizations. Creating effective forms of public relations communication. Requires typing ability.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 372', 'TV News Production', 'Writing, production and evaluation of television news. Discussion of TV reporting techniques and problems. Cover events and produce TV news in lab. (2 hours lecture, 2 hours lab)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 380', 'Interactive Media Design', 'Underlying design concepts and production techniques for creating interactive multimedia presentations for educational lessons, commercial applications and online publications. (2 hours lecture, 2 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 407', 'Communications Law', 'Anglo-American concept of freedom of speech and press; statutes and administrative regulations affecting freedom of information and publishing, advertising and telecommunication. Libel and slander, rights in news and advertising, contempt, copyright and invasion of privacy.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 410', 'Principles of Communication Research', 'Research methods used to assess the effects of print, broadcast and film communications on audience attitudes, opinions, knowledge and behavior. Research design and data analysis in communications research.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 421', 'Advanced Studio Photography', 'Prepare an advanced portfolio of images for print and/or screen publications that demonstrates ability to produce professional quality illustrative assignments within advertising, public relations, entertainment studies and other commercial, persuasive communication contexts.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 422', 'Communications Technologies', 'Issues surrounding communications technologies. Recent developments in technology, impact of government, industry and economic factors, historical overview and implications for social change. Technological developments. Applications to all areas of mass communications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 328', 'Global Media', 'Major mass communication systems, both democratic and totalitarian, and the means by which news and propaganda are conveyed internationally. The role of media in the process of globalization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 434', 'Magazine Editing and Production', 'Produce a high-quality magazine and learn about the dynamics of magazine production and the magazine industry. May repeated for a maximum of 6 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 435', 'Opinion Writing', 'Techniques of editorial writing and opinion writing, including personal essays, for print, broadcast and Internet. The role of punditry in television news and on TV and radio talks shows, and how this might affect public perceptions of the media. Requires an upper-division writing course.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 436', 'Reporting on the Entertainment Industry', 'Developing expertise in reporting and writing on the entertainment industry. Understanding the economics, business models, legal aspects and culture of the industry. May be repeated once for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 437', 'Advanced Magazine Writing', 'Practical experience in reporting and writing long, in-depth feature articles for professional magazines. Challenges of researching and writing for specialized audiences and the business of freelancing. Techniques for improving clarity, brevity, cohesion and emphasis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 438T', 'Specialized Reporting', 'Varied topic course designed to teach advanced reporting and writing skills in specialized areas. Combines an awareness of techniques and resources with an abundance of writing models and field experiences. May be repeated once for credit with different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 444', 'Portfolio - Visual Communications', 'Build, refine and present a visual portfolio that demonstrates professional skills in a field of communication. Work individually and collaboratively to create and present multiple projects, r?sum? and portfolio.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 446', 'Entertainment and Society', 'Role of entertainment and tourism in modern society. Uses theoretical and historical approaches to explore how factors such as culture, technology, economics and politics intersect with the entertainment we create and consume.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 447', 'Tourism and Travel', 'Concepts, tools and techniques necessary for understanding the tourism and travel industry and its promotional communications. Trends and issues of tourism and travel and the unique problems and opportunities of this field.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 448T', 'Entertainment Industry Studies', 'Variable topics course that focuses on specific entertainment industries, issues, organizations, trends and/or functions. May be repeated once for credit with different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 449', 'Capstone - Entertainment and Tourism Communications', 'Prepares for entertainment industry careers by combining theory with applied principles and analytical skills in examining and developing case studies. Students plan and execute their own campaigns and projects. A “C-” (1.7) or better is required to pass course.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 450', 'Advertising and Brand Communication Management', 'Theory and techniques for planning, directing and evaluating advertising and brand communication programs, with emphasis on media-message strategies. Managerial approach with case studies to the solution of brand communications problems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 452', 'Advanced Media Strategy and Tactics', 'Further education in advertising media. Integrates theories from related disciplines, such as communications, marketing and psychology to illustrate better ways to use media as a competitive tool in business.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 453', 'Advertising Creative Strategy and Execution II', 'Advertising projects involving application and execution of creative advertising strategies for mass media, including theory and practice of writing copy, and preparing comprehensive layouts and completed scripts. Group discussions, labs and individual conferences.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 454', 'Advertising Media Sales', 'Advertising media sales, emphasizing print, special event, online and social media platforms. Work directly with the Daily Titan advertising staff while developing personal sales techniques, media sales strategies and supporting marketing tactics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 455', 'Internet Advertising and Promotional Communications', 'Internet advertising and marketing issues and ideas. Evaluate, develop and execute Internet-based advertising and promotional campaigns.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 456', 'Advertising Account Planning', 'Apply principles of research, consumer behavior and creative concept development to advertising and brand communication campaigns. Field study and case application facilitate the process of the planner’s consumer advocacy function.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 457', 'Broadcast Advertising', 'Theoretical and practical exposure to the field of broadcast advertising from an agency perspective, including positioning, creative brief writing, strategy, script development and analysis, storyboarding and pitching.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 462', 'Public Relations Writing II', 'Further develops strategic and creative public relations writing skills for multimedia platforms. Cultivates the ethical awareness and sensitivity essential for media gatekeepers.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 465', 'Entertainment Public Relations', 'Public relations strategies and tactics as they are used in the entertainment industry, including media relations, talent relations, special events, high visibility techniques, presentation, and dealing with adverse situations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 468', 'Corporate and Nonprofit Public Relations', 'Public relations strategies and tactics used in today’s increasingly sophisticated and maturing corporate and nonprofit marketplaces. Professional guest speakers and in-class simulations/exercises. Fund raising, corporate and social responsibility, media relations, and technology and ethical issues.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 469', 'Crisis Communications', 'Practical experience in preparing for and responding to crisis situations across a wide variety of contexts. Theory and practice of organizational issue management, crisis planning and crisis response. Current and future challenges of issue/crisis management.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 471', 'Capstone - Daily Titan News', 'Students form the editorial staff of Daily Titan, the university newspaper; training in print and online journalism. Meets four hours per week for critiques in news reporting, writing, editing and production. (more than 9 hours laboratory.) Must pass with a “C-” (1.7) or better.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 472', 'Capstone - TV News', 'Produce, report and anchor live television newscast OC News. Learn online journalism. (2 hours lecture, 3 hours lab.) May be taken for credit for a maximum of six units. Must pass with a “C-” (1.7) or better.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 480', 'Persuasive Communications', 'Persuasive communications applied to mass communication. The communicator, audience, message content and structure, and social context in influencing attitudes, beliefs and opinions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 481', 'Advanced Interactive Media Design', 'Interactive media design for various platforms and design topics, such as interactive narratives, experience design, usability and accessibility and productive interaction. Learn to use current interactive media protocols to develop projects for interactive audiences. (2 hours lecture, 2 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 495T', 'Mass Media Internship', '120 hours minimum of supervised fieldwork at a CICE-approved internship site. Practical application of academic knowledge within the student’s field of concentration via hands-on experience in the professional arena. Attendance at an orientation session is required. Details at: communications.fullerton.edu/internship.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 496', 'Student-to-Student Tutorial (1-3)', 'Under faculty supervision, provides tutorial assistance in a communications course. May involve small group demonstrations and discussions, individual tutoring and evaluation of student performance as appropriate. May be repeated for a maximum of 6 units either separately or in combination with COMM 499. Requires superior performance in a similar or equivalent course.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 497T', 'Event Planning and Management', 'Plan, produce and promote public events to meet communication objectives. Hands-on applications to COMM Week, Newport Beach Film Festival, Fullerton Arboretum or other events. May be repeated once for extra elective units only.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 499', 'Independent Study (1-3)', 'Individually supervised mass media projects and research on campus and in the community. May involve newspaper and magazine publishers, radio and television stations, and public relations agencies. May be repeated for a maximum of 6 units, either separately or in combination with COMM 496. Requires consent of department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 500', 'Theory and Literature of Communications', 'Theories and research on communication processes and effects; source, media, message, audience and content variables; types, sources and uses of communication literature. Graduate seminar.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 507', 'Communications Research Design and Analysis', 'Develops a working knowledge of data collection and analysis techniques in both quantitative and qualitative research methods. Material and presentation are developed for practical application to all professional fields of communication. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 508', 'Humanistic Research in Communications', 'Humanistic methods of study in communications: historical research and critical analysis applied to problems, issues and creative works in communication. Graduate seminar.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 509', 'Social Science Research in Communications', 'Social-scientific research design and analysis and the study of communication processes and effects. Graduate seminar.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 515T', 'Professional Problems in Specialized Fields', 'Selected topics and issues in the field of mass communications. Subjects vary each semester. May be repeated with different topics for a maximum of 21 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 516', 'Media Audience Behavior', 'In-depth analysis of the types, attitudes and behaviors of media audiences. Theories from psychology, marketing, anthropology and communications are integrated for comprehensive understanding of why people consume media and performance. Appropriate for all communications disciplines.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 517', 'Ethical Problems of the Mass Media', 'Criticisms of specific functions of the mass media and public relations. Three sections: history of criticism; problem areas of the media; and practitioner response to criticism.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 518', 'Public Relations Theory', 'Cutting-edge communication and organizational theories and vital emerging issues influencing the field of public relations. Special focus on contemporary public relations models and practitioner roles.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 525', 'Advanced Communications Management', 'Up-to-date assessment of general management and communications management techniques, and helps equip the student for management positions in advertising, journalism, public relations and broadcasting.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 527', 'Politics and Mass Media', 'Nature of the relationship between the mass media and politics. Particular attention to the role and impact of the mass media in political election campaigns and policy making.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 536', 'International Communications', 'Comparative examination of communications policies and practices in different national settings. Provides future practitioners with an understanding of cross-national variations in communication policies and how they shape communication industries and practices.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 541', 'Film Criticism', 'Graduate foundation course in screenwriting that examines methods of evaluating and critiquing motion picture screenplays and films for a variety of Hollywood genres.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 550', 'Advertising in Modern Society', 'Assessing the impact of advertising on society, the culture and economy. Philosophical rather than technical examinations of critical issues and problems such as economic and social effects of advertising, effects of value and life styles, ethics and regulation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 563', 'Tourism Venues and Attractions', 'Communication efforts in developing entertainment themes in tourism destinations, venues and attractions to draw both attention and audiences. Different public relations and advertising principles used in targeting media and specific publics are examined.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 595', 'Graduate Mass Media Internship', 'Supervised practical work experience with media outlets, advertising and promotion agencies, public relations firms, film companies, etc. Involves cooperative efforts of departmental faculty and employers. Current and innovative techniques in research, management and creative activities while offering practical experience. Requires consent of graduate adviser.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 597', 'Project', 'Complete creative project in a sequence beyond regularly offered coursework. Requires consent of graduate coordinator.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 598', 'Thesis (3-6)', 'Complete a thesis in a sequence beyond regularly offered coursework. May be repeated for a maximum of 6 units. Requires consent of graduate coordinator.', 3, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMM 599', 'Independent Graduate Research (1-3)', 'Individually supervised mass media projects or research for graduate students. May be repeated for a maximum of 6 units. Requires consent of graduate coordinator.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 180', 'Digital Logic and Computer Structures', 'Binary number system and arithmetic, computer codes, Boolean algebra, logic gates, K-map minimization, sequential circuits, memory devices, state diagram and table, computer architecture, memory, Arithmetic Logic Unit and control unit. (2 hours lecture, 2 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 371', 'Modeling and Simulation of Signals and Systems', 'Modeling and simulation of physical systems, mathematical description of systems, transfer functions, poles and zeros, frequency response, continuous and discrete-time convolution, continuous and discrete Fourier transforms, Laplace and Z transforms, Fast Fourier Transforms, simulation using Matlab.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 381', 'Computer Design and Organization', 'Computer system, central processing unit (CPU) organization and design, instruction set and addressing modes, microprogrammed control unit design, cache memory, internal memory, virtual memory, input/output interfacing, parallel processors, superscalar processors (2 hours lecture, 4 hours laboratory).', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 441', 'Advanced Electronics for Computer Engineers', 'High-speed CMOS, biCMOS, CPLDs, FPGAs, A/D, D/A, transducers and optics; integration of these devices into complete systems. (2 hours lecture, 4 hours laboratory)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 450', 'Embedded Processor Interfacing', 'Techniques of interfacing based on speed, timings, synchronization, interrupts, protocols, noise, and race conditions. Interfacing specifications of the processor data, address and control buses. (2 hours lecture, 4 hours laboratory)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 456', 'Introduction to Logic Design in Nanotechnology', 'Promising novel Nanoelectronic technologies and logic primitives for such technologies, applicable basic logic design technique, design models for spatial dimensions, applicable word-level data structures, multilevel circuit design, testability and observability, tolerance and reliable computing.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 463', 'Current Topics in Computer Engineering', 'Topics of contemporary interest from the perspective of current research and development in computer engineering. Lectures by guest professionals.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 470', 'Multidisciplinary Projects in Computer Engineering - I', 'The first course in the two-course senior design sequence. Student teams develop a hardware/software project, from conception through implementation and testing, under an instructor’s supervision. Teams first explore technology issues related to the projects and then prepare complete design proposals.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 471', 'Multidisciplinary Projects in Computer Engineering - II', 'Second course in the two-course senior design course in which student teams develop a hardware/software project under the supervision of the instructor. Develop design skills, based upon previous and current courses and laboratory experience. (4 hours laboratory)', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 120', 'Introduction to Programming', 'Introduction to the concepts underlying all computer programming: design and execution of programs; sequential nature of programs; use of assignment, control and input/output statements to accomplish desired tasks; design and use of functions. Structured and object-oriented methodologies. (1.5 hours lecture, 3 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 121', 'Object-Oriented Programming', 'The object-oriented programming paradigm: classes, member functions, interfaces, inheritance, polymorphism, and exceptions. Design practices including encapsulation, decoupling, and documentation. Pointers/references and memory management. Recursion. (2 hours lecture, 2 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 131', 'Data Structures', 'Classical data structures: vector, linked list, stack, queue, binary search tree, and graph representations. Worst-case analysis, amortized analysis, and big-O notation. Object-oriented and recursive implementation of data structures. Self-resizing vectors and self-balancing trees. Empirical performance measurement.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 223J', 'Java Programming', 'Characteristics of Java: portable, robust, secure, object-oriented, high performance; using the Java environment; server administration; types, expressions and control flow; classes, interfaces and packages; threads; exceptions; class libraries; Java for the Internet; tools, the Java Virtual machine. (2 hours lecture, 2 hours lab per week)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 223N', 'Visual C# Programming', 'Characteristics of C#, object-oriented design concepts, control structures, methods, arrays, classes, objects, inheritance, polymorphism, exception handling, graphical user interfaces, multithreading, characters, strings, files, streams. Rudiments of the Unified Modeling Language Software development assignments. (2 hours lecture, 2 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 240', 'Computer Organization and Assembly Language', 'Digital logic and architecture of a computer system, machine level representation of data, memory system organization, structure of low-level computer languages. Machine, assembly, and macro language programming. Principles of assembler operation, input-output programming, interrupt/exception handling. Laboratory programming assignments. (2 hours lecture, 2 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 253U', 'Workshop in UNIX', 'Workshop in the use of the UNIX operating system. (2 hours activity)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 254', 'Applied Artificial Intelligence', 'Concepts of Artificial Intelligence, application software and open-source projects. Understanding AI capabilities, AI applications, their impact and ethical issues. Identifying domain-specific problems and solving them with AI technologies and related open-source projects.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 301', 'Programming Lab Practicum', 'Intensive programming covering concepts learned in lower-division courses. Procedural and object oriented design, documentation, arrays, classes, file input/output, recursion, pointers, dynamic variables, data and file structures.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 311', 'Technical Writing for Computer Science', 'Develop documentation skills as used in the computer field. Proposals, feasibility studies, user guides and manuals, business communication and technical presentation. Case studies in professional ethics. Written and oral reports required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 315', 'Professional Ethics in Computing', 'Ethics and moral philosophy as applied to software and digital artifacts. Notions of rights, responsibilities, property, ownership, privacy, security, and professional ethics. Security obligations. Intellectual propertystatutes, licenses, and their terms. Oral and written reports are required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 323', 'Compilers and Languages', 'Basic concepts of programming languages and principles of translation. Topics include history of programming languages, various programming paradigms, language design issues and criteria, design of compilers for modern programming languages.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 332', 'File Structures and Database Systems', 'Fundamental theories and design of database systems, the Structured Query Language (SQL), basic concepts and techniques of data organization in secondary storage. Topics include introduction to database systems, ER model, relational model, index structures and hashing techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 335', 'Algorithm Engineering', 'Algorithm design using classical patterns: exhaustive search, divide and conquer, randomization, hashing, reduction, dynamic programming, and the greedy method. Asymptotic and experimental efficiency analysis. NP-completeness and decidability. Implementing algorithms to solve practical problems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 386', 'Introduction to Game Design and Production', 'Current and future technologies and market trends in game design and production. Game technologies, basic building tools for games and the process of game design, development and production.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 431', 'Database and Applications', 'Database design and application development techniques for a real world system. System analysis, requirement specifications, conceptual modeling, logic design, physical design and web interface development. Develop projects using contemporary database management system and web-based application development platform.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 440', 'Computer System Architecture', 'Computer performance, price/performance, instruction set design and examples. Processor design, pipelining, memory hierarchy design and input/output subsystems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 462', 'Software Design', 'Concepts of software modeling, software process and some tools. Object-oriented analysis and design and Unified process. Some computer-aided software engineering (CASE) tools will be recommended to use for doing homework assignments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 463', 'Software Testing', 'Software testing techniques, reporting problems effectively and planning testing projects. Students apply what they learned throughout the course to a sample application that is either commercially available or under development.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 464', 'Software Architecture', 'Basic principles and practices of software design and architecture. High-level design, software architecture, documenting software architecture, software and architecture evaluation, software product lines and some considerations beyond software architecture.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 466', 'Software Process', 'Practical guidance for improving the software development process. How to establish, maintain and improve software processes. Exposure to agile processes, ISO 12207 and CMMI.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 471', 'Computer Communications', 'Introduction to digital data communications. Terminology, networks and their components, common-carrier services, telecommunication facilities, terminals, error control, multiplexing and concentration techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 474', 'Parallel and Distributed Computing', 'Concepts of distributed computing; distributed memory and shared memory architectures; parallel programming techniques; inter-process communication and synchronization; programming for parallel architectures such as multi-core and GPU platforms; project involving distributed application development.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 449', 'Web Back-End Engineering', 'Design and architecture of large-scale web applications. Techniques for scalability, session management and load balancing. Dependency injection, application tiers, message queues, web services and REST architecture. Caching and eventual consistency. Data models, partitioning and replication in relational and non-relational databases.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 481', 'Artificial Intelligence', 'Using computers to simulate human intelligence. Production systems, pattern recognition, problem solving, searching game trees, knowledge representation and logical reasoning. Programming in AI environments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 483', 'Introduction to Machine Learning', 'Design, implement and analyze machine learning algorithms, including supervised learning and unsupervised learning algorithms. Methods to address uncertainty. Projects with real-world data.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 484', 'Principles of Computer Graphics', 'Examine and analyze computer graphics, software structures, display processor organization, graphical input/output devices, display files. Algorithmic techniques for clipping, windowing, character generation and viewpoint transformation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 485', 'Computational Bioinformatics', 'Algorithmic approaches to biological problems. Specific topics include motif finding, genome rearrangement, DNA sequence comparison, sequence alignment, DNA sequencing, repeat finding and gene expression analysis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 486', 'Game Programming', 'Survey of data structures and algorithms used for real-time rendering and computer game programming. Build upon existing mathematics and programming knowledge to create interactive graphics programs.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 489', 'Game Development Project', 'Individually or in teams, students design, plan and build a computer game.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 499', 'Independent Study (1-3)', 'Special topic in computer science, selected in consultation with and completed under the supervision of instructor. May be repeated for a maximum of 9 units of Undergraduate credit and 6 units of Graduate credit. Requires approval by the Computer Science chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 531', 'Advanced Database Management', 'Implementation techniques for query analysis, data allocation, concurrency control, data structures and distributed databases. New database models and recent developments in database technology. Student projects directed to specific design problems. CPSC 431 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 541', 'Systems and Software Standards and Requirements', 'SESC framework and the IEEE Software Engineering Standards. Establishing the following standards: Software Life Cycle Processes, Work Product Standards, Process Standards, Requirement Analysis and Management and System Integration. Introduces CMMI framework; discuss number of practical lessons. CPSC 362 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 542', 'Software Verification and Validation', 'Theory and practice of software verification and validation (V&V), including software integrity levels, minimum V&V tasks, walkthroughs, inspections and clean room. Topics include: white-box and black-box testing, boundary value analysis, equivalence class partitioning, unit testing, functional testing and test plans. CPSC 362 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 543', 'Software Maintenance', 'Theory and practice of maintaining large-scale software. Maintenance framework, process, measures, and process management. Topics include fundamentals of software change and its implications, maintenance process models, reusability for maintenance, reverse engineering, maintenance testing, software configuration management and tools in maintenance. CPSC 362 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 544', 'Advanced Software Process', 'Advanced guidance for defining and improving the software development process. Concepts of software maturity framework, principles of process improvement and software process assessment. Current topics such as CMMI and SCAMPI. CPSC 362 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 545', 'Software Design and Architecture', 'Advanced software design and architecture principles focusing a software engineering approach to the development process. Topics include architecture business cycle, quality attributes, attribute-driven design method, architectural styles, design patterns, software product lines and component-based design. CPSC 362 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 546', 'Modern Software Management', 'Modern project management methodologies and techniques. Software development process. Planning, estimating, organizing, directing, monitoring, controlling software projects and managing risks. Other related software management issues, such as infrastructure, quality software development, project and product metrics and external factors. CPSC 362 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 547', 'Software Measurement', 'Current software measurement practices. Topics include: establishing an effective software metrics program; measuring software product, project and process; applying Statistical Process Control and other statistical techniques. High maturity concepts defined in CMMI model will be discussed. Stresses a practitioner-based approach. CPSC 362 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 548', 'Professional, Ethical and Legal Issues for Software Engineers', 'Professional, legal and ethical issues pertaining to software engineering. Topics include professional codes of ethics, intellectual property laws, computer privacy and human-computer interaction. Relevant regulatory documents and their applications. CPSC 362 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 551', 'Operating Systems Design', 'Design and evaluation techniques for controlling automatic resource allocation, providing efficient programming environments and appropriate user access to the system, and sharing the problem solving facilities. CPSC 351 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 558', 'Advanced Computer Networking', 'System-oriented view of computer network design, protocol implementation, networking, high-speed networking, network management, computer network performance issues. CPSC 471 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 566', 'Advanced Computer Graphics', 'Three-dimensional: reflection models, shading techniques, rendering process, parametric representation, ray tracing, radiosity, texture, anti-aliasing, animation, color science. CPSC 484 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 583', 'Knowledge Representation and Reasoning', 'A field of artificial intelligence representing information about the world in a form that a computer system can use to solve complex tasks. Representing knowledge symbolically for automated reasoning; inference algorithms; logic programming; Semantic Web; reasoning under uncertainty; Requires project. CPSC 481 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 585', 'Neural Networks, Deep Learning, and Reinforcement Learning', 'Principles of artificial neural networks, designing network architectures, implementations and applications. Principles of reinforcement learning, frameworks, designing solutions, implementations and applications. Principles of deep learning and applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 589', 'Seminar in Computer Science', 'Research methods in computer science. Current technology trends and research topics. Verification of computer science theories and principles. Identification of practical application development and/or research problems. Presentations on selected topics and problems. Writing a proposal for a capstone graduate project.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 597', 'Project', 'Conduct a computer science research or development project proposed in the selected topic, complete it, write a final project report, and present the results in partial fulfillment of the requirements for the master’s degree. Classified graduate standing and approval of the computer science graduate adviser are required to enroll.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 598', 'Thesis', 'Requires approval of the Computer Science graduate adviser.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPSC 599', 'Independent Graduate Research (1-3)', 'Special topic in computer science, selected in consultation with and completed under supervision of a full-time faculty member. May be repeated for a maximum of 6 units. CPSC 589 recommended. Requires approval of Computer Science department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 252', 'Career and Life Planning', 'Career, personal and educational awareness. Strategies include integrating skills, abilities, interests and values into the career search. Decision-making and goal setting. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 350', 'Leadership Skills and Personal Development', 'Leadership concepts and skills, including psychological process, conflict resolution, counseling and human service skills. Becoming aware of personal leadership styles; maintaining vitality through physical and mental health. (HUSR 350 and COUN 350 are the same course).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 380', 'Theories and Techniques of Counseling', 'Contemporary theories and techniques of counseling. The counseling process, comparison of various theoretical approaches, introduction to professional and ethical issues. (HUSR 380 and COUN 380 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 500', 'The Counseling Profession', 'Counseling as a mental health profession, including its history, current functions and future directions. The counselor as a professional, including educational goals, personal values and cultural understandings. Opportunity to observe master counselors at work.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 502', 'Career and Lifestyle Development', 'Survey of career and lifestyle development throughout the lifespan. Major theories and strategies in career counseling. Integrating knowledge of career development with the practice of counseling. (COUN 502 and PSYC 502 are the same course). Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 511A', 'Pre-Practicum', 'Basic counseling skills, including establishing a therapeutic relationship, facilitating client self-exploration and understanding how one’s values influence the counseling process. Crisis intervention. Extensive role play practice. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 518', 'Human Development and Functioning', 'Human development from infancy to old age, and its effect on individuals, couples and family relationships. Implications for counseling; role of cultural/social contexts and social stressors; role of human sexuality in development. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 520', 'Modes of Individual Counseling', 'Advanced study of major theoretical frameworks in counseling, including models of personality, definitions of individual dysfunction and approaches to treatment. Practice in case conceptualization and application of theories to counseling.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 521', 'Research in Counseling', 'Applied research methods, critical evaluation of research in counseling and completion of literature review for anticipated COUN 597 project. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 522A', 'Diagnosis and Treatment Planning', 'Advanced study of the latest edition of the Diagnostic and Statistical Manual of Mental Health Disorders (DSM). A comprehensive bio/psychosocial/cultural view, focusing on diagnosis and assessment of major diagnostic categories, as well as integrative treatment planning', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 524', 'Child and Adolescent Counseling', 'Knowledge and clinical skills practice for counseling culturally diverse children/adolescents using play therapy and creative/expressive arts. Principles related to consultation with parents/teachers. Seven contact hours of training in child abuse assessment and reporting.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 525', 'Psychopharmacology for Counselors', 'Introduces biochemical basis of behavior and a general knowledge of the effects and side effects of the major classes of psychotropic drugs. Such knowledge is to make appropriate referrals and a comprehensive approach to treatment.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 526', 'Professional, Ethical and Legal Issues in Counseling', 'Current ethical and legal standards in practice of counseling and marriage and family therapy. Issues related to child/partner/elder abuse and substance abuse. Role of counselor values, work contexts and client-centered perspective in ethical decision-making. Licensing laws and process. Must pass with a B or better to advance to COUN 530. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 527A', 'Systems of Family Counseling', 'Survey of the leading family systems models/theories, focusing on cultural responsiveness.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 528', 'Groups: Process and Practice', 'Basic issues and concepts related to group process. Demonstration of culturally informed group leadership skills, emphasizing self-reflection.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 530A', 'Practicum', 'Supervised clinical practice with adults, families and children in approved community agencies. Practice in case management, documentation, use of community resources. Emphasizes dysfunction and health functioning. Hours accrued toward 280 required for yearlong practicum experience. Credit/No Credit only. May be repeated for a maximum of 6 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 535', 'Addictions Counseling', 'Etiology and treatment of addictive behaviors (e.g. substance abuse, gambling). Biological, psychological and systemic factors. Current approaches to assessment, intervention, prevention programs and relapse prevention, including Motivational Interviewing. Role of co-occurring disorders. Using community resources to help client and client’s family. (COUN 535 and PSYC 535 are the same course).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 560', 'Appraisal in Counseling', 'Theories and applications of psychological testing and other means of appraisal, as they relate to the practice of community-based counseling and marriage and family therapy.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 562', 'Intimate Partner and Couples Counseling', 'Treating intimate partners and couples, including overview of current theories, assessment, goal-setting, interventions, ethical issues and diversity issues. Assessing and treating intimate partner violence. Sexual dysfunctions and sex therapy. (COUN 562 and PSYC 562 are the same course)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 584A', 'Advanced Practicum', 'Advanced supervised clinical practice with adults, families and children in approved community agencies. Diagnosis, treatment planning, applied use of theory and techniques. Hours accrued toward 280 required for yearlong practicum experience. May be repeated once for credit. Credit/No Credit only.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 590', 'Advanced Counseling Techniques (1-3)', 'Advanced interventions, such as disaster and trauma response with attention to resilience, helping issues with the severely mentally ill, case management and evidenced-based practice. Required as part of yearlong practicum experience. Hours may be accrued toward 280 minimum. May be repeated for a maximum of 12 units. Credit/No Credit only.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 597', 'Project', 'Capstone program experience; taken final semester. Conduct original research relevant to the counseling field. Requires consent of faculty adviser.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COUN 599', 'Independent Study (1-3)', 'Research and development in counseling pursued independently with periodic conference with instructor. May be repeated for a maximum of 3 units. Requires consent of instructor or graduate program adviser.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 300', 'Foundations of Criminal Justice', 'Overview and analysis of the components of the criminal justice system; emphasizing the historical and contemporary aspects of law, policing, courts and corrections.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 303', 'Controlling Crime', 'Crime control and prevention. Common criminal justice tactics, such as imprisonment, capital punishment, camera surveillance, electronic monitoring, restorative justice, and situational crime prevention. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 484', 'Criminal Law: Substantive', 'History and evolution of criminal law from common law origins to present. Elements of crime, criminal offenses and defenses. Apply basic legal analysis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 315', 'Police and Society', 'Critical overview of local policing from a historical and contemporary lens. Organizational structure, law and practices, including discretion, use of force and police-public interactions in a diverse society. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 322', 'Leadership for Public Service', 'Conceptions of leadership as applied in governmental and nonprofit sectors. Types of leaders; tools for leaders; leadership in public policy-making settings. Includes student project and extend leadership concepts; participation in CSUF Student Leadership Institute or similar activity. (POSC 322 and CRJU 322 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 330', 'Theories of Crime and Delinquency', 'Historical foundations and development of criminological theories to explain criminal behavior. Implications for criminal justice policy and practice. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 340', 'Criminal Justice Research Methodology', 'Introduction to basic techniques in criminal justice research; focus on literature review, correlation/causation, research design and sampling techniques. Read research reports and critically analyze research study methodology. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 345', 'Complexities in Corrections', 'Overview of the history and philosophies of corrections, emphasizing current trends and populations, policies and practices for adult correctional systems. The experience of individuals, from intake to reentry and its impacts on communities and society. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 385', 'Race, Inequality and the Criminal Justice System', 'Historical and current issues that contribute to the overrepresentation of racial/ethnic individuals in criminal justice system. Utilizes current research, theory and practice with an intersectional approach to promote effective polices that lead to greater equality across individuals and communities.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 405', 'Criminal Justice Policy', 'Evolving purposes and practices associated with the development of criminal justice policies, principally in the U.S. Particular topics, such as sentencing legislation, illustrate the development, adoption and impact of public policy on criminal justice systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 406', 'Crime and Popular Culture', 'How the prevalence of crime and violence in popular culture reflects on contemporary society. Materials and readings argue that images of crime are not only entertaining, they also perform deep social and political functions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 422', 'Human Resources Management', 'Civil service and the merit system; recruitment procedures and examinations; position classification, salary structures, retirement plans, in-service training, employee organizations and personnel supervision. Examples and cases from the criminal justice field. Emphasizes themes and topics from criminal justice. (POSC 422 and CRJU 422 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 435', 'Civil Disobedience and Social Justice', 'The violation of law as protest. Definitions and types of disobedience and the policing and punishment of dissent. Analysis of protest as a strategy for social justice. (CRJU 435 and POSC 435 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 440', 'Correctional Rehabilitation', 'Theories and techniques of correctional treatment. Current state of correctional rehabilitation with a focus on the What Works! literature and the value of proper programmatic evaluation and correctional classification.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 455', 'Gangs and the Criminal Justice System', 'Causal factors of, and legal solutions to, gang-related crime in the U.S. Relevance of sociological, psychological, economic and educational deviance theories to justice intervention strategies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 462', 'Crime Analysis', 'Crime analysis function within the law enforcement organization; how to develop, implement and operate a crime analysis unit, and discuss the nexus between crime analysis, field and investigative operations, and administrative bureaus.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 465', 'Law, Punishment and Justice', 'Theoretical scholarship in criminal justice is increasingly concerned with law in relation to delivery of justice and practices of punishment. Examines the rule of law, questions whether justice is different from law and reviews the role punishment plays.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 471', 'Moot Court: Legal Practicum', 'Open to undergraduates only. Prepares students for competition. Legal research, writing, court strategies and oral argument; civil liberties law, cases and adjudication; appellate court review and amicus brief reading and writing. May be repeated for a maximum of 12 units. (POSC 471 and CRJU 471 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 472', 'Judicial Politics', 'Examines the United States courts and jurisprudence as a political body. Explores the politics, procedures and theories covering federal and state courts. (CRJU 472 and POSC 472 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 475T', 'Topics in Administration of Justice: A Seminar', 'Current social, legal and practical problems confronting police, courts and corrections. Variable topic class with specific subjects to be announced each semester. May be repeated with different topics up to a maximum of 9 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 480', 'Courtroom Evidence', 'Rules of evidence in the context of a criminal trial in a California court. Rules, their application and rationale. Lecture, discussion and simulated courtroom situations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 485', 'Search, Seizure and Interrogation I', 'Analyze laws that apply in common street search-and-seizure and interrogation situations in California; how they have evolved, and what developments are anticipated.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 486', 'Search, Seizure and Interrogation II', 'Analyze laws that apply in some search-and-seizure and interrogation situations, such as those involving the border patrol and college officials.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 492', 'Prelaw Internship', 'Acquaints students with the legal profession. A supervised working commitment of eight hours weekly with an assigned individual or organization. May be repeated once for credit. (POSC 492 and CRJU 492 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 495', 'Internships', 'Criminal justice professions; eight to 20 hours per week as a supervised intern in a public agency or related organization. In addition to the job experience, interns meet in a weekly three-hour seminar. May be repeated once for credit. Requires consent of instructor.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CRJU 499', 'Independent Study (1-3)', 'Student selects an individual research project, either library or field. Conferences with adviser as necessary, culminating in one or more papers. May be repeated for a maximum of 6 units. Requires consent of adviser.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ECON 100', 'The Economic Environment', 'Application of economics to the problems of unemployment and inflation, the distribution of income, competition and monopoly, the role of government in the economy, other policy issues. Not open to pre-business, business administration majors or minors, economics majors or minors or international business majors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ECON 201', 'Principles of Microeconomics', 'Principles of individual consumer and producer decision-making in various market structures, the price system, market performance and government policy.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ECON 202', 'Principles of Macroeconomics', 'Principles of macroeconomics analysis and policy, unemployment and inflation, financial institutions, international trade, economic growth, comparative systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ECON 595', 'Current Research in Economics', 'Read, present and replicate scholarly research published in peer-reviewed journals covering a variety of topics in economics. Receive guidance as to research methodology, composing a research paper and professional presentation. Attendance at departmental research seminars required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ECON 598', 'Thesis Research', 'Selection and approval of topic; outline; methodology; literature survey; data collection and analysis; presentation of results. Award of the grade is contingent upon the completion and acceptance of the thesis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ECON 599', 'Independent Graduate Research', 'Directed advanced independent inquiry. May not be repeated for credit. Not open to students on academic notice. Requires consent of instructor, Department Chair, and the Graduate Studies Committee.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 505A', 'P-12 Instructional Leadership and Assessment A', 'Approaches for advocating, nurturing and sustaining a school culture and instructional program conducive to student learning and professional growth.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 505B', 'Instructional Leadership in Higher Education', 'Instructional leadership in higher educational settings and the role of the student development educator in advocating, nurturing and sustaining a culture that supports student learning and development.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 510', 'Instructional Leadership and Assessment B', 'Use data and inquiry methods to assess students’ learning and instructional practices. Apply data analysis to determine interventions and assess impact.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 520', 'History and Function of Community Colleges', 'Overview of American and California community colleges, including history, administration, and contemporary issues such as student development and learning outcomes, student diversity, access and equity.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 521', 'History and Philosophy of Higher Education', 'Evolution of U.S. higher education, considering the diversity of the system, internal and external influences, and the evolution and development of student affairs and student learners.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 522', 'College Student Characteristics and Cultures', 'Students in postsecondary education in the United States. Major demographic groups (race, class, ethnicity, age, ability, sexual orientation, gender, etc.) and their experiences with access, equity, campus cultures and retention at two- and four-year institutions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 523', 'Student Learning and Development', 'Student development theory in college, considering traditional and non-traditional students and learning outcomes. Theoretical assumptions and the practical application of theory to diverse student learners and the role of theory in student affairs practice.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 524', 'Diversity Access and Equity', 'Diversity, access, equity, multiculturalism, pluralism as concepts in education. Understanding of these concepts and their applications to student affairs/higher education from a historical lens.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 563', 'Human Resource Administration', 'Importance and dimensions of human resource administration and the need to attract, retain, develop and motivate school personnel in ways that enhance learning and professional development; leading to positive and productive school settings. Collective bargaining and employee evaluation in public schools.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 564', 'School Law and Regulatory Process', 'Federal, state and local educational laws, regulations and other policies that govern schools and the requirements that administrators act in accordance with these laws and regulations in ways that are ethically and legally defensible.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 565', 'School Finance', 'Effectively managing fiscal resources and business services. Sources of income to public schools: federal, state, local and private (including grants and foundations). Review sound budgetary and business procedures for schools.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 566', 'Community Engagement for School Leaders', 'Role of the school leader in engaging community and family stakeholders to transform schools and communities. Identifying and incorporating community and familial needs/resources in the vision of the school. Leadership, reflective practice, human relations, school leader’s role in community outreach.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 568', 'Higher Ed Fieldwork', 'At least 200 hours at two different sites demonstrating competence in applying theory to practice, assessment, evaluation, and program design and implementation, supervised by an approved educational leader who provides feedback for learning and growth as a student affairs educator/leader. May be repeated for a maximum of 6 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 595', 'Professional Seminar in Higher Education', 'Application of technology for effective communication, verbal and written, and individual and group interactions on-line and face to face. Applying computers to work in student affairs/higher education settings.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 596', 'Directed Study in Educational Research', 'Research under direction of a faculty member or principal investigator. Requires completing specified “deliverables” or outcomes. Develop intended learning outcomes and describe the methods for attaining each within the context of independent study, providing specific deliverables. Requires consent of program director or graduate advisor.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDAD 599', 'Independent Graduate Research (1-3)', 'Independent inquiry for qualified students. May be repeated for a maximum of 6 units. Requires consent of instructor.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 600', 'Organizational Theory and Challenges for Instructional Leadership', 'Organizational theories and their application to the role of educational leaders. Theories from leadership and management literatures, which predicate the conceptual development of the role of educational leadership. Implications of these theories for effective performance as educational leaders.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 601', 'Methods of Research: Quantitatively Based Methods', 'Introduction to the conceptual and methodological bases of quantitative analysis in educational leadership. Issues of research design, measurement and statistical analysis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 602', 'Methods of Research: Qualitatively Based Methods', 'Developing knowledge, dispositions and critical thinking skills necessary for conducting field research. Applying these skills to design and implement applied research projects that create knowledge for solving dilemmas related to educational leadership.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 603', 'Research Elective: Specialization in Qualitatively Based Tools', 'Identifying, conducting, analyzing and interpreting field research in education toward the purpose of improving education.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 604', 'Applications of Research: Forecasting and Planning', 'Theories and methods that accurately forecast the impact of social, economic, political, cultural, academic and demographic trends as they affect educational institutions. How these indicators can be used to engage effective planning.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 605', 'Applications of Research: Collection and Analysis of Assessment Data', 'Methods of system-level data collection and analysis of outcomes of education. Complexity and efficacy of using various types of data for making judgments at the system level about the effectiveness of instruction across classrooms and schools.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 606', 'Specialization in Quantitatively Based Tools', 'Statistics, exploratory data analysis, sampling, survey and experimental design; and interview and questionnaire design in the context of using research in planning, change management, policy analysis and program management.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 611', 'Inquiry 1', 'Methods of conducting research using a mixed-methods orientation. Acquiring knowledge, dispositions and critical thinking skills necessary to understand educational research and descriptive statistical applications. Philosophical and epistemological foundations of educational research.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 612', 'Inquiry II', 'Practical, philosophical and ethical considerations for data collection and analysis using quantitative, qualitative and mixed methods research designs. Significant quantitative and qualitative lab components utilizing quantitative and qualitative software.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 613', 'Inquiry III', 'Applying the philosophical and epistemological foundations of educational research to the design of a formal research project. Draws upon educational research and the methods using a mixed-methods orientation that includes quantitative and qualitative perspectives.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 620', 'Ethical and Legal Dimensions of Instructional Leadership', 'Concepts of ethics (e.g., self-interest, free will, social responsibility, duty) as the basis for legal standards (protection of individual rights, fair treatment, equality of opportunity, duty of care, public trust) through the study of education case law.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 621A', 'Leadership of Curricular and Instructional Practices', 'Current issues in curriculum design and implementation. Forces affecting the curriculum; curriculum continuity and articulation; content trends in the subject areas; appropriate curriculum for students from diverse backgrounds; curriculum censorship; and effective instructional leadership for school curriculum improvement.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 621B', 'Higher Education, Community College Systems, Structures, and Cultures', 'Higher education, from Egyptian Era to the diversity of current postsecondary instructions, philosophies and orientations. Organizational development and structures of higher educational systems and the impact of faculty, student and administrative cultures on higher education leaders.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 622A', 'Human Dimensions of Educational Change', 'Issues associated with change. Change as a sociopolitical process; sources and purpose of change; coping with multiple reform efforts; decision-making processes; reform implementation; problems of resistance to change in curriculum and instruction; and change as a continuous process.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 622B', 'Resource Management and Development', 'Practical applications and skills for college resource management in personnel, structures, facilities, technologies, finances, programs and services. Optimizing resources through management and creative leadership that encourage and support collaboration across divisions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 624A', 'Social Contexts of Education Politics, Policy and Governance', 'Topics relevant to instructional leadership and educational policy cycles. Policy-making process, role of values and interest groups, policy analysis, equality of educational opportunity, how policy efforts are reshaped and systemic reform. Policy issues, including high-stakes testing, curricular mandates and accountability.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 624B', 'Student Learning and Development', 'Student development and learning theories based on cognitive, psychosocial, typology and person-environment perspectives. Role of faculty and others in the collaborative development and implementation of responsive curricula and co-curricula at two- and four-year institutions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 626A', 'Transforming Teaching and Education through Resource Optimization', 'Perspectives on how optimizing resources can transform education through a multidisciplinary approach. Identifying economic, social and political resources; innovative ways to develop new streams of resources and policies and procedures that increase highly productive ways to use resources.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 626B', 'Integrative Seminar in Higher Education/Community College Issues', 'Current issues in higher education/community colleges from local to global perspectives, reinforcing a multilens view of higher educational studies. Opportunities for interactions with experts and to engage in questions/challenges and data-driven solution-focused discussions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 627', 'Epistemology, History and Structure of Contemporary Education', 'Epistemological and historical trends that have shaped the structure of contemporary education. Influence of major schools of thought, including rationalism, empiricism, pragmatism, behaviorism and constructivism; and how modern education structure, curriculum and pedagogy have been influenced by these various perspectives.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 630', 'Leadership for Change and Collaboration', 'Research on leadership and organizational change in higher education, multicultural organizational development, forecasting, planning and change analyzed. Community relations needed to develop programs responsive to workforce and community needs. Educational codes, laws, policies and practices impacting higher education.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 670A', 'Linking Research to Problems of Practice', 'Identifying complex problems of educational practice appropriate for doctoral research. Small-group instruction provides coaching that enables students to initiate the research cycle by linking research to problems of practices.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 670B', 'Connecting Research Questions to Scholarship in the Discipline', 'Assists in writing a critical review of the professional literature pertaining to the identified research problem.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 670C', 'Written Qualifying Examination', 'Preparation for the EDD Qualifying Examination, a prerequisite for advancing to candidacy in the doctoral program.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 670D', 'Refining Research Questions', 'Further refine research questions or hypotheses, select the research method to investigate the research question, design a research study that specifies methods to be implemented for data collection and analysis.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 670E', 'Proposal Defense Preparation', 'Assists in writing a defensible dissertation research proposal reflecting high quality scholarship.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 670F', 'IRB Approval and Proposal Defense', 'Obtain CSUF IRB approval and submit a revised and completed dissertation research proposal in preparation for the dissertation proposal defense.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 698', 'Dissertation Research', 'Individual research on a dissertation. Conferences with a faculty adviser and committee members, culminating in the publication of a dissertation. May be repeated for a maximum of 12 units.', 6, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDD 699', 'Independent Study (1-6)', 'Independent doctoral level inquiry for qualified students.', 1, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 203', 'Electric Circuits', 'Units; Ohm’s and Kirchhoff’s laws; mesh and nodal analysis, superposition; Thevenin and Norton theorems; RL and RC transients; phasors and steady state sinusoidal analysis; response as a function of frequency; current, voltage and power relationships; polyphase circuits.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 203L', 'Electric Circuits Laboratory', 'Simple resistive RL and RC circuits, electrical measurement techniques, verification of basic circuit laws through hard-wired breadboarding and CAD circuit simulation. (3 hours laboratory) Pre- or', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 215', 'Solving Engineering Problems Using MATLAB', 'Formulating, solving, verifying and reporting engineering problems such as control, signal processing and communication systems and engineering, math and physics problems such as engineering/scientific computations and operations research using the MATLAB/SIMULINK program. (3 hours laboratory)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 245', 'Computer Logic and Architecture', 'Logic design and organization of the major components of a computer, analysis and synthesis of combinational and sequential logics, analysis of the arithmetic, memory control and I/O units, concepts in computer control.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 245L', 'Computer Logic and Architecture Lab', 'Computer-Aided Design (CAD) of digital logic circuits, including decoders, multiplexes, adders and subtracters, counters, shift registers and Arithmetic Logic Unit (ALU) of a computer. After verifying the CAD design through simulation, the circuits are built on a protoboard. (3 hours laboratory) Pre- or', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 303', 'Electronics', 'Characteristics and elementary applications of semiconductor diodes, field-effect transistors and bipolar-junction transistors and operational amplifiers; mid-frequency small-signal analysis and design of transistors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 303L', 'Electronics Laboratory', 'Semiconductor diodes, transistors and elementary electronic circuits through hard-wired breadboarding, CAD electronic simulation and analysis. (3 hours laboratory)', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 309', 'Network Analysis', 'Performance of RLC circuits; complex frequency and the s-plane; frequency response and resonance; network topology; two-port network characterization; classical filter theory.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 310', 'Electronic Circuits', 'Continuation of EGEC 303; analyzing and designing multistage and feedback amplifiers; frequency characteristics of amplifiers, frequency characteristics and stability of feedback amplifiers, differential amplifiers, design of IC circuit biasing, operational amplifiers and their applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 310L', 'Electronic Circuits Lab', 'Computer-Aided Design (CAD) of electronic circuits, including multi-stage feedback amplifiers; linear and integrated circuits; ADC and DAC and wireless design projects. After verifying the CAD design through simulation, the circuits are built on a protoboard. (3 hours laboratory)', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 311', 'Field Theory and Transmission Lines', 'Introduction to waves and phasors; analysis and design of transmission lines; electrostatics and magnetostatics; boundary value problems; Maxwell equations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 313', 'Introduction to Electromechanics', 'Electromagnetic fields and circuits; transformers, saturation effects. Simple electro-mechanical systems. Circuit models, terminal characteristics and applications of DC and AC machines.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 313L', 'Power Laboratory', 'Experiments in electromagnetic fields and circuits, transformers and electromechanical systems such as AC and DC machines (3 hours laboratory) Prerequisite EGEC 303L. Pre- or', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 323', 'Engineering Probability and Statistics', 'Set theory: axiomatic foundation of probability; random variables; probability distribution and density functions; joint, conditional and marginal distributions; expected values; distribution of functions of random variables; central limit theorem; estimation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 404', 'Introduction to Microprocessors and Microcomputers', 'Hardware and software concepts in microprocessors, processor family chips, system architecture, CPU, input/output devices, interrupts and DMA, memory (ROM, RAM), electrical and timing characteristics, assembly language programming.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 406', 'Design Applications with Microcontroller and FPGA', 'Digital system application design using microcontrollers, FPGAs and CPLDs including programming hardware interfacing, A/D conversion, CLB, logic arrays, interconnections, testing and simulations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 409', 'Introduction to Linear Systems', 'Development of time and frequency domain models for physical systems. Linearization process and representation with block diagrams and signal flow graphs; discrete-time systems and digital signals including use of Z-transforms; stability theory of continuous and discrete time systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 410', 'Electro-Optical Systems', 'Introduction to electro-optics; optical radiation characteristics and sources; geometrical and physical optics; lasers and electro-optical modulation; quantum and thermal optical radiation detectors; detector performance analysis; electro-optical systems modeling and analysis; application examples.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 416', 'Feedback Control Systems', 'Feedback control system characteristics; stability in the frequency and time domains; analysis and design of continuous-time systems using root-locus, Bode and Nyquist plots, Nichols chart and applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 420', 'Introduction to Digital Filtering', 'Discrete-time signals and systems; solution of difference equations; Fourier transform for a sequence; Z-transform; discrete Fourier transform; FIR and IIR realizations; design of digital filters.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 435', 'Microwave Engineering', 'Essential fundamentals for radio frequency, wireless and microwave engineering. Wave propagation in cables, wave-guides and free space; impedance matching, standing wave ratios, impedance and scattering parameters.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 442', 'Electronic Circuits', 'Power amplifiers and tuned amplifiers; RF amplifiers; modulation and detection circuits; oscillators; and operational amplifier applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 443', 'Electronic Communication Systems', 'Principles of amplitude, angular and pulse modulation, representative communication systems, the effects of noise on system performance.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 445', 'Digital Electronics', 'RC circuits, attenuators, compensation and scope probe. Logic circuits: DTL, TTL, STTL, LSTTL and ECL. Fanout, noise-immunity, switching speed, power consumption, input-output characteristics. Design and analysis of MOS logic circuits; PMOS, NMOS and CMOS gates, flip-flops, shift registers and memory circuits.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 448', 'Digital Systems Design with FPGA', 'Basic concepts and characteristics of digital systems, traditional logic design, LSI/VLSI logic design with VHDL, combinational and sequential logic, and their applications; timing and control, race conditions and noise, microcomputers, computer-aided programming, development systems, microcomputer system hardware design, input/output devices.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 455', 'Microelectronics and Nano Devices', 'Quantum mechanical principles, crystal structure, energy brand, carrier transport, carrier generation and recombination, p-n junction, bipolar transistor, MOSFET, MEFET and related devices, basic microwave and optoelectronic technology, crystal growth and fabrication, introduction to nano structure, nano devices and technology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 460', 'Introduction to Cellular Mobile Communications Systems', 'Introduction to wireless mobile telecommunications, description and analysis of cellular radio systems, co-channel interference reduction, channel capacity and digital cellular systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 465', 'Introduction to VLSI Design', 'Computer-aided design of VLSI circuits. MOS device structure, design rules, layout examples and CMOS standard cells. Speed power trade off, scaling, device and circuit simulation. VLSI design software tools. Routing method system design, Design Project. Chip fabrication through MOSIS service, testing.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 469', 'Antennas for Wireless Communications', 'Aspects of antenna theory and design; radiation from dipoles, loops, apertures, microstrip antennas and antenna arrays.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 480', 'Optical Engineering and Communications', 'Optics review, lightwave fundamentals, integrated optic waveguides, first design of fiber optic system, analog and digital modulation, digital fiber optic system design, baseband coding, digital video transmission, optical emitters and receivers, coherent optical communication, measurements in fiber optic telecommunication.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 483', 'Introduction to Global Positioning Systems (GPS)', 'Description of Global Positioning Systems (GPS) and Differential Global Positioning Systems (DGPS), GPS navigation, errors. Satellite signals and co-ordinate transform math. Modeling for position and velocity. Application to navigation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 483L', 'Global Positioning System Lab', 'Novatel, Magelon, Ahstek, Collins and Tribel receivers. Computing GPS and GEO stationary satellite positions from ephemeris data available on almanac. Calculate and compensate errors, such as selective availability, ionospheric, tropospheric and satellite ad receiver, in the data.(1 hour lecture, 3 hours laboratory)', 2, 2, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 485', 'Electrical Engineering Design Projects Laboratory', 'Practical aspects of design and project construction. Instructor-approved design project in electrical engineering, inter-disciplinary projects. Using CAD program for schematic capture and simulation. Constructing final hardware according to the design specification. Performance evaluation and demonstration of project. (1 hour lecture, 6 hours laboratory).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 497', 'Senior Project (1-3)', 'Directed independent design project. May be taken for credit for a maximum of six units. Requires consent of adviser and instructor.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 499', 'Independent Study (1-3)', 'Specialized topics in engineering selected in consultation with and completed under the supervision of the instructor. May be repeated for a maximum of 6 units. Requires approval of study plan by adviser.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 503', 'Information Theory and Coding', 'Information measures, probabilistic studies of the transmission and encoding of information, Shannon’s fundamental theorems and coding for noisy channels.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 504A', 'Linear Network Synthesis', 'Synthesis of passive element driving-point and transfer-functions with emphasis on RC networks. Basic operational amplifier RC circuits and their performance limitations, introduction to second-order RC active filters. Parameter sensitivity analysis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 510', 'Optics and Electromagnetics in Communications', 'Plane-wave propagation and reflection from multiple layers; two- and three-dimensional boundary value problems; waveguides and resonant cavities; radiation from apertures and antennas; electromagnetic properties of materials, gases and plasmas; significant coverage of engineering applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 518', 'Digital Signal Processing I', 'Discrete Fourier transform; fast Fourier transform; Chirp Z-transform; discrete time random signals; floating-point arithmetic; quantization; finite word length effect in digital filters; spectral analysis and power spectrum estimation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 522', 'Spread Spectrum Communications', 'Spread Spectrum (SS) Systems. Performance analysis of coherent digital signaling schemes. Synchronization. Direct sequence, frequency hopping, time hopping and Hybrid Spread Spectrum Modulations. Binary shift register sequences. Code tracking loops. SS systems performance in a jamming environment, with forward error correction.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 523A', 'VLSI and Nano Technology and Devices', 'Silicon crystal, PN junction physics, oxide and interface physics and wafer fabrication technology; oxidation, diffusion, ion-implantation, epitaxy, photolithography and thin films process. Layout design principle for integrated circuits. Nano-electronic devices and technology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 523B', 'CMOS VLSI Design', 'Surface physics of MOS system and MOS device physics. Short channel effect; hot carrier effect, subthreshold conduction. CMOS fabrication process. Layout design rules. Scaling design and analysis of CMOS circuits. Standard cell method. CAD design and SPICE simulation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 526', 'Digital Control Systems', 'Analysis, design and implementation of digital control systems; Z-transform methods; frequency domain and state-space approach for discrete-time systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 529', 'Principles of Neural Systems', 'Principles of neural systems and their hardware implementation. Basic properties, discrete and continuous bidirectional associative memories. Temporal associative memories. Neural nets classifiers, perceptrons, supervised and unsupervised learning. Forward and backward propagation. Electrical models of neural networks using op-amp., analog VLSI.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 531', 'Digital Communication and Phase Locked Loop', 'Theory of digital communications. Baseband modulation and demodulation/detection. Bandpass modulation/demodulation. Theory of noise and linear system. FM feedback principles. Theory and design of phase locked loops and their application in communication and control.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 537', 'Satellite Communications', 'Satellite systems, link analysis, propagation effects, SNR/CNR calculations, modulation schemes, TDMA, FDMA, and CDMA techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 557', 'Microprogramming and Embedded Microprocessors', 'Introduction to microprogramming concepts and applications to the control unit of a computer, microprogrammable control, arithmetic-logic unit, implementation of an embedded process on FPGA and interfacing with external memories.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 558B', 'Microprocessors and Systems Applications II', 'Advanced microprocessor architecture and their applications to microcomputer networking; RISC VS CISC architectures, communication protocol, distributed-operating system, and local area networks.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 559', 'Introduction to Robotics', 'Science of robotics from an electrical engineering standpoint, including modeling, task planning, control, sensing and robot intelligence.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 580', 'Analysis of Random Signals', 'Random processes pertinent to communications, controls and other physical applications, Markov sequences and processes, the orthogonality principle.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 581', 'Theory of Linear Systems', 'State space analysis, linear spaces, stability of systems; numerical methods of linear systems analysis and design.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 582', 'Linear Estimation Theory', 'Mathematical models of continuous-time and discrete-time stochastic processes; the Kalman filter, smoothing and suboptimal filtering computational studies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 598', 'Thesis (1-6)', 'Unless approved by the department chair, EGEC 598 cannot be taken if EGEC 597 has been completed. May be repeated for a maximum of 6 units. Requires consent of adviser. Classified graduate students only.', 1, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGEC 599', 'Independent Graduate Research (1-3)', 'Unless approved by department chair, EGEC 599 cannot be taken if EGEC 597 has been completed. May be repeated for a maximum of six units. Requires consent of adviser.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 110', 'The Teaching Experience: Exploration', 'Exploring one’s self in relation to other people in the schools, and an encounter with the teaching experience through fieldwork. Accompanying seminar helps extend observations and explore relevant issues. (2 hours fieldwork, 2 hours seminar). (EDSC 110, EDEL 110, SCED 110 and SPED 110 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 315', 'Introduction to Elementary Classroom Teaching', 'Exploratory course with field assignments for those considering careers in schools, grades TK-8. Students taking this course to meet the prerequisite for either the Multiple Subject or the Special Education Credential Program must earn a “C-” or better. Fieldwork required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 325', 'Cultural Pluralism in Elementary Schools', 'Culture and cultural pluralism in grades TK-8. Examine one¿s own beliefs and values; classroom practices and materials that promote equity; strategies for learning about students; history/traditions of cultural groups; and assess multicultural education programs. Students taking this course to meet the prerequisite for either the Multiple Subject or the Special Education Credential Program must earn a “C-” or better.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 429', 'Integrated Curriculum and Instruction in the Elementary School', 'Additional study of elementary curriculum emphasizing language arts, integrated instruction across the curriculum and assessing learning outcomes. Must be taken for a letter grade if enrolled in the credential program. A “B” or better is required to pass the course.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 430', 'Foundations in Elementary School Teaching', 'Curriculum of the elementary school, instructional planning, principles of effective teaching, generic instructional strategies, classroom management and legal issues in education. Must be taken for a letter grade if enrolled in the credential program. A “B” or better is required to pass the course.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 433', 'Language Arts and Reading Instruction in the Public Schools', 'Overview of principles of reading instruction, elements of the language arts program including literature-based reading, content area reading, the role of phonics, emergent literacy and diagnosis of reading problems. Must be taken Credit/No Credit. A “B” (3.0) or better is required to receive a grade of credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 434', 'Methods and Inquiry for Teaching English Learners', 'Theoretical foundations, legal issues and school programs for the education of English learners. Assessment, materials, methods and strategies for English language development and learning across the curriculum for elementary school English learners. Must be taken Credit/No Credit. A “B” (3.0) or better is required to receive a grade of Credit.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 435', 'Mathematics Curriculum and Instruction in Elementary School Teaching', 'Instructional materials, learning styles, inquiry, concept learning, problem solving, various instructional strategies applied to teaching of mathematics. Must be taken Credit/No Credit. A “B” (3.0) or better is required to receive a grade of credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 436', 'Science Curriculum and Instruction in Elementary School Teaching', 'Instructional materials, learning styles, inquiry, concept learning, problem solving, various instructional strategies applied to the teaching of science. Must be taken Credit/No Credit. A “B” (3.0) or better is required to receive a grade of credit.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 437', 'Social Studies Curriculum and Instruction in Elementary School Teaching', 'Instructional materials, learning styles, inquiry, concept learning, problem solving, various instructional strategies applied to teaching social studies. Credit/No Credit only. A “B” (3.0) or better is required to receive a grade of credit.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 438', 'Supervised Fieldwork in Elementary Teacher Education (1-2)', 'Students serve as teacher participants in an assigned elementary school classroom. Credit/No Credit only. A “B” or better is required to receive a grade of credit. May be repeated for a maximum of 2 units.', 1, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 439', 'Student Teaching in the Elementary School (4-15)', 'Participate in a regular elementary school teaching program for the full school day. Credit/ No Credit only. A “B” (3.0) or better is required to receive a grade of credit. May be repeated for a maximum of 15 units.', 4, 15, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 446', 'Methods and Inquiry for Bilingual Teachers', 'Prepares bilingual teacher candidates for teaching Spanish-speaking students. Program models for bilingual instruction, methods for teaching reading and content areas in bilingual settings, materials and assessment. Conducted in Spanish and English; 20 hours of fieldwork required. (EDEL 446 and EDSC 446 are the same course)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 450', 'Visual and Performing Arts Methods: Art, Dance, Drama and Music', 'Instructional materials, learning styles, integration and strategies as they apply to teaching the arts in elementary education. Credit/No Credit only. A “B” (3.0) or better is required to receive a grade of credit.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 451', 'Community, School, and Classroom Issues', 'Current issues of elementary school teaching, including classroom management, parent-teacher communication, school law and child abuse reporting. Credit/No Credit only. A “B” (3.0) or better is required to receive a grade of credit.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 452', 'P.E., Health and Mainstreaming Education', 'Mainstreaming students with special needs, health education and physical education in elementary school settings. Credit/No Credit only. A “B” (3.0) or better is required to receive a grade of credit.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 453', 'Teaching Performance Assessment Seminar', 'Preparation for completing the California Teaching Performance Assessment (CalTPA) Cycle 2, which is required for a Preliminary Multiple Subject Teaching Credential. A “B” (3.0) or better is required to receive credit. May be repeated for a maximum of 2 units. Credit/No Credit only. Requires admission to student teaching.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 453B', 'Teaching Performance Assessment Support: Assessing Learning and Culminating Teaching Experience', 'TPA support within social studies or science for the Multiple Subject Credential program. Credit/No Credit only. A “B” (3.0) or better is required to receive a grade of credit. May be taken for credit for a maximum of two units. (EDEL 453B and SPED 453B are the same course.)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 499', 'Independent Study (1-3)', 'Individual investigation under supervision of a faculty member. Only students of demonstrated capability and maturity will be approved. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 500', 'Bilingual Multicultural Curriculum', 'Culture and school curriculum, forces operating on the curriculum, the participants involved in curriculum building, modification of the curriculum to reflect multicultural contexts, and pedagogy and pluralism.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 502E', 'Pedagogy, Assessment and Support for New Teachers: Semester 1', 'Formative assessment and professional development for new teachers via utilization of state-approved formative assessment system. Inquiry into teaching effectiveness including analyzing teaching and learning context and assessment. Requires participation in the Fullerton Teacher Induction Program. (EDEL 502E, EDSC 502E, SPED 502E are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 511', 'Survey of Educational Research', 'Descriptive statistics and statistical inferences in educational research. Representative research papers. Principles of research design. Prepare papers using research findings.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 512', 'Level Two Technology Proficiencies for Teachers in TK-8 Schools', 'Theoretical basis and strategies for improving teaching TK-8 students using multimedia and other technologies. Requires teaching credential.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 515', 'Technology and Problem Solving in Schools', 'Software and web-based applications that promote problem-solving in schools. Research and discuss issues, implications of and implementation strategies for using technology to enhance students’ problem-solving skills.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 518A', 'Issues in the Instructional Design of Software for use in Schools', 'Issues related to the instructional design of courseware designed specifically for classroom students. Learning principles, learner characteristics, instructional strategies, screen design, response analysis, feedback and interactivity.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 518B', 'Multimedia Development and Instruction in the Classroom', 'Application and instruction of computer-based instructional design principles in developing classroom software and multimedia projects. Planning and assessment, design principles and developing tools.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 522', 'Web Design for Instruction in Schools', 'Design, develop and implement web pages and sites for instructional purposes. Issues surrounding using the World Wide Web for instruction. Fieldwork required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 523', 'Distance Education Issues and Trends in Schools', 'Issues and trends in distance education for teaching and learning in schools. Draws on research in K-12, higher education and corporate domains.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 528', 'Reading/Language Arts in the Early Childhood Curriculum', 'Significant research, curriculum developments and materials, and current instructional strategies for promoting emergent literacy in children.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 529', 'Graduate Studies: Learning Theory for Classroom Use', 'Major theoretical positions in planning and interpreting classroom practices. Educational research findings, implications for curriculum development and teaching practices.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 530', 'Graduate Studies in Elementary Education: Second Languages', 'Significant research, curriculum developments and materials, and criteria for planning and improving second language programs, including those for English as a second language.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 531', 'Graduate Studies in Elementary Education: Integrated Language Arts', 'Significant research, trends and problems in teaching the fundamental skills of communication; curriculum development and materials, and criteria for planning and improving integrated language arts programs.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 532', 'Graduate Studies in Elementary Education: Mathematics', 'Significant research, curricular developments and materials, criteria for planning and improving mathematics programs and instruction.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 533', 'Graduate Studies in Elementary Education: Science', 'Research and materials in science education and criteria for planning and improving science programs and instruction.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 534', 'Graduate Studies in Elementary Education: Social Studies', 'Research developments and materials, criteria for planning and improving social studies programs, and current techniques of teaching.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 536', 'Curriculum Theory and Development', 'School curriculum, including the forces operating on the curriculum and the participants involved in curriculum building. Process of curriculum building.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 538', 'Teaching and Learning in the Early Childhood Classroom', 'Applying significant research in the education of young children. Current instructional strategies and criteria for planning and improving programs in early childhood education.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 541', 'Culture and Education of Latino Students', 'Impact of historical, social, political and economic forces on educational experiences for Latino students in the U.S., in particular, those of Mexican origin. Immigration, migration, language and culture with respect to educational attainment. Requires consent of Bilingual Authorization Coordinator. (EDEL 541 and EDSC 541 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 542', 'Current Issues and Problems in Bilingual-Bicultural Education', 'Problems and issues in the development and implementation of bilingual-bicultural education.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 548', 'Social Studies, Science and Math in Early Childhood Education', 'Current curriculum standards and instructional options in social studies, science and mathematics in early childhood education. Content, process skills and literature connections.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 552', 'Family, Community and Professional Partnership', 'Value of educational partnerships between families, teachers and the community. Inquiry and the development of strategies to develop partnerships, address and overcome barriers, and sustain partnerships to enhance the education of children.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 590', 'Technology Professional Development in Schools', 'Planning, implementing and evaluating technology professional development in schools. Writing grants, acting as a change agent and serving as a technology leader in a school. Fieldwork required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 594', 'Culminating Project', 'Preparing, evaluating, developing and presenting curriculum research proposals culminating in a graduate project.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 597', 'Research Project (1-3)', 'Individual research on an empirical project, with conferences with the instructor, culminating in a project. May be repeated for a maximum of 3 units. Consent of instructor required.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 598', 'Thesis (1-3)', 'Individual research with conferences with the instructor, culminating in a thesis. May be repeated for a maximum of 3 units. Requires consent of instructor.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EDEL 599', 'Independent Graduate Research (1-3)', 'Independent inquiry. May be repeated for a maximum of 3 units. Requires one year of teaching experience.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 312', 'The Bible as Literature', 'Literary qualities of biblical literature and the influence of major themes upon Western literary traditions. (CPLT 312 and RLST 312 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 315', 'Classical Mythology in World Literature', 'Greek and Roman myths which have been of continuing significance in Western world literature.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 324', 'World Literature to 1650', 'Asian and Western literature from the beginning to 1650.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 325', 'World Literature from 1650', 'Asian and Western literature from 1650 to the present.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 345T', 'Trends and Movements in English Studies and Comparative Literature', 'Various trends and movements in literature, composition and rhetoric, cultural studies, creative writing, or linguistics through a variety of critical lenses. (ENGL 345T and CPLT 345T are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 355T', 'Images of Women in Literature', 'Images of women in genres such as autobiography, poetry, drama, novel. Individual sections may treat conventional literary periods or specific cultures. May be repeated with different topics for a maximum of 6 units. (ENGL 355T and CPLT 355T are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 380', 'Introduction to Asian Literature', 'Selected translations of Arabic, Persian, Indian, Chinese or Japanese literature. (CPLT 380 and ENGL 380 are the same course)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 381', 'African Literature', 'African literature written in the English language; the fiction, poetry and drama of the new nations. (ENGL 381 and CPLT 381 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 382T', 'Topics in Asian Literature', 'Specific topics will vary from semester to semester. May be repeated with different topics for a maximum of 6 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 450', 'Medieval Literature', 'Readings in modern English translation from the medieval literature of England and the continent from St. Augustine to Sir Thomas Malory. (ENGL 450 and CPLT 450 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 451', 'Literature of the Renaissance', 'The Renaissance as a literary movement, from Erasmus to Montaigne and Cervantes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 499', 'Independent Study (1-3)', 'May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 525T', 'Proseminar in Literature, Rhetoric, or Writing', 'Comprehensive reading course focusing on a key area in literature, rhetoric or writing. Major primary works. Students are strongly advised to take proseminars before enrolling in seminars. May be repeated with different topics for a maximum of 12 units. ( ENGL 525T and CPLT 525T are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CPLT 599', 'Independent Study (1-3)', 'Research projects in areas of specialization beyond regularly offered coursework. Oral and written reports. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 105', 'Introduction to Creative Writing', 'Exploratory creative writing with the opportunity to write in various genres. No credit toward the major or English minor.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 200', 'Literature and Popular Culture', 'For non-English majors who like to read. Uses subjects in popular culture to study fiction, drama and poetry; including non-conformity and rebellion in modern music, conspiracy theory, visual literacy and the influence of science. Carries no credit toward the major.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 206', 'Introduction to Language Structure and Language Use', 'Introduction to the nature, structure, development and use of English. How sounds are articulated and patterned in meaningful units (phonology); symbolic correspondence (phonics); rules of word formation (morphology); word history (etymology); and language use (pragmatics). (ENGL 206 and LING 206 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 211', 'British Literature to 1760', 'Major periods and movements, major authors and major forms through 1760.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 212', 'British Literature from 1760', 'Major periods and movements, major authors and major forms from 1760 through modern times.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 221', 'American Literature to 1865', 'Major writers, such as Hawthorne, Poe, Melville, Emerson, Thoreau, Whitman and Dickinson.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 222', 'American Literature from 1865', 'Major writers such as Twain, James, Crane, Hemingway, Faulkner, O’Neill, Frost and Eliot.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 300', 'Analysis of Literary Forms', 'Main literary forms-prose fiction, poetry and drama-are studied and analyzed. English majors should schedule this basic course as early as possible.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 301', 'Advanced College Writing', 'Writing expository prose for non-English majors. Precision in rhetoric and development of individual style by concentration on matters of diction, audience, emphasis and persuasion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 302', 'Advanced Composition and Rhetoric for English Teachers', 'Expository prose, journalistic prose and creative writing for prospective teachers of English. Meets the university upper-division writing requirement for English majors. Requirement for application to English teaching credential.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 303', 'The Structure of Modern English', 'Grammar of contemporary English. Modern English usage. Requirement for application to English Teaching Credential.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 305', 'The English Language in America', 'American English, its origins, regional and social dialects and role in American history and in such institutions as schools, corporations, government and media. Requirement for application to English Teaching Credential. (ENGL 305 and LING 305 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 306', 'Intermediate Creative Writing', 'Creative writing beyond the introductory level. Poetry, the short story and/or the one-act play.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 307', 'Advanced College Writing for English Studies', 'Interpretive frameworks of communities within the discipline of English Studies (literary studies, creative writing, English education, composition, cultural criticism). Uses discursive conventions of these communities to produce formal and informal texts of various genres. Requires completion of all lower-division writing requirements.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 315', 'Chaucer', 'Canterbury Tales and Chaucer’s language. Vocabulary, pronunciation, grammar and syntax of the East Midland dialect of Middle English.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 316', 'Shakespeare', 'Study of the major plays.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 317', 'Milton', 'Poetry and prose in the light of Milton’s intellectual development.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 324', 'Introduction to African American Literature', 'Literary contributions by major black American authors. Contemporary black writers and the recurring themes of protest and quest for identity. (AFAM 324 and ENGL 324 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 326', 'The American Frontier in Literature', 'Thematic study of American literature as it reflects the changing frontier experience and establishes national myths and symbols.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 327', 'Asian American Literature', 'Introduces early literary expressions of the Asian American experience. Readings include poetry, short stories, novels and autobiographies. Fundamental understanding of Asian American literary history and awareness of the cultural diversity in America. (ASAM 327 and ENGL 327 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 328', 'Indigenous Literatures in English', 'The prose and poetry of the North American Indian tribes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 331', 'Shakespeare on Film', 'Analyze representative Shakespeare plays; view and analyze film versions of each play. Use literary and film terminology to write critical responses to drama and film, develop storyboards and conceptualize a Shakespeare play adaptation “pitch” with set, costume design, marketing strategy. (ENGL 331 and THTR 331 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 341', 'Children’s Literature', 'World literature written primarily for children, including material from the oral tradition, realistic fiction, fantasy and poetry.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 345T', 'Trends and Movements in English Studies and Comparative Literature', 'Various trends and movements in literature, composition and rhetoric, cultural studies, creative writing, or linguistics through a variety of critical lenses. (ENGL 345T and CPLT 345T are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 355T', 'Images of Women in Literature', 'Images of women in genres such as autobiography, poetry, drama, novel. Individual sections may treat conventional literary periods or specific cultures. May be repeated with different topics for a maximum of 6 units. (ENGL 355T and CPLT 355T are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 360', 'Technical Writing', 'Advanced composition stressing professional rhetorical situations, genres and styles. Professional writing, designing and editing, with attention to outlines and abstracts, description, process explanation, instructions and fundamentals of reports, feasibility studies, proposals, internal memos and letters.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 365', 'Legal Writing', 'Advanced composition stressing logic, reasoning and legal analysis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 370', 'Horror Fiction', 'Horror/occult fiction (or “dark fantasy”) from Mary Shelley to the present, including such writers as E.A. Poe, J.S. LeFanu, Bram Stoker, H.P. Lovecraft, Fritz Leiber and Stephen King.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 371', 'Fantasy Fiction', 'Fantasy in literature from Ariosto to Brautigan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 372', 'Crime Fiction', 'Crime fiction from Edgar Allan Poe to the present, including Sayers, Christie, Chandler, Hammett and Ross MacDonald.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 373', 'Science Fiction', 'Science fiction as a literary genre, including future-science fiction, the utopian novel, the superman/woman novel and short stories.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 381', 'African Literature', 'African literature written in the English language; the fiction, poetry and drama of the new nations. (ENGL 381 and CPLT 381 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 402', 'Theories of Response to Written Composition', 'Theories and practices in tutoring writing. Prepares students to work with writers from diverse backgrounds and disciplines. May be taken for letter grade or Credit/No credit.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 402S', 'Tutor Supervision', 'May be taken for letter grade or Credit/No credit. Pre- or', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 404T', 'Advanced Creative Writing', 'Instruction and practice in a workshop setting for students with some experience in creative writing; emphasizes writing for professional markets. Consult the class schedule to determine section’s emphasis. May be repeated once with different topic. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 416', 'Studies in Shakespeare', 'Problems of dramatic structure and artistic meanings. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 423', 'Early American Literature', 'Literature of colonial and revolutionary America, including the Puritans, 18th-century deism and rationalism, and the literary antecedents of American democratic thought.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 429', 'American Landscape in Literature', 'Literary perception of our environment, with special attention to what perceptions of the landscape reveal about human nature.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 434', 'Young Adult Literature', 'Evaluation, selection and interpretation of fiction, non-fiction, drama and poetry reflecting the interests of young people ages 12 to 17.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 442', 'Changing Words: History, Semantics and Translation', 'Etymology, related problems of lexicography and translation. Recent developments in theory of semantic change as related to cultural shifts. Emphasizes words, collocations, idioms. (LING 442 and ENGL 442 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 450', 'Medieval Literature', 'Readings in modern English translation from the medieval literature of England and the continent from St. Augustine to Sir Thomas Malory. (ENGL 450 and CPLT 450 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 451', 'Elizabethan and Jacobean Drama', 'Dramatic tradition in plays by such dramatists as Marlowe, Jonson, Webster, Beaumont and Fletcher.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 452', 'Elizabethan Poetry and Prose', 'Non-dramatic literature of the English Renaissance.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 453', '17th-Century Poetry and Prose', 'Non-dramatic literature of the period from 1603 to 1660 excluding Milton.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 455', 'Restoration and 18th-Century Literature', 'Major writers from prose, poetry and dramatic genres, such as Butler, Rochester, Dryden, Pepys, Swift, Addison and Steele, Pope, Boswell, Johnson, Sheridan, Wycherly and Gay, as well as selected minor writers.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 456', 'The British Novel through Jane Austen', 'British novel from its beginnings to the 19th century, including Defoe, Richardson, Fielding, Sterne and Austen.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 457', 'The Romantic Movement in English Literature', 'Writers such as Burns, Blake, Wordsworth, Coleridge, Byron, Shelley and Keats.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 458', 'Victorian Literature', 'Writers such as Carlyle, Tennyson, Browning, Arnold, Ruskin and Pater.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 459', 'The 19th-Century British Novel', 'Novelists such as the Brontes, Thackeray, Dickens, Eliot and Hardy.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 460', '19th-Century American Literature', 'Poetry, drama and prose in 19th-century America. Writers such as Emerson, Stowe, Dickinson and Thoreau.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 462', 'Modern British and American Fiction', 'Modern British and American novels from 1900 to 1960’s.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 463', 'Contemporary Fiction in English', 'Fiction (novels and short stories) since the 1960’s.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 464', 'Modern British and American Drama', 'British and American drama from 1900 to 1950.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 465', 'Contemporary Drama in English', 'Drama in English from the 1960’s to the present.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 466', 'Modern British and American Poetry', 'British and American poetry from 1900 to the 1960’s.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 467', 'Contemporary Poetry in English', 'Poetry in English from the 1960’s to the present.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 492', 'Modern Critical Theory', 'Major movements in 20th-century British and American criticism.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 498', 'English Internship (1-3)', 'Practical application of literature and language studies outside the university. Specified hours, limited enrollment, credit/no credit; no credit toward major. May be repeated for a maximum of 6 units. Requires consent of faculty supervisor.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 499', 'Independent Study (1-3)', 'Open to advanced students in English with consent of department chair. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 500', 'Introduction to Graduate Studies in English', 'Research techniques, analytical approaches and theories of literature. Basic orientation in graduate literary studies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 509T', 'Creative Writing Workshop', 'Intensive workshop in creative writing. Produce own work, write critiques of others’ works and discuss opportunities for publication. May focus on writing poetry or fiction or a mix of fiction and drama, depending on instructor’s expertise. Each topic may be repeated for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 515', 'Professional Editing and Journal Production', 'Firsthand experience editing and producing the English department’s literary journal, DASH. Solicit, review and edit creative writing submissions; design and create one journal issue.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 525T', 'Proseminar in Literature, Rhetoric, or Writing', 'Comprehensive reading course focusing on a key area in literature, rhetoric or writing. Major primary works. Students are strongly advised to take proseminars before enrolling in seminars. May be repeated with different topics for a maximum of 12 units. (ENGL 525T and CPLT 525T are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 571T', 'Graduate Seminar: Major Writers', 'As appropriate to the specialized research and publication of instructor; major figures such as Shakespeare, Dante, Cervantes, Goethe, Bronte, Twain, Joyce, Woolf and Morrison. May be repeated with different topics for a maximum of 9 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 572T', 'Graduate Seminar: Literary Genres', 'As appropriate to the specialized research and publication of instructor, major literary types such as the epic, novel, short story, lyric poetry, tragedy, comedy and historical drama. May be repeated once for credit with a different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 573T', 'Graduate Seminar: Cultural Periods', 'As appropriate to the specialized research and publication of instructor, the literature of a cultural period from Anglo-Saxon to modern times. May be repeated once for credit with a different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 574T', 'Graduate Seminar: Special Problems in Literature', 'As appropriate to the specialized research and publication of the instructor, special problems such as influences on literature, including philosophical, religious, scientific, geographic and other ecological viewpoints. May be repeated once for credit with a different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 579T', 'Graduate Seminar: Problems in Criticism', 'Historical development and schools of criticism. Individual offerings within this course number may deal with only one aspect of critical problems. May be repeated once for credit with a different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 590', 'Writing Theory and Practice for Teaching Associates', 'Theory and practice of the composing process for the beginning college teacher of expository writing. Required of all English Department Teaching Associates during their first semester of teaching. Requires admission to the English Department Teaching Associate Program.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 590S', 'Teaching Associate Supervision', 'Supervised teaching of developmental writing and freshman composition. No credit toward the M.A. in English.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 591T', 'Seminar: Topics in Rhetoric and Composition', 'As appropriate to the specialized research of instructor, special topics on rhetoric and composition, including historical and theoretical approaches. May be repeated once with different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 595', 'Project/Comprehensive Exam', 'Writing a master’s project in literature, rhetoric and composition, or creative writing. Or, prepare to take a comprehensive exam covering a predetermined area of focus. Requires prior departmental approval of project proposal or desired exam area of focus.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENGL 599', 'Independent Graduate Research (1-3)', 'Research projects in areas of specialization beyond regularly offered coursework. Oral and written reports. May be repeated once for credit.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENED 442', 'Teaching English in the Secondary School', 'Principles, methods and materials of teaching English in the secondary school. Students must earn a “B-” (2.7) or better to meet the requirements for earning a preliminary Single Subject credential.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENED 449E', 'First Semester Student Teaching', 'Student teaching in the secondary school during the first semester of the teacher preparation program. Candidate plans and teaches assigned lessons during the last third of the semester.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENED 449I', 'Second Semester Student Teaching', 'Student teaching in the secondary school during the second semester of the teacher preparation program. Candidate has the same instructional hours of responsibility as the master teacher.', 10, 10, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENED 449S', 'Seminar in Secondary Teaching', 'Teaching a single subject in secondary schools. Videotape analysis of teaching based on Teaching Performance Assessments. Credit/No Credit only. A “B” (3.0) or better is required to receive a grade of credit. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ENST 500', 'Environmental Issues and Approaches', 'Interdisciplinary approaches to environmental problems and research methods. Prepare seminars and papers on research design for potential thesis topics. Meets graduate writing requirement.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 340', 'Introduction to Investments', 'Institutional characteristics of securities markets, security valuation and trading methods, fundamental and technical analysis, selection and management of securities, role of the capital asset pricing model in investing, options and futures markets, portfolio analysis and mutual funds.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 342', 'Capital and Money Markets', 'Capital and money markets in the American and international economies; markets for new corporate and government issues; secondary markets; use of derivative securities for hedging; factors influencing yields and security prices.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 351', 'Real Estate Principles', 'Real estate principles, practices and investment decisions. Equity investment, finance, legal aspects, practices, principles, property development, real estate administration in the public sector, real estate market analysis and valuation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 360', 'Principles of Risk Management and Insurance', 'Analysis of the risk management process, introduction to property and liability insurance, employee benefits and financial planning. Overview of the insurance industry and insurance problems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 370', 'International Business Finance', 'Financing problems of the multinational business. International financial environment, taxation of foreign income, the cost of capital in international capital and money markets, problems of risk in foreign investments, and financial techniques for the operation of the multinational firm.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 371', 'Export-Import Financing', 'Institutional arrangements, methods and techniques used to finance international trade. Government and financial institution services. Risk-return aspects of international sales, insurance needs, the use of letters of credit, international factoring, accounts receivable insurance and other financing techniques. Review of required export-import documentation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 410', 'Theory and Practice of Personal Financial Planning', 'Developing, implementing and monitoring comprehensive personal financial plans. Risk management, investments, taxation, retirement and estate planning, professional practices', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 425', 'Commercial Bank and Financial Institution Management', 'Financial institution problem solutions. Major financial intermediaries and the decision-making problems they face. Regulation and its effect on management operations. Group problems and case studies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 432', 'Financial Forecasting and Budgeting', 'Forecasting in financial management; profit planning and control process; goals, technical procedures and effects of budgeting; mechanics of forecasting and budgeting, follow-up and control.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 433', 'Problems in Business Finance', 'Group problems and case studies relating to estimation of funds requirements, long-term financial planning, evaluation of cash flows, financing acquisitions and mergers, capital budgeting and cost of capital. Team-building, leadership and computer-assisted presentation skills.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 440', 'Business Valuation, Mergers and Acquisitions', 'Valuation, especially for mergers and acquisitions. Valuation methods and their application in mergers and acquisitions. May not receive credit for both FIN 440 and FIN 540.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 442', 'Portfolio Management for Stocks and Bonds', 'How to make evidence-based decisions for personal investing, or prepare for careers in financial planning or asset management. Topics include investment research methods, portfolio management techniques, financial statement analysis, cash flow forecasting and professional ethics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 454', 'Real Estate Economics', 'Factors and influences of urban growth and development. Economic factors and real estate supply and demand. Location theory and urban growth patterns. Public policy as a factor in real estate development. Analysis of real estate markets.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 495', 'Internship', 'A supervised experience where financial principles or methods are applied in a fieldwork setting. Mandatory class meetings for students to discuss their experience and integrate financial practice. Sections for other concentrations within the department will include application of relevant principles. May be repeated for a maximum of 6 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 499', 'Independent Study (1-3)', 'Open to undergraduate students desiring to pursue directed independent inquiry. May be repeated for a maximum of 6 units. Not open to students on academic notice. Requires consent of department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 517', 'Managerial Finance', 'Modern theory and practice of financial management. Net present value and the time value of money. Basic principles of risk and return. Capital budgeting and forecasting. Capital structure and dividend theory. Firm valuation from a value-based management and corporate governance perspective.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 523', 'Seminar in Corporate Financial Management', 'Analyze financial decision-making process through case studies and seminar presentations. Current financial theory and models. International applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 528', 'Seminar in Financial Economics', 'Valuation or corporate liabilities and other securities. Economic decision-making under uncertainty and asset pricing theories are analyzed rigorously. Other topics may include optimal capital structure, the market for corporate control, or macroeconomics aspects of finance. (FIN 528 and ECON 528 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 533', 'Seminar in Financial Administration', 'Optimal financing and asset administration; advanced techniques of capital budgeting; application of analytical methods to the administration of the finance function of the business firm.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 540', 'Seminar in Business Valuation, Mergers and Acquisitions', 'Issues and techniques related to business valuation and mergers and acquisitions. May not receive credit for both FIN 440 and FIN 540.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 541', 'Seminar in Investment Management', 'Problems of investment and portfolio management; concepts of risk evaluation and investment criteria; analysis of interest rate movements; investment valuation and timing; regulation and administrative problems of the industry. May not receive credit for both FIN 442 and FIN 541.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 543', 'Entrepreneurial Finance', 'Financing a new/small firm, including forecasting the firm’s investment needs, raising short-term funding and banking relationships, managing working capital, making fixed asset investments and managing risk.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 551', 'Seminar in Real Estate Investment', 'Problems of real estate investment; concepts of evaluation and investment criteria; analysis of real property values; real estate development and financing. Case studies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 560', 'Corporate Risk Management and Insurance Seminar', 'Managing risks that confront firms; how they are managed with diversification, capital structure, loss control, corporate governance, and how they are financed with commercial insurance contracts; analyzes market and instruments created to enable corporations to manage downside risks.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 562', 'Enterprise Risk Management (ERM)', 'ERM framework with the integration of pure, financial, strategic and operational risks. Discusses seven building blocks for developing an ERM program. Legal and regulatory environment, technical tools and future prediction on ERM.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 597', 'Project', 'Directed independent inquiry. Not open to students on academic probation. Requires consent of instructor, approval by Department Chair.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FIN 599', 'Independent Graduate Research (1-3)', 'May be repeated for a maximum of 6 units. Not open to students on academic notice. Requires consent of instructor, approval by department chair and associate dean.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 100', 'Global Geography', 'Introduction to world’s geographical regions. Cultural patterns and their evolution in diverse physical environments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 220', 'Introduction to Gender and Social Space', 'Introduction to the study of gender within the history of geography as a social science. Concepts such as the social construction of gender and space and how these concepts vary in different geographical regions. (GSS 220 and GEOG 220 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 281', 'Map Making with Geographic Information Systems', 'Principles and practice of effective map making using computerized geographic information systems technology. (2 hours lecture, 2 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 283', 'Introduction to Spatial Data', 'Introduction to the variety of evidence used in geographic analysis and the sources and techniques for acquiring geographic evidence.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 400A', 'Geographic Thought', 'Introduction to geographic thought through readings, discussion, and writing assignments. Physical, environmental, regional and spatial traditions in geography, and current themes in geographic research. Meets the upper-division writing requirement for geography majors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 400B', 'Geographic Methods', 'Quantitative and qualitative methods used in geographic research, including statistical techniques, and qualitative methods such as interviews.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 312', 'Geomorphology', 'Landforms and the processes responsible for their evolution.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 328', 'Global Change and Environmental Systems', 'Introduction to the Earth’s environment in the context of global change. Interdisciplinary discussion of the nature, causes and consequences of both the natural and human aspects of global environmental change.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 329', 'Cities and Nature', 'Impact of urbanization on landforms, climate, vegetation, and animals. Planning implications and case studies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 330', 'California', 'Landscapes of California, their environmental characteristics, development patterns and current problems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 333', 'Latin America', 'Mexico, Central America, the Caribbean and South America. The region’s physical and cultural landscapes. Emphasizes nature-society problems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 340', 'Asia', 'Physical, human and regional geography of Asia from Pakistan and India through Southeast Asia and the Malay Archipelago to China, Japan and Korea.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 345', 'China', 'China’s spatial organization, emphasizing spatial pattern of population, migration, regional politics and economics, and China’s many types of physical and cultural environments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 357', 'Cultural Geography', 'The dynamic spatial aspects of culture, including cultural landscapes, cultural politics, and cultural practices to understand human relationships to place, to things, to the local and to the global - how geography helps people make meaning.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 360', 'The Global Economy', 'Geographic perspectives on the global production of goods and services and their distribution to consumers. Key geographic issues in uneven development, international trade, investment patterns, and the spatial integration of local and regional economies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 422', 'Global Climate Change', 'Physical factors that produce climatic patterns and regional impacts of climate change.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 424', 'Desert Landscapes', 'Survey of desert landscapes including climate, geomorphology, vegetation, natural history, settlement, and unique urban planning challenges. The desert as “place” in geographic literature will also be explored. Course will focus on North American deserts. Field trip is required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 425', 'Tropical Rainforests', 'Discussion/seminar examining the geography, ecology and human use of tropical rainforests. Causes and consequences of deforestation, sustainable development and preservation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 426', 'The Coastal Environment', 'Coastal geomorphology, climatology and plant geography, emphasizing Southern California. Human interaction, modification, and management of those systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 478', 'Urban Planning Principles', 'Seminar/discussion on conceptual themes and legal foundations of American urban planning. Policy areas associated with urbanization and suburbanization processes: land use, economic development, redevelopment, housing systems, neighborhood dynamics and growth management. (GEOG 478 and POSC 478 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 481', 'Geographic Information Systems: Introduction', 'Methods and applications of computer-assisted mapping and geographic information systems. Instructional fee. (2 hours discussion, 3 hours lab)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 482', 'Environmental Impact Assessment', 'Techniques relevant to environmental impact assessment in accord with CEQA (state) and NEPA (federal) regulations. Systematic evaluation of major environmental impact topics. Individual and small team activities.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 483', 'Mountain Field Geography', 'Summer field study of the physical geography of mountain systems in the West. Alpine/subalpine glacial action, weather and climate, biogeography, soils, human impact and sustainability. Instructional fee required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 484', 'Urban Planning Methods', 'Seminar and Practicum on methods in urban planning. Analytical techniques and basic data sources. Population forecasting, housing surveys, economic development, fiscal impacts and area revitalization. Individual and team projects. (GEOG 484 and POSC 484 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 485', 'Geographic Information Systems: Principles and Applications', 'Integrated computer-assisted methods for handling spatial data, including database design, data conversion and updating, information retrieval, analysis, modeling and mapping. Instructional fee.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 486', 'Environmental Remote Sensing', 'Fundamentals of remote sensing science and digital image processing. Remote sensing principles and the processing and interpretation of remotely sensed data using image processing techniques and software.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 489', 'Digital Image Processing', 'Beginning and advanced techniques in digital image processing. Provides working knowledge of remote sensing with a primary focus on how to analyze and interpret remotely sensed data using image processing techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 495', 'Internship in Applied Geography (1-3)', 'Work specified number of hours in appropriate public or private organizations under the supervision of its staff and as coordinated by departmental faculty. Meet with instructor by arrangement. May be repeated for a maximum of 3 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 499', 'Independent Study (1-3)', 'May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 500', 'Geographic Research Design', 'Preparation for thesis research and writing. How to select a topic, craft a research question, select appropriate research methods, delve into relevant geographic literature and write a thesis proposal. Required of all Geography M.A. students, who are strongly encouraged to take the course as soon as possilbe in their programs. Requires consent of instructor.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 520', 'Seminar in Physical Geography', 'Research in physical geography: methods and contemporary themes. Case studies in climatology, geomorphology and plant geography.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 530T', 'Seminar: Selected Topics in Geography', 'Various topics selected from any of the subfields of geography. Chosen topic and general outline of the seminar are circulated prior to registration. May be repeated once with different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 550', 'Seminar in Human Geography', 'Survey of methodology and case studies including: experiential environments; rural landscapes; urban, social and economic structure; geography and public policy; and Third World development. Meets the graduate level writing requirement.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 597', 'Project', 'Requires consent of adviser.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 598', 'Thesis', 'Requires advancement to candidacy.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOG 599', 'Independent Graduate Research (1-3)', 'May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 101', 'Introduction to Geology', 'Introduction to the science of rocks, fossils, volcanoes, earthquakes, landscapes and oceans. Natural hazards, geology in everyday life and geology as field of practice. High school algebra recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 101L', 'Introduction to Geology Laboratory', 'Hands-on analysis and evaluation of rocks, maps, geologic time and Earth processes. Natural hazards, geology in everyday life and scientific inquiry. Pre- or', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 102', 'Earth Science Investigations for Future Teachers', 'For prospective elementary school teachers. A laboratory and activity-based introduction to the field of earth science: fundamental Earth; atmospheric, oceanic and astronomical science concepts; potential impacts of natural hazards on planet Earth.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 110T', 'Topics in Earth Science', 'Public interest topics in Earth science. Alternating topics include dinosaur world, earthquakes and volcanoes. Courses may include integrated labs, lectures and field trips that explore mainstream Earth science issues. (3 hours lecture, field trips.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 201', 'Earth History', 'Evolution of Earth as interpreted from rocks, fossils and geologic structures. Plate tectonics provides a unifying theme for consideration of mountain building, evolution of life and ancient environments. (2 hours lecture, 3 hours laboratory, field trips)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 201L', 'Earth History Supplemental Lab', 'Supervised research on topics related to Earth history. Project will result in a term paper and/or web page. (3 hours laboratory, field trips)', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 303A', 'Earth Materials', 'Identifying rock-forming minerals based on their chemical, physical and optical properties; relating mineral identification to rock lithology and classification; interpreting the significance of a rock’s mineral assemblage in terms of its igneous, metamorphic, sedimentary or hydrothermal origin. (1 hour discussion,2 hours activity, 6 hours laboratory, field trips.)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 303B', 'Igneous and Metamorphic Petrology', 'Description, classification, occurrence and origin of igneous and metamorphic rocks. (2 hours lecture, 6 hours laboratory, field trips)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 310T', 'Topics in California-Related Geology', 'Directed investigations of one aspect of Earth science. Alternating topics include geology of California, earthquakes, geologic hazards of California, geology of national parks, Earth’s environmental crisis and California’s water crisis. May be repeated for credit with a different topic. (3 hours lecture; optional field trips)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 321', 'Sedimentation and Stratigraphy', 'Sedimentary rocks, including: classification, texture, mineralogy and provenance; introduction to sedimentary environments and interpretation of ancient environments in the rock record; study of stratigraphic methods and patterns. (2 hours lecture, 6 hours laboratory, field trips)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 322', 'Paleontology', 'Identification, systematics, evolution, ichnology, biostratigraphy, taphonomy and paleoecologic analysis of fossil groups. (3 hours lecture, 3 hours laboratory, field trips).', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 333', 'General Oceanography', 'Chemical, physical and geological nature of the oceans. (2 hours lecture, 3 hours laboratory, field trips)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 335', 'Hydrology and Surface Processes', 'The impact of surface water on the formation of soils, weathering, surface features (rivers) and groundwater. Applying hydrology as a predictive and postdictive tool on geologic, biotic and engineering problems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 355', 'Earth’s Interior', 'Geophysical, geochemical properties of mantle and core. Data collection techniques. Impact of internal processes on crustal/surface phenomena.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 360', 'Structural Geology', 'Faults, folds, mechanics of rock deformation and elementary tectonics; solution of problems by geometric, trigonometric and stereographic analysis. (1 hour lecture discussion, 2 hours activity, 6 hours laboratory, field trips)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 380', 'Geologic Field Techniques', 'Basic geologic field equipment. In-class and weekend field projects include: basic geologic mapping on topographic maps and aerial photographs; field note-taking methods; field data interpretation; preparing geologic maps; preparing stratigraphic columns and geologic cross-sections; technical report writing. (2 hours lecture, 6 hours in-field activity, weekend field trips) Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 404', 'Optical Mineralogy and Petrography', 'Principles of optical mineralogy and use of petrographic microscope to analyze minerals and textures of igneous, metamorphic, and sedimentary rocks. (1 hour lecture, 6 hours laboratory, field trip)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 406', 'Geochemistry', 'Basic chemical and thermodynamic principles applied to the origin and alteration of igneous, sedimentary and metamorphic rocks and economic mineral deposits. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 408', 'Volcanology', 'Volcanic eruptions and their deposits, hazards and impact on society. Classroom activities and field trips (required) will explore modern and ancient volcanic environments. (1 hour lecture discussion, 3 hours laboratory, field trips).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 410', 'Planet Earth for Educators', 'Project-based course to prepare for teaching Earth Science in K-8 or credential program. Earth Science concepts, the Next Generation Science Standards, and how to teach using them. Develop lesson plans and activities, and practice teaching with peers. in M.S. Geology; available for graduate credit in education program. (2 hours lecture, 2 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 436', 'Hydrogeology', 'Occurrence, movement and utilization of groundwater resources; geological, geophysical and hydrological methods for groundwater exploration and development. Well hydraulics and ground-water contamination. (1 hour lecture discussion, 3 hours laboratory, field trips)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 440', 'Paleoclimatology', 'Methods and archives used to understand past climate; examining atmospheric circulation, oceanic circulation and the Earth’s energy budget in the context of past climate change. (1 hour lecture discussion, 3 hours laboratory, field trips)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 456', 'Geophysics', 'Seismic refraction, gravity, magnetic and electrical techniques and fundamentals as applied to determine subsurface structure, groundwater and location of mineral resources. (1 hour lecture discussion, 3 hours laboratory, field trips). PHYS 226 or PHYS 212 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 470', 'Environmental Geology', 'Geologic processes, hazards, mineral and energy resources and their interaction with planning and environmental regulations. (3 hours lecture, 3 hours lab, field trips)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 475', 'Quaternary Tectonics', 'Processes and products of relatively young Quaternary tectonics. Evaluating surface tectonic features, their ages, deformation styles and structural regimes. Assessment of past and contemporary deformation rates. (2 hours lecture, 6 hours laboratory, field trips)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 481A', 'Geology Field Camp I', 'Advanced geologic mapping in a variety of geologic settings. Requires field report, map and cross-sections. Instructional fee required. (45 hours per week for four weeks during summer)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 493', 'Directed Studies (1-4)', 'Directed studies in specialized areas of the geological sciences, such as petroleum geology, sedimentology, optical and instrumentation techniques. Library research and written reports required. May be repeated for a maximum of 8 units. Not available for M.S. Geology graduate credit.', 1, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 495', 'Geological Sciences Internship', 'Geological sciences work experience, salaried or volunteer, with industry, government or private agencies. Student intern will be supervised by faculty adviser and employer. (1 hour of seminar per week plus a total of 120-150 hours of work experience)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 496L', 'Geological Sciences Tutorial', 'Provides a maximum of 6 hours per week of supervised tutoring or teaching experiences (including office hours) for undergraduate students assisting in laboratory or field geology classes. Not available for M.S. geology graduate credit.', 2, 2, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 498', 'Undergraduate Thesis (1-3)', 'Extension of an advanced course, conducted independently by the student under faculty supervision, culminating in a paper of professional quality. Must be taken for credit for a maximum of three units. Requires approval of thesis adviser for first unit. Completion of thesis proposal that is approved by thesis adviser and the Department Undergraduate Adviser for second and subsequent units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 499L', 'Independent Study (1-3)', 'Independent study of a topic selected in consultation with and completed under the supervision of the instructor. May be repeated for a maximum of 6 units. Not available for M.S. geology degree credit.', 1, 3, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 500', 'Advanced Geological Concepts and Methods', 'Current advances in geological concepts emphasizing Southern California geology. Develop tools to construct a thesis proposal: research planning; developing thesis topics; bibliographic methods; research design (laboratory and field); research proposal preparation. May include seminars, group projects and field trips. (2 hours lecture, 2 hours activity, field trips)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 506T', 'Advanced Topics in Geochemistry', 'Special topics on modern techniques and recent advances in geochemistry, such as geochronology and environmental isotope geochemistry. May be repeated once for credit with different topic. (3 hours lecture; field trips)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 510T', 'Advanced Topics in Geology', 'Modern techniques and recent advances in geology such as basin analysis, carbonate sedimentology, paleontology, paleolimnology, igneous petrology, tectonics and studies of the Mesozoic Era. May be repeated with different topics for a maximum of 12 units. (2 hours discussion; 3 hours field laboratory; field trips)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 535T', 'Advanced Topics in Hydrogeology', 'Modern techniques and recent advances in hydrogeology, such as groundwater modeling, well hydraulics and aquifer analysis, contaminant hydrogeology, hydrogeochemistry and environmental sampling and protocols. May be repeated with different topics for a maximum of 12 units. (2 hours discussion; 3 hours field laboratory; field trips)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 575T', 'Advanced Topics in Engineering Geology', 'Modern techniques and recent advances in engineering geology, such as Quaternary geology, landslide analysis and paleoseismology. May be repeated with different topics for a maximum of 9 units. (2 hours discussion; 3 hours field laboratory; field trips)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 590', 'Geoscience Seminar', 'Attendance at departmental and other seminars. Discussion and/or written assignments based on seminar topics required. May be repeated for a maximum of 3 units.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 593', 'Directed Graduate Studies in the Geosciences (1-3)', 'Directed studies of specialized geoscience topics not covered by existing courses and tailored to individual student interest. Literature research, recitations and written reports required. May be repeated for a maximum of 3 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 598', 'Thesis (1-3)', 'Completion of M.S. Thesis proposal that is approved by the thesis committee and the Department Graduate Committee Chair for second and subsequent units. Design, analyze and present a research problem culminating in a thesis for the master’s degree. May be repeated for a maximum of 6 units. Requires approval of thesis adviser for the first unit.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GEOL 599', 'Independent Graduate Research (1-3)', 'Independent research on an approved topic. May be repeated for a maximum of 3 units. Requires approval of adviser and Department Graduate Committee.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AGNG 425', 'Successful Aging and Gerotechnology', 'Gerotechnology is the study of technology and aging. The impact of computer and Internet, devices for sensory impairments, telehealth, smart home, automobile and transportation innovation on older adults, caregivers and society.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AGNG 500', 'Applied Gerontology', 'Introduction to professional practice of Gerontology. Applying biopsychosocial content and theoretical models, research and ethics in practice, career path exploration and networking, and developing leadership skills and resources.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AGNG 593', 'Research Methods in Gerontology, Project Development', 'Research processes and problems in gerontology; more detailed study of applied research, including program evaluation in the field of gerontology.Development of a project to conclude in AGNG 594 as a culminating experience.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AGNG 503', 'Aging and Public Policy', 'Origin, development, and overview of public policies affecting older persons, families and service providers. Political administrative, advocacy and private sector involvements in employment, retirement, income security, health care, social services and housing of older persons. May include a service learning component. (AGNG 503 and POSC 503 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AGNG 526', 'Public Organizational Theory and Behavior', 'Management-oriented analysis of organizational behavior. Treatments of decision-making, leadership, communication, group dynamics and ethical aspects of organization. Applying theories of administration and systems management to public and volunteer programs and services. (POSC 526 and AGNG 526 are the same course).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AGNG 535', 'Program Planning and Evaluation', 'Comprehensive theories and methods for planning and evaluating health promotion programs. Techniques for collecting and analyzing quantitative and qualitative data. Skills for measuring effectiveness of health promotion programs. (PUBH 535 and AGNG 535 are the same course)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AGNG 595', 'Gerontology Internship', 'Supervised experience in organizations that serve older adults and their families. May be repeated once for credit. Requires classified status in M.S. in Gerontology program, and consent of instructor and Program Coordinator.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AGNG 597', 'Project (3-6)', 'Under the direction of a faculty member, a topic that integrates learning in the program with an applied area of student’s interest will be selected; a major project on the topic will be developed and submitted. Requires classified status in the M.S. in Gerontology Program, and consent of instructor and Program Coordinator.', 3, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AGNG 598', 'Thesis (3-6)', 'Individual research under supervision, reported in a thesis and defended successfully in an oral examination conducted by a faculty thesis committee. Requires classified status in the M.S. in Gerontology degree program, and consent of instructor and Program Coordinator.', 3, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('AGNG 599', 'Independent Study in Gerontology (1-3)', 'Individualized study with an instructor whose recognized interests are in the area of the planned study. Conferences with the instructor as necessary; work will culminate in one or more papers. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 101', 'Personal Health', 'Basic concepts relating to health and well-being from a holistic perspective. Mental, emotional, physical and socio-environmental dimensions of health, sexuality and relationships; nutrition and physical fitness; use and abuse of drugs; health care services and current health problems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 133', 'Introduction to Aging Studies', 'Multidisciplinary overview of: characteristics, strengths and problems of older persons; diversity in aging process involving gender, race, ethnicity, subculture; services to older adults; gerontology as an academic discipline and a field of practice. (AGNG 133, SOCI 133, PUBH 133, HUSR 133 and PSYC 133 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 203', 'CPR, Automated External Defibrillator and First Aid', 'Provides knowledge and skills necessary to respond to injuries and sudden illnesses in the community. Successful completion provides American Red Cross certifications in infant, child and adult Cardiopulmonary Resuscitation (CPR), Automated External Defibrillator (AED) and standard first aid. Credit/No Credit only. (PUBH 203 and KNES 203 are the same course)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 301', 'Promotion of Optimal Health', 'Advanced health concepts and practices. Common health problems, causative factors and methods for prevention. Preventive and promotive health concepts and practices; integrating physiological, psychosocial, spiritual, cultural and environmental factors that inhibit or facilitate optimal health. Elective for nursing majors only.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 321', 'Drugs and Society', 'Psychoactive substances from an interdisciplinary perspective. Social, historical, biological and legal aspects of substance use.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 325', 'Consumer Health', 'Analyze and evaluate health information, products and services; medical quackery, fraudulent health practices, and laws and agencies protecting the consumer.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 342', 'Stress Management', 'Nature of stress and physiological and psychological effects of prolonged stress responses. Short- and long-term somatic and behavioral techniques (exercise, relaxation, meditation, nutrition, time management and goal setting) for management of stress. (PUBH 342 and KNES 342 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 349', 'Measurement and Statistics in Health Science', 'Measurement theory and statistics used to evaluate health and human performance, focusing on analyzing and interpreting data in different environments. Lecture, discussion, cooperative learning and field observation. Active participation and experiential learning.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 350', 'Nutrition', 'Concepts of nutrition as they relate to nutritional needs, practices and problems throughout the life cycle. Nutritional counseling and education of individuals/groups toward health promotion and disease prevention.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 358', 'Contemporary Issues in Children’s Health', 'Overview of common causes of, interrelationships between, and prevention of morbidity and mortality among children and youth; preventive and promotive health concepts and practices; connections between health and learning are explored.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 401', 'Epidemiology', 'Applying epidemiologic procedures to the understanding of the occurrence and control of infectious and chronic diseases, mental illness, environmental health hazards, accidents and geriatric problems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 410', 'Community Health Education', 'Multiple settings for community health education practice and professional roles and skills that are required for health educators. Identification of community health education concepts with application to various segments of the nation’s health.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 411', 'Promoting Health in Diverse Populations', 'Impact of cultural variables on health/illness. Current and potential strategies to improve health care delivery to underrepresented groups. Identifying cultural competence skills that are essential for health educators.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 415', 'Environmental Health', 'Overview of environmental factors such as noise, water and land pollutions, pests and contaminants that influence human and ecological health on the regional scale. Methods of control to prevent diseases from environmental agents.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 310', 'The California Experience', 'Seven themes in California studies. Explores the California experience through readings, films and music, and three writing assignments that ask them to research one topic each in the arts/humanities, social sciences and natural sciences in California. (LBST 310 and HIST 310 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 311', 'World War II', 'History of World War II: Films, documentaries, lectures and discussion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 315', 'A European Tour', 'Interdisciplinary introduction to the development of European civilization in the pre-modern period through an examination of select sites. The geographical and environmental context, the peopling of Europe and the evolution of cultural, political, economic and religious ideas and institutions. (HIST 315 and LBST 315 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 320', 'Modern European History 1789 - Present', 'Major political, social, economic and cultural developments in Modern Europe: French Revolution, industrial revolution, liberalism, socialism, nationalism, imperialism, urbanization, modernity, the World Wars, Russian Revolution, inter-war period and post-1945 period.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 331', 'History of Science: Copernicus to the Present', 'Science from the 16th century to the present, especially the scientific revolutions of the 17th and 20th centuries and the interaction between science, technology and culture. (HIST 331 and LBST 331 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 332', 'Concepts and Approaches in Women’s History', 'Overview of problems, concepts, methodologies and debates that have characterized women’s history in recent decades. (HIST 332 and GSS 332 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 355', 'History of African Civilization', 'Social, political, economic and cultural evolution of African civilizations from early times to the present.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 360', 'Modern Asia: Nationalism and Revolutionary Change', 'Modular analysis of nationalism, revolution and modernization as drawn from the experiences of countries in Asia, including China, Japan, Korea, India, Vietnam, Indonesia and the Philippines.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 377', 'Women’s Image in American Film', 'Images, symbols, visual metaphors and myths as they relate to the image of women. Change in film images will be contrasted with the changing status of women in America.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 382', 'World War II Japanese American Evacuation', 'World War II eviction and detention of people of Japanese ancestry in the United States, pivoting on the significance of this experience in the areas of civil and human rights, cross-cultural relations and international affairs. (HIST 382 and ASAM 382 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 394', 'The American Civil War', 'History of the American Civil War. Both contemporary and current analyses of the war will be amplified by the use of films and slides.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 395', 'World War I', 'Explores military, cultural, social, economic, ecological, and political aspects of the war using film, literature and other sources.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 400A', 'Teaching Premodern History', 'For students intending to teach world history. Introduction to and critical analysis of the history and pedagogy of world history. The differential development of human societies across time and across the globe.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 410', 'The Rise of the Atlantic World', 'Main themes of the history of the Atlantic Basin, 1450-1700, including the discovery and conquest of the New World, Africans’ contributions to the creation of the Atlantic world and the origins of the “plantation complex.”', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 411B', 'Genocide and Ethnic Cleansing', 'History of genocide and ethnic cleansing in a global context. Weekly readings and seminar discussions highlight questions of facial violence, victimhood, modernization, nation building, gender, class, and the politics of memory and denial.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 412A', 'History of the Christian Church to the Reformation (1517)', 'Christian Church from its origins in the apostolic preaching through the late Middle Ages and the beginning (1517) of the Reformation in both the East and West. (HIST 412A and RLST 412A are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 412B', 'History of the Christian Church from the Reformation to the Present', 'Western church as an institution from the Reformation (1517) to the present. Orthodoxy, Catholicism and Protestantism in historical perspective. (HIST 412B and RLST 412B are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 412C', 'History of the Jews', 'The Jewish people from the biblical period to the present. The literature of each period, as well as the relationships which exist between the Jewish communities and the societies in which they exist. (HIST 412C and RLST 412C are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 415A', 'Early Greece: From Troy to Thermopylae', 'Introduction to the history of early Greece (c.1400-479 BCE). Social, cultural, political and economic history, critically analyzed on the basis of primary sources; focusing on historical context of beginnings of ancient Greek poetry, philosophy, historiography and political organization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 417A', 'Roman Republic', 'Roman social and political institutions under the republic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 417B', 'Roman Empire', 'Roman imperial institutions and culture with attention to the rise of Christianity. (HIST 417B and RLST 417B are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 420', 'The Byzantine Empire', 'East Roman Empire from Constantine to the Ottoman conquest of 1453. Institutional aspects of Byzantine society: church, state, the economy, law and culture.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 423A', 'Medieval History, 300-1350', 'Medieval civilizations - East European, West European and Islamic - from the decline of the Roman Empire to the beginning of the Hundred Year’s War, with emphasis on cultural, intellectual and social history.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 423C', 'Ancient and Medieval Britain', 'Britain from 5 B.C. to 1485. Constitutional, institutional and cultural aspects of Roman, Celtic, Anglo-Saxon, Norman and Plantagenet Britain.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 425A', 'The Renaissance', 'Europe in the 14th and 15th centuries: development of humanism and capitalism in Italy and their impact on European culture; rise of Renaissance monarchies; the Renaissance papacy; Christian humanism; and Renaissance science and mysticism.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 326', 'Magic, Mysticism and Witchcraft in Early Modern Europe', 'Magical thinking in Europe from its medieval roots through the 17th century. The currents of magical thinking in elite and popular culture and its manifestations in Renaissance science and philosophy and in the witch craze.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 429B', 'From the Defeat of Fascism to the Fall of Communism: Europe since 1945', 'Survey of the cultural, political and economic history of Europe since 1945.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 432A', 'Germany to Fall of the Nazis: Nation, Race, Sex and Empire', 'German national unification, the rise of racial antisemitism, imperialism in Africa, World War I, fascism and antifascism, the sexual and cultural innovations of the Weimar Republic, and Nazi genocide during World War II. Focus on race, gender and empire.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 433A', 'Tudor Stuart England', 'England from the accession of Henry VII to the Glorious Revolution. Political, institutional, ecclesiastical and cultural aspects of the period of the Tudors and Stuarts.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 433B', 'History of Modern England and Great Britain', 'Modern British history (Glorious Revolution to present). Achievement of constitutional monarchy, transition from agrarian to industrial society, establishment of political democracy and the rise and fall of socialism.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 435A', 'The Holocaust', 'The history and origins, implementation and results of the European-wide programs of persecution and genocide carried out by Nazi Germany and their collaborators against the Jews during the period 1933-1945. (HIST 435A and RLST 435A are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 435B', 'Fascism, 1918 - 1945', 'Global phenomenon of fascism from its origins at the end of the 19th century to its “defeat” at the end of World War II, examining major and minor movements from a social, cultural, and political point of view.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 436A', 'Cities in European Civilization, 1000-1915', 'Urban history of Western Europe from the revival of urban life in the High Middle Ages through WWI, with a focus on urban social and cultural evolution.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 449A', 'Race, Ethnicity and Gender in Latin America: A History', 'Issues of race, ethnicity and gender in Latin America from the 15th century to the present. Emphasizes Latin America’s two largest countries, Brazil and Mexico.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 449B', 'Cuban History Through Film', 'History of Cuba through film. The camera as a window into Cuban society. Major themes, such as slavery, gender, Cuban-U.S. relations and the socialist revolution.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 451A', 'Colonial Period of Latin America', 'Latin America from its pre-Columbian origins to the era of the Wars of Independence. Ethnic, social, and cultural factors that characterized the colonial period.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 451B', '19th-Century Latin America: Era of Nation Building', 'Latin America during the 19th century (1810-1910) with emphasis on cultural and socio-political factors that were important in the creation of Latin American nations. Special focus on development of the Rio de la Plata, the Andean nations and Mexico.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 451C', 'Latin America Since 1945', 'Focuses on political, economic, cultural and social patterns in key Latin American nations from 1945 to the present.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 452', '20th-Century Brazil', 'Social, economic, cultural and political history of Brazil, with particular emphasis on the period since World War II.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 453A', 'History of Mexico pre-Columbian (pre 1521) through 1821', 'History of Mexico from prior to the Spanish conquest of 1521 through the wars for Independence ending in 1821.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 453B', 'History of Mexico from Independence (1821) to Modern Day', 'Pivotal moments in modern Mexican history, including post-colonial nation building, Mexican-American War, Mexican Revolution of 1910, Chiapas Rebellion of the mid-1990s and 2000 elections.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 458A', 'West Africa and the African Diaspora', 'West African relationships with the African diaspora in the Americas. Issues of the origins of political conflict, economic exploitation, racism, gender, revolts and emancipation, Pan-Africanism and rights of African descendants since the 15th century.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 458B', 'Southern Africa in the 20th Century', 'Twentieth-century developments in the Union (Republic) of South Africa, Central Africa (the Rhodesias and Nyasaland) and Portuguese colonies; the political, economic and social ramifications of race relations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 458C', 'African History Since 1935', 'Issues of European imperialism, settler cultures, racism and African consciousness, ethnic conflict, gender, nationalist and guerrilla liberation movements, Pan-Africanism, international relations and society development policies in Africa since 1935.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 460A', 'The Chinese Diaspora', 'History of Chinese migration from the 16th century to the present, focusing on the domestic and international situations that shaped the conditions for Chinese migration to different parts of the world.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 461', 'History of Ancient China', 'Chinese history from ancient times to the middle of the 17th century; society, thought, economy and political institutions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 463A', 'History of Japan', 'Social, political, and economic history of Japan until 1868, stressing the Tokugawa era.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 463B', 'History of Japan', 'Rise of the modern Japanese state, Japanese imperialism and the postwar era.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 463C', 'Themes in Korean History', 'Chronological overview of Korean history, emphasizing the modern period. Thematic approach covers topics such as a state building, Confucianism, nationalism, the colonial period, the Korean War and reunification of the peninsula.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 464A', 'History of Southeast Asia to 1800', 'Development of Southeast Asian civilizations from the earliest times to 1800, including the classical and early modern era.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 464B', 'History of Southeast Asia, 1800-present', 'Development of Southeast Asian history from 1800 to the present, including the colonial, post-colonial and contemporary period.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 464C', 'Early Vietnam', 'History of Vietnam from the earliest times to c. 1800. Seeks to identify main issues in early history of Vietnam, trade origins of Vietnamese civilization and its implications on the formation of Vietnamese national identity and nationalism.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 464D', 'Modern Vietnam', 'History of Vietnam since 1802. The French colonial experience, the Vietnamese struggle against the French from 1946 to 1954, and the American involvement in Vietnam.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 466A', 'Islamic Civilization: Arab Era', 'Arab predominance in the Middle East from the rise of Islam to the Mongol invasions of the 13th century. (HIST 466A and RLST 466A are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 466B', 'Islamic Civilization: Imperial Age', 'Mongol invasions of the Middle East and their effects. Ottoman Turkish, Safavid Persian and Moghul Empires to 1800. (HIST 466B and RLST 466B are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 467A', 'The Middle East in the 19th Century', 'Western penetration of the Middle East and the reaction to it, modernization, the growth of nationalist movements and revolutionary disturbances ending with World War I.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 467B', 'Contemporary Middle East History', 'Social, political and economic changes in the Middle East since World War I. The period after World War II and recent independence movements.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 468A', 'Women and Gender in Middle East History', 'History of women and gender relations in Middle Eastern society and culture from the period of late antiquity to the present.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 468B', 'Making the Medieval Middle East', 'Most important historical events, social transformations and historiographic issues that pertain to the rise of caliphal rule and the creation of medieval society in the Eastern Mediterranean.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 471A', 'American Colonial Civilization', 'Creation and development of societies in English North America from 1492-1754; the emergence of economic, social and political patterns and structures in a maturing Anglo-American culture.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 471B', 'The United States from Colony to Nation', 'Social, economic, political and intellectual developments in late 18th-century America, the coming of the American Revolution, origins of American nationalism, social structure of the new nation and formation and ratification of the Constitution.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 473B', 'United States, 1845-1877', 'Mid-19th century U.S. society, politics and culture. Slavery, the sectional crisis, the Civil War and Reconstruction.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 473C', 'United States, 1876-1920', 'Industrialization, urbanization and immigration. Reconstruction, the New South, and the West. Populist and Progressive reform movements. World War I and the Red Scare.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 475A', 'United States, 1920-1960', 'Major trends and conflicting values in domestic policies, national security policies, the economy, society and culture. Civil rights, civil liberties, parties and politics. Key historiographic controversies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 475B', 'United States in the 1950s', 'American society, politics and culture during the Cold War era. From World War II’s end, the Cold War at home and abroad and America’s involvement in the Vietnam War.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 475C', 'United States Since 1960', 'U.S. History from 1960 to present, interrelating foreign and domestic policy, economic, social and cultural trends, a study of U.S. history as it is being formed.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 477A', 'The Multiracial History of America', 'History of race relations and racial ideas in the United States through the experiences of multiracial families, from prior to European colonization to the present day.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 477B', 'Native American History', 'Role of Native Americans in American history. Focuses on religion, education, literature, commerce and museums to understand the interactions between Native Americans and Americans of other races and ethnicities within the context of wider historical trends.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 380B', 'American Legal and Constitutional History', 'Legal and constitutional issues affecting the development of the U.S. Constitution, American law and government. Developments from English and colonial legal origins to constitutional problems of the post-World War II era.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 380C', 'American Military History', 'America’s military experience focusing upon the democratic, industrial, managerial, mechanical, scientific and social revolutions that have molded military institutions and national policies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 480D', 'United States Foreign Relations', 'Relations from 1900 to the present. United States as a world power in the 20th century; the search for world order and the diplomacy of the atomic age.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 481A', 'U.S. West and Borderlands', 'History of the Western frontier and region of the U.S. and its borderlands from the 17th century to the present. The U.S. West as a dynamic space marked by conquest, frontier mythology, aridity, migrations and complex relations with federal power.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 481B', 'History of California', 'Political, economic and social history of California from the aboriginal inhabitants to the present; the development of contemporary institutions and the historical background of current issues.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 481C', 'The History of Orange County', 'History of Orange County. Stresses the process of urbanization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 490T', 'Senior Seminar', 'Directed research seminar with class discussions applied to specific topics and areas as schedule and staff allow. Original research and writing. Required of all history majors. History majors must earn a “C” (2.0) or better. May be repeated with different topics for a maximum of 9 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 498', 'History Internship', 'Offers work experience related to the history academic program or to areas of public and private employment where any liberal arts major is appropriate. May be repeated once for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 499', 'Independent Study (1-3)', 'Open to advanced students in history with consent of department chair. May be repeated once for credit.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 501', 'Theory and History', 'Seminar introducing philosophical issues in history as a humanistic social science, to epistemological considerations of the relationship of history to other disciplines and to new subdisciplines in history. Required for the M.A.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 506', 'Seminar in Public History', 'Seminar in sources, themes, writing and formats used by historians working outside the classroom. Content will vary with instructor and will emphasize applying historical methods to various sectors of community history. Alternative to HIST 572/HIST 522 requirement for M.A. Required for M.A. students pursuing the Public History Emphasis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 521T', 'Directed Readings Seminar in Fields of European History', 'Literature that has been important in different fields of European history. May be repeated once with different topic. Requires 3-unit upper-division course in the sub-field of the offering.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 522', 'Seminar in European History', 'Utilize primary sources in writing research papers on European History. May be repeated once for credit with different sub-field.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 551T', 'Directed Readings Seminar in World and Comparative History', 'Variable topics reading seminar designed to offer a comprehensive background in the literature of world and comparative history. May be repeated once for credit with different topic. Requires 3-unit upper-division course in world history.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 552T', 'Seminar in World and Comparative History', 'Variable topics research seminar designed to explore world and comparative history through a primary source based research paper. May be repeated once for credit with different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 571T', 'Directed Readings Seminar in Fields of American History', 'Literature that has been important or influential in specific fields of American history. May be repeated once for credit with different topic. Requires 3-unit upper-division course in sub-field of the offering.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 572', 'Seminar in American History', 'Utilize primary sources in writing research papers on American History. May be repeated once for credit with different topic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 596', 'Graduate Internship in History', 'Professional-level internship in historical work. Usually precedes HIST 597, Project and constitutes research phase of main graduate exercise, as well as preparation for post-graduate career. May be repeated once for credit. Requires classified graduate status.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 597', 'History Project (3-6)', 'Editing a significant body of primary source materials, including a critical and interpretive introduction, as well as appropriate reference and explanatory notes. Foreign sources will normally be translated into English. May be repeated for a maximum of 6 units.', 3, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 598', 'Thesis (3-6)', 'May be repeated for a maximum of 6 units.', 3, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HIST 599', 'Independent Graduate Research (1-3)', 'May be repeated for a maximum of 6 units. Requires consent of department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 100', 'Introduction to Human Communication', 'Theory and practice of interpersonal communication. Practice in the development of skills for improving the quality of communication is required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 102', 'Public Speaking', 'Theory and presentation of public speeches, including an analysis of determinants of comprehension and attitude formation; selection and organization of speech materials, development of delivery skills and evaluation of message effectiveness. Student presentations required. Participation in research projects.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 138', 'Forensics', 'Investigation and practice in the background, format procedures and evaluation criteria of the various forensic events. Students must participate in at least two intercollegiate speech tournaments. May be repeated once for credit. (More than 6 hours of class work for each unit of credit)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 220', 'Interpersonal Conflict Management', 'Nature, causes and structure of interpersonal conflict; communication strategies exhibited in conflict; and intervention principles for conflict management. Conflict management theory is applied to conflicts within marriages, small groups, organizations and intercultural relationships.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 235', 'Essentials of Argumentation', 'Methods of critical inquiry and advocacy. Identify fallacies in reasoning, testing evidence and evidence sources; advancing a reasoned position; and defend and refute arguments. Analysis and evaluation of oral and written arguments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 241', 'Introduction to Phonetics', 'Analysis and description of speech at the segmental and suprasegmental levels. Practice using the International Phonetic Alphabet for broad and narrow transcription. Overview of speech production.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 242', 'Introduction to Communicative Disorders', 'Broad overview of disorders of communication, including classification and prevalence. Educational and training requirements for speech-language pathology and audiology, professional settings and opportunities, ethical considerations, clinical observations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 302', 'Introduction to Sign Language', 'Overview of the deaf experience and the options for communication in the deaf community. Use of American Sign Language and finger spelling at the introductory level.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 313', 'Interpersonal Communication Theory', 'Behavioral and humanistic approaches to theories of interpersonal communication. Functions of communication that influence interpersonal relationships, including communicator characteristics, information exchange, situational demands and interpersonal evaluations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 318', 'Family Communication', 'Research and theory in family communication. Role of communication in courtship, family satisfaction, family conflict and family dysfunction, with emphasis on marital, parent-child sibling and intergenerational family relationships.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 320', 'Intercultural Communication', 'Communication problems that result when members of different cultures communicate. How interpersonal communication can overcome differences in cultures’ perceptions of communication’s functionality, value orientations, nonverbal behavior, language, epistemologies and rhetorics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 324', 'Communicating in Teams and Groups', 'Applying communication theories and behavioral research findings as they relate to small groups and teams. Communication facilitation among individuals in task realization, including interpersonal needs, leadership, norms, roles, verbal and nonverbal messages, and group systems and procedures.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 325', 'Interviewing: Principles and Practices', 'Principles and practices of interviewing processes. Consideration of appraisal, counseling, employment, exit, journalistic, persuasive and survey types of interviews. Case analyses, simulations and community fieldwork required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 326', 'Organizational Communication Dynamics', 'The Interrelationships between management and communication theories. Microsystems and macro-systems within an organization are emphasized in terms of intra-personal, interpersonal, small group and organizational communication theories.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 330', 'Rhetoric of Popular Culture', 'Rhetorical theories as they apply to contemporary communication events. Various perspective of rhetorical theory are utilized to further understanding of communication in today’s society.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 331', 'Rhetorical Dimensions of Sex and Gender', 'Rhetorical dimensions of sex and gender American communication contexts. Explanation and evaluation of the creation and maintenance of masculinity and femininity in American culture from a rhetorical perspective.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 332', 'Processes of Social Influence', 'Major theories of communication concerned with influence and persuasion in society. Communication effectiveness through strategic application of theory to effecting change and evaluating appeals for change by others.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 333', 'Communication in Business and the Professions', 'Human behavior, structural demands and communication within organizations. Applying theory and behavioral research as a framework for generating managerial communication competencies such as interviewing, briefings, conference leadership and intergroup coordination.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 334', 'Persuasive Speaking', 'Strategies and tactics appropriate to leading social policy persuasive campaigns. Analyze receiver variables, progressive use of persuasive materials, question and answer techniques, and the development of personal influence. Student presentations required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 335', 'Advanced Argumentation', 'Argument as applied to advocacy; logic and evidence as related to analysis of significant issues.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 337', 'Communication in the Legal Arena', 'Review and evaluation of research into communication variables and legal practices, from interviewing to closing arguments. Courtroom observation required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 338', 'Intercollegiate Forensics', 'Directed activity in debate and other forensic events. Participation in intercollegiate speech competition is required for credit. May be repeated once for credit. (More than 6 hours of class work for each unit of credit.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 340', 'Asian American Communication', 'Introduction to Asian American communication. Influences of Asian American cultural heritage, ethnic identity, generation and language fluency on communication. Similarities and differences in communication among the various Asian American ethnic groups. (ASAM 340 and HCOM 340 are the same course)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 342', 'America Speaks', 'America’s story told through the speeches that moved her. Critical evaluation of significant messages and what it would have been like to be part of the American audience exposed to famous speeches and speakers.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 344', 'The Anatomy and Physiology of Speech and Hearing', 'Anatomy and physiology of the speech and hearing mechanism. Processes of respiration, phonation, articulation-resonance and hearing.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 345', 'Communication and Aging', 'Communicative changes found in older adults, including normal and pathologic changes in the physiological and behavioral aspects. Diagnosis, rehabilitative strategies, social implications and health care systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 350', 'Speech and Hearing Science', 'Physiology and acoustics of speech production, including voice, resonance and individual speech segments. Instrumentation for the acoustic and perceptual analysis of speech.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 352', 'Child Language and Phonological Disorders', 'Language and phonological disorders in children. Speech/language profiles of special populations and contemporary approaches to assessment and intervention. Practice analyzing child speech/language samples.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 360', 'Nonverbal Communication', 'Physical actions, gestures and changes in the physiognomy that occur together with language and paralanguage in human communication; substitutions for language and modifications of it in varying cultures. (LING 360 and HCOM 360 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 404', 'Communication Development/Disorders in Children from Culturally/Linguistically/Diverse Backgrounds', 'Speech-language development in children from culturally and linguistically diverse (CLD) dialect and language backgrounds, differentiating normal language and dialect differences from disorder, and current clinical procedures for assessing and treating speech and language disorders in CLD child populations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 413', 'Communication in Interpersonal Relationships', 'Communication in the interpersonal relationship development setting with particular emphasis on current theoretical and methodological issues.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 422', 'Applications of Intercultural Communication', 'Nature and effects of intercultural communication within multicultural/multinational organizations. Intercultural leadership, negotiation, decision-making and communication competence. Analyze and practice a number of intercultural training approaches.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 426', 'Directing Forensics', 'Philosophies of forensics education, including coaching, judging and tournament administration. Strategies of implementation of these philosophies. May be repeated for a maximum of 12 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 432', 'Contemporary Rhetoric', 'Theories of how cultures and individuals manage meaning in public communication, including speeches, campaigns, print and electronic media. Applies classical, modern and contemporary critical frameworks of analysis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 433', 'Training and Development', 'Communication in a training and development environment with particular emphasis on learning principles, instructional design, implementation and evaluation of training and needs assessment.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 440', 'The Dark Side of Interpersonal Communication', 'Social scientific literature regarding the “dark side” of communication, which includes aspects of communication that are poorly understood, understudied and/or classified as destruction, dysfunctional, evil, immoral, malicious, criminal or abusive.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 445', 'Leadership: Toxic and Intoxicating', 'Leadership from a communication theory perspective. Leadership dynamics to help gain insight into leadership and the influences.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 456', 'Intercultural Conflict: Theory and Practice', 'Relationship between intercultural conflict theory and practice. Key cultural patterns that impact conflict. Theoretical and applied perspectives on intercultural conflict across contexts will be emphasized.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 548', 'Clinical Practicum: Speech and Language Disorders in Children', 'Supervised experience in the assessment and treatment of children with speech and language disorders. Weekly individual and group conferences. Approximately 25-40 clinical clock hours. May be repeated for credit. Requires approved Clinical Practicum Plan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 461', 'Audiology and Audiometry', 'Characteristics of hearing disorders, including etiologies and risk factors. Methods and procedures used in assessing the auditory system including current topics of interest. Partially fulfills the requirements for state audiometrist certificate.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 465', 'Aural Rehabilitation', 'Effects of hearing loss on speech and language. Treatment of hearing disorders, including amplification and aural rehabilitation. Role of the audiologist and speech-language pathologist in the management of hearing disorders.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 472', 'Voice and Craniofacial Disorders', 'Disorders of voice; disorders of articulation and resonance caused by orofacial pathology. Anatomical and physiological bases, assessment, diagnosis, management and interdisciplinary aspects.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 474', 'Neurology and Neurogenic Communicative Disorders', 'Anatomy and physiology of the nervous system as they relate to speech, language, hearing and swallowing. Clinical characteristics of neurogenic language disorders, apraxia of speech and dysarthria. Contemporary approaches to assessment and treatment. Lecture, demonstration and clinical observations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 475', 'Fluency Disorders', 'Theories of development and remission of stuttering, constitutional and environmental risk factors. Clinical characteristics of stuttering. Contemporary approaches to assessment and treatment. Lecture, demonstration, clinical observations and exercises.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 476', 'Clinical Methods and Procedures', 'General principles and procedures for assessment and treatment of individuals with communicative disorders. Lecture, demonstration, clinical observations and supervised clinical experience.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 585', 'Aural Rehabilitation Practicum', 'Aural rehabilitation of hearing-impaired children and adults in on- and off-campus facilitates. Sign language background recommended. Credit/No Credit only. Requires approved Clinical Practicum Plan.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 589A', 'Public School Practicum in Communicative Disorders', 'Meets the directed teaching requirements for the Speech-Language Pathology Services Credential. Approximately 100-150 clinical clock hours. Requires approved Clinical Practicum Plan and application approved prior to semester of practicum.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 492T', 'Proseminar in Speech Communication', 'Current research topics in the concentration areas of persuasion and argumentation, interpersonal communication, intercultural communication and organizational communication will be presented. May be repeated with different topics for a maximum of 12 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 496', 'Student-to-Student Tutorials (1-3)', 'Consult “Student-to-Student Tutorials” in this Catalog for more complete course description. May be repeated for a maximum of 3 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 499', 'Independent Study (1-3)', 'Open to upper-division students in speech communication only with signed consent form from department chair. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 500', 'Research in Speech Communication', 'Research design and methods used in historical, descriptive and experimental research in speech communication. A “B” (3.0) or better is required for credit in the Communication Studies M.A.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 501', 'Seminar in Speech-Language Pathology', 'Introduction to requirements for the M.A. degree in communicative disorders, including the requirement for demonstrating knowledge-based and skill-based competencies. Students start a portfolio for documentation of competencies and demonstrate a number of competencies within this course. Credit/no credit only.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 509', 'Qualitative Research Methods', 'Perspectives in qualitative research methodology in communication studies (ethnography, naturalistic inquiry, case study, phenomenological research, textual/content analysis, archival analysis). Interpretive design; application of standards; data analysis; reporting conclusions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 510', 'Seminar in Interpersonal and Relational Communication', 'Theoretical and empirical examination of interpersonal and relational communication. Generation of theoretical frameworks and/or heuristic models of concepts and process under investigation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 520', 'Seminar in Group Communication', 'Small group communication theory. Small group variables, methods and outcomes, and group process as a learning tool.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 522', 'Seminar in Intercultural Communication', 'Theory and methodology in intercultural communication research. Specific variables examined include attribution, values, communication competence and acculturation/adaptation. Practice in completing original research in intercultural communication.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 525', 'Seminar in Organizational Communication', 'Theoretical postulates concerning managerial and organizational communication. Research findings and case studies relating to communication determinants and organizational effectiveness. Communicative relationships among individuals, the work unit and the organization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 535', 'Seminar in Argumentation and Persuasion', 'Leading theories and empirical research on argumentation and persuasion. Strategies of effective advocacy and compliance-gaining. Laboratory research and applied settings. Ethical issues related to argumentation and persuasion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 536', 'Seminar in Communication and Rhetorical Theory', 'Analyze rhetorical and communication theories. Comparisons and contrasts of the epistemological bases of empirical and humanistic inquiry. A “B” (3.0) or better is required for credit in the Communication Studies M.A.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 542', 'Neurologic and Clinical Aspects of Speech, Language and Cognition', 'Neuroanatomy as it relates to speech, language and cognition; the neuropsychological bases of consciousness, attention, sensation, perception, higher mental functions, language and motor speech; emphasis on assessment, diagnosis, prognosis and management of neurogenic communicative disorders.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 543', 'Seminar in Dysphagia', 'Theory and clinical aspects of dysphagia. Physiology of normal swallow, etiologies of dysphagia, clinical and instrumental assessment, diagnosis and management.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 544', 'Seminar in Neurogenic Speech, Language and Cognitive Disorders', 'Theory and clinical aspects of neurogenic speech, language and cognitive disorders. Standardized and informal assessment, differential diagnosis, prognosis and management, including evaluation of the validity of clinical practice guidelines through the analysis of published research.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 554', 'Seminar: Cultural, Linguistic, and Global Issues in Communication Sciences and Disorders', 'Culturally responsive research-to-practice considerations for individuals and families from diverse cultural-linguistic and global communities. Case study reviews with applied assessment, treatment, instruction and counseling/consultation activities across lifespan involving varied communication disorders and differences.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 558A', 'Clinical Practicum: Speech and Language Disorders in Adults', 'Supervised experience in assessing and treating adults with speech and language disorders. Weekly individual and group conferences. Approximately 25-40 clinical clock hours. May be repeated for credit. Requires approved Clinical Practicum Plan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 559A', 'Advanced Clinical Practicum: Communicative Disorders', 'Advanced clinical practice under supervision with children and/or adults. Off-campus program in hospitals, clinics and other rehabilitation facilities. Approximately 150 clinical clock hours. Requires approved Clinical Practicum Plan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 564', 'Autism Spectrum Disorders in Speech-Language Pathology', 'Communication disorders in children with autism spectrum disorders (current theories, diagnostic process, co-occurring conditions, the role of speech-language pathologists in multi-disciplinary approaches to assessment and intervention planning, critical review of relevant research).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 571', 'Seminar in Fluency Disorders', 'Reading assignments, seminars, lectures and case reviews to enable students to develop a framework for understanding the etiology and maintenance of stuttering and to develop their own approaches to assessment and treatment. Requires approved Individual Student Schedule.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 573', 'Seminar in Voice Disorders', 'Review classification of voice disorders (perceptually); examine instrumental assessment of such disorders (acoustically); and emphasize a comprehensive physiological, perceptual and acoustic work-up of individual cases. Requires approved Individual Student Schedule.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 574', 'Seminar in Phonological Disorders', 'Develop critical thinking and analytical skills related to current issues in linguistic theories on the assessment and treatment of phonological disorders in children. Requires approved Individual Student Schedule.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 576', 'Seminar in Augmentative and Alternative Communication', 'Historical service delivery approaches; symbol sets and systems; assessment and management strategies for persons with severe physical and speech impairments; advocacy approaches for the disabled.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('COMD 577', 'Seminar in Child Language Disorders', 'Principles of language assessment and intervention based upon psycho-linguistic theory and current research on language disordered children. Develop critical thinking and analytical skills related to the assessment and treatment of language disorders in children. Requires approved Individual Student Schedule.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 598B', 'Thesis', 'The selection, investigation and written presentation of a selected problem in the field of speech.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HCOM 598C', 'Thesis', 'The selection, investigation and written presentation of a selected problem in the field of speech.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 201', 'Introduction to Human Services', 'Origin and scope of human services, including theoretical frameworks, the functions and activities of human services organizations, and the roles and related skills of human services workers.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 300', 'Character and Conflict', 'Experiential, theme-oriented class exploring life choices in the struggle for personal autonomy. Body image, sex roles, love, sexuality, intimacy, marriage, loneliness, death, meaning and values. Credit/No Credit only. Requires consent of instructor at first class meeting.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 310', 'Case Management', 'Principles and critical issues in case management, along with various models of service delivery. Special attention given to the diverse populations utilizing case management systems. Collaborative and interagency services. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 315', 'Research and Data Management in Human Services', 'Basic research and assessment skills appropriate to the delivery of human services. Introductory skills relating to library search techniques, evaluation of research articles, computer-based data analysis, tracking client progress and implications for human services.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 318', 'Human Services for Immigrants and Refugees', 'U.S. immigration policy for newcomers. Stressors and cultural influences on coping behaviors, and culturally sensitive models of human service delivery emphasizing Southeast Asian, Latino and Soviet immigrants and refugees. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 350', 'Leadership Skills and Personal Development', 'Leadership concepts and skills, including psychological process, conflict resolution, counseling and human service skills. Becoming aware of personal leadership styles; maintaining vitality through physical and mental health. (HUSR 350 and COUN 350 are the same course).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 380', 'Theories and Techniques of Counseling', 'Contemporary theories and techniques of counseling. The counseling process, comparison of various theoretical approaches, introduction to professional and ethical issues. (HUSR 380 and COUN 380 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 385', 'Program Design and Proposal Writing', 'Techniques of program design, budgeting and staffing of human service programs; proposal writing and fund development methods; survey of needs assessment procedures.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 400', 'Ethical and Professional Issues in Human Services', 'Ethical, legal and professional issues facing the human services worker. Designed to teach a process of ethical decision-making and to increase awareness of the complexities in practice.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 410', 'Crisis Intervention for Para-Professionals', 'Emphasis on theories and techniques of short-term intervention and referral procedures addressing societal crises including suicide, cultural, developmental, loss, veterans, PTSD, community disaster, IPV, child abuse, sexual assault/rape, sexuality, bullying, substance misuse, gun violence, the pandemic, and social media issues.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 411', 'Human Services Delivery to Communities', 'Identifying the human service needs of varied community groups and focuses on the utilization of this knowledge about those groups in order to develop effective service delivery strategies. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 412', 'Gerontology in Human Services', 'Gerontology and human services practice and policy, focusing on historical developments and content of key social, legislative and governmental programs designed for older adults, including the Social Security Act, Older Americans Act and Medicare.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 415', 'Treatment Issues in Drug Addiction', 'Treatment issues and theoretical models involved in treating drug dependencies. Specific effects of different drug classifications; understanding drug cultures; women, children and elderly addiction; co-dependency and enabling.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 416', 'Group Process and Membership', 'Didactic and experiential overview of stages of group development, impact of members on group identity, group member and leader issues. Survey various counseling groups. May be repeated for a maximum of 3 units. Credit/No Credit only.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 420', 'Human Services Management', 'Issues in administration and management of human services in community agencies. Assessing client needs, designing human service delivery systems, program budgeting, marketing strategies, accountability and improving program management.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 425T', 'Contemporary Issues in the Human Services', 'Systematic study and theory, research findings and intervention strategies related to contemporary issues faced by paraprofessional human service workers. May be repeated with different topics for a maximum of 9 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 430', 'Child Abuse and the Human Services', 'Introduction to types and symptoms of abuse, assessment techniques, legal and ethical issues, family dynamics pertaining to children, adolescents and adults abused as children. Networking and referral, utilizing community resources and prevention.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 434', 'Physiological Effects of Alcohol and Other Drugs', 'Pharmacological actions of drugs of abuse and how these relate to the physiological, psychological and behavioral effects of such drugs. Properties of recreational, “street” drugs and of prescription drugs that lead to abuse and/or dependence are covered. Not available for use on a graduate study plan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 435', 'Drug Abuse Prevention and Early Intervention', 'History, theories and models in the drug prevention field. Theoretical foundations and conceptual frameworks that have been used in the field will be presented. Major research and evaluation outcomes on the effectiveness of prevention strategies. Not available for use on a graduate study plan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 436', 'Dynamics of Substance Abuse Treatment in Families', 'Explore and apply methods of assisting significant others, organizations and communities to understand, treat and prevent substance abuse and dependence. Students develop practice strategies that will prepare them to deliver services at the micro, meso and macro levels. Not available for use on a graduate study plan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 437', 'Co-Occurring Disorders: Assessment, Treatment and Referral', 'Concepts, definitions and features of co-occurring mental disorders and substance-related disorders in individuals seen in human services settings; includes screening, assessment, case management and service delivery for such individuals. Not applicable to graduate degree requirements.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 445', 'Persons with Disabilities and Human Services Community Support Systems', 'A diversity model approach to human service practice for persons with disabilities. Societal and professional stereotypes; disability culture; disability groupings; guidelines for practice with persons with disabilities; systems and community supports for persons with disabilities.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 465', 'Human Services Delivery to Latinos', 'Theory, research findings and intervention strategies related to contemporary issues faced by paraprofessional human service workers in dealing with Latino populations. How to best deliver services in mental health, social welfare, and educational agencies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 450', 'Theory and Practice of Group Counseling', 'Critical evaluation of 10 contemporary theoretical approaches to group counseling, as well as issues in group work. Applying theories and techniques to actual group situations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 470', 'Evaluation of Human Services Programs', 'Making program objectives measurable; determining appropriate methodology and techniques to evaluate effectiveness, efficiency and process variables; practical problems of program evaluation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 475', 'Human Services Policy and Practice', 'Relationship between policy and practice. Problem of inequities and inequalities in the distribution of resources through social policies and social welfare programs. How policy impacts service delivery to disenfranchised groups.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 480', 'Case Analysis and Intervention Techniques', 'Psychodynamic principles of evaluation, diagnosis and intervention; techniques of counseling appropriate to diverse populations; application of a psychoanalytic perspective to the diagnostic categories of the DSM.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 490', 'Practicum in Group Leadership', 'Supervised experience as a group leader. Approaches and techniques of group leadership. May be used as a substitute for HUSR 396, HUSR 495 or HUSR 496 with coordinator approval. May be repeated for a maximum of six units. Human Services majors and minors must earn a “C” (2.0) or better.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 495', 'Fieldwork Seminar', 'Students participate in 120 hours of service at an approved agency, 8 hours per week. Classroom analysis of agency experience focusing on skills and techniques of human service workers and organizational analysis.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 496', 'Internship Seminar', 'Supervised internship in a community service agency in area of specialization. Seminar consists of group supervision and discussion of cases. Letter grade only. Internship experience consisting of 120 hours with a minimum of 8 hours per week during the semester.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('HUSR 499', 'Independent Study (1-3)', 'Individual research project, either library or field, under the direction of a faculty member. May be repeated for a maximum of 6 units; only three units in one semester. Requires approval of coordinator, consent of instructor.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 309', 'Introduction to Programming', 'Structured programming principle; object-oriented programming principles; using GUI objects; handling events; processing files and streams.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 351', 'Principles of Information Systems', 'How business professionals can leverage Information Systems (IS) through planning, oversight and management. Understanding the implications of IS, learning to identify and evaluate potential opportunities to employ IS, understanding the role of IS as a major facilitator of the fundamental business activities and learning to manage IS projects.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 361A', 'Business Analytics I', 'Statistical data analysis and inference techniques within the context of business analytics. Selecting statistical tools that are appropriate for a given application. Develop a high level of proficiency in Microsoft Excel. Minimum 2.5 GPA required for online section registration.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 361B', 'Business Analytics II', 'Advanced concepts and applications of business analytics. Developing analytical thinking, applying business analytics solutions, and communicating insights based on the solutions to decision makers in an organization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 371', 'C++ For Business Applications', 'C++ syntax, structured programming, table handling, design standards, object oriented programming.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 402', 'Database Management Systems', 'Essential concepts, principles and methods for analysis, design and implementation of database management systems; covers theory and practice; emphasis the relational model; examines issues and problems associated with developing single and multiple user applications both today and in the future; project required.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 406', 'Systems Analysis and Design', 'Systems analysis and design for business information systems; systems development methodologies; managing changes to system parameters; systems process and data models; case tool types and their use; structured vs. object oriented analysis and design.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 409', 'Business Telecommunications for Information System Design', 'Essential concepts for developing a data communication architecture to support information systems for a business enterprise. Requires group project to design a LAN.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 411', 'Business Applications using Web Technologies', 'Contemporary issues in the design and development of integrated, graphical user interface-based business applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 418', 'Privacy and Security', 'Security and privacy problems associated with the use of computer systems; ways to minimize risks and losses.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 435', 'Integrated Enterprise Information Systems', 'Application programming fundamentals for ERP systems; accessing and management of ERP database tables and external files; layout design and data extraction for advanced output; testing, debugging and analysis tools; security issues in an ERP system.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 442', 'Business Modeling Using Spreadsheets', 'Use Microsoft Excel to implement business models. Excel will be used to effectively organize, analyze and present information. Examples include operations, production, marketing and finance. Macros, goal seek, solver, simulation and data tables.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 443', 'Marketing Analytics: Decision-Making in the Information Age', 'Applying analysis and modeling techniques to a broad range of marketing decision making domains. (MKTG 443 and ISDS 443 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 454', 'Senior Project: Information Systems Development', 'Integrates information systems development concepts of analysis, design and implementation. Develop an information system from concept to completion. Individual and team effort.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 477', 'Applied Business Forecasting', 'Forecasting methods applied to problems in business and industry; practical multiple regression models with computer solutions; basic techniques in time-series analysis of trend, cyclical and seasonal components; correlation of time-series and forecasting with the computer.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 474', 'Data Mining for Managers', 'Fundamentals of data mining. Topics may include association, classification, clustering, decision trees, statistical modeling, and visualization. Motivation for the applications of data mining techniques. Use of data mining software suites on data sets.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 495', 'Internship (1-3)', 'Planned and supervised work experience. May be repeated for a maximum of 6 units. Credit/No Credit or 3-unit Letter Grade option. Only 3-unit Letter Grade option will fulfill practicum requirement. Consent of department internship adviser needed.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 499', 'Independent Study (1-3)', 'Open to qualified students desiring to pursue directed independent inquiry. May be repeated for a maximum of 6 units. Not open to students on academic notice. Requires approval by the Department Chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 514', 'Decision Models for Business and Economics', 'Linear programming; inventory; PERT-CPM; queuing; computer simulation; time-series forecasting; and other optional topics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 526', 'Forecasting for Analytical Decision Making', 'Time series analysis. Trend, cyclical and seasonal components. Statistical decision theory. Fundamental principles of experimental design; interaction. Software packages.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 551', 'Info Resources and IT Project Management', 'Expanding role of information systems in the overall strategy and management of organizations is examined. Topics include strategic value of information systems, management of the information systems development and procurement process, E-commerce, and integrated enterprise systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 552', 'Systems Analysis, Design and Development', 'Systems analysis and design concepts, life cycle and prototyping; planning and managing projects; systems evaluation, selection and development. Interface design with controls, object-oriented design concepts and tools, including the use cases and UML.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 553', 'Electronic Commerce: Analysis and Evaluation', 'Electronic commerce. Understanding the technical infrastructure, which enables E-commerce. Organizational challenge for developing an appropriate business model for emergence of the electronic business. Social economical impact of electronic commerce.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 555', 'Business Databases: Design and Processing', 'Internet and multi-user databases; accessing Web servers; data warehouse, structured query language, client-server database systems and programming; object-oriented databases.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 556', 'Data Warehousing and Foundations of Business Intelligence', 'Basic concepts, architectures and development strategies of data warehousing, issues in managing data as organizational assets and its potentials for competitive advantages in dynamic business environments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 557', 'Issues in Business Information Technology', 'Advanced concepts of global networks, advanced communications design and management, global information security and privacy, global communications protocol and applications to industry, government and commercial sectors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 558', 'Advanced Software Development with Web Applications', 'This course focuses on advanced software development with web applications using Python. Topics include python basics, web scraping, application program interface, and building your own web applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 577', 'Seminar in Information Systems Implementation', 'Integrates the development concepts of project management, analysis, design and implementation with telecommunications, database design, programming, testing and system integration issues. Develop information systems from concept to completion through individual and team effort. Requires projects. Individual project will fulfill the terminal degree requirement. To be taken in the last semester or with completion of at least seven ISDS courses in the program.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ISDS 599', 'Independent Graduate Research (1-3)', 'May be repeated for a maximum of 6 units. Not open to students on academic notice. Requires consent of department chair and associate dean.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('IDT 505', 'Foundations of Instructional Design and Digital Authoring Tools', 'Understanding operating systems, hardware and networking environments to develop instructional tools and products using a multimedia authoring tool.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('IDT 510', 'Research Practices in Instructional Design and Technology', 'Terms and accepted procedures in qualitative and quantitative inquiry as they apply to instructional design and technology. Conduct controlled portions of IDT research and prepare preliminary proposals for larger projects. Requires completion of orientation program for M.S. in Instructional Design and Technology (IDT).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('IDT 520', 'Instructional Design 1: Issues in ELearning and the Design Process', 'Systematic design of instructional courseware, including analysis, media selection, design, development and evaluation. Learning principles, learner characteristics, instructional strategies, screen design, response analysis, feedback and interactivity.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('IDT 525', 'Learning Theories for Postsecondary and Adult Instructional Settings', 'Behavioral, cognitive, constructionist learning theories, related concepts and their implications for designing instruction. Develop critical thinking about desirable cognitive outcomes when designing educational experiences.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('IDT 530', 'Instructional Design 2: Advanced Issues in Implementation, Management and Program Evaluation', 'Applying computer-based instructional design principles to develop new methods and materials for technology-based instruction. Computer-based instruction, project management, planning, assessment, design principles and development tools. Design multimedia courseware.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('IDT 535', 'Instructional Strategies and Universal Design Issues in Learning Environments', 'Training in instructional strategies for Pre-K through adulthood. Current research on instructional strategies and assistive technologies in a variety of instructional contexts.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('IDT 545', 'Trends, Emerging Technologies and Issues in Instructional Design', 'Theoretical basis, issues and strategies for improving teaching and learning through the use of emerging technologies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('IDT 550', 'Practicum in Instructional Design and Technology', 'Strategies for effectively implementing and evaluating instructional design and technology to improve learning; includes significant field work assignments in work-related settings. Requires consent of Program Coordinator.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('IDT 597', 'Project', 'Individual research on an empirical project, with conferences with the instructor, culminating in a project. Requires consent of Program Coordinator.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 100', 'Physical Conditioning', 'Performance courses are instructional. Beginning, intermediate and advanced sections are offered for most performance courses. Students who already possess proficiency in an activity should consider the course chosen from the standpoint of the level of skill development that may be encountered, standards of proficiency expected and their own ability level. Initial assessment and determination will be made by the course instructor. May be repeated for a maximum of 6 units.', 1, 1, FALSE, FALSE);
