INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 172', 'Intercollegiate Cross Country', 'An intercollegiate activity in individual or team sports in an educational setting under the direction of a coach. May be repeated for a maximum of 20 units.', 2, 2, FALSE, FALSE);
