INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 191A', 'Integrated Human Anatomy and Physiology A', 'Integrated introduction to human anatomy and physiology. Structure and function of the musculoskeletal, nervous and cardiorespiratory systems. For nursing majors and students interested in allied health professions; no credit toward Biological Science major. (3 hours lecture, 3 hours laboratory) (KNES 191A and BIOL 191A are the same course).', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 191B', 'Integrated Human Anatomy and Physiology B', 'Second semester of integrated concepts in human anatomy and physiology for nursing, allied health and kinesiology majors. Nutrition, water and ion balance, and homeostatic regulation by the digestive, renal, cardio-respiratory, endocrine, nervous systems. No credit toward biological science major. (3 hours lecture, 3 hours laboratory) (BIOL 191B and KNES 191B are the same course.)', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 202', 'Introduction to Kinesiology', 'Study of human movement, including its role in daily life, its place in higher education and professional career opportunities in areas related to sport, movement, exercise and fitness. Multiple ways of knowing and studying human movement with a focus on the subdisciplines within kinesiology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 205', 'Medical Terminology', 'Introduction to medical terminology using word building (roots, suffixes, prefixes, spelling, and pronunciation) as they relate to anatomical structure and function. Additional topics include medical terminology related to pharmacology, abnormal conditions, surgical procedures, and diagnosis and treatment of medical conditions. (KNES 205 and NURS 205 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 210', 'Human Anatomy and Physiology', 'Introduction to human anatomy and physiology concepts as they apply to physical activity, sport and exercise. Structure and function of the skeleto-neuromuscular and cardio-respiratory systems relative to human movement. Preparation for KNES 360, KNES 361, KNES 348, KNES 371 and major in Health Science. No credit toward biological science major. (BIOL 210 and KNES 210 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 214A', 'Basic Scuba', 'Skin and scuba diving, theory of diving, safety procedures and ocean environment. Open Water Basic Scuba Certification earned with successful completion. Requires ability to swim 200 yards; float or tread water for 10 minutes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 240', 'Teaching Team Sports', 'Team sport history, skills, rules, progressions and sport-specific teaching strategies to promote active participation and experiential learning. (2 hours lecture, 2 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 241', 'Teaching Nontraditional Team Sports', 'Nontraditional sports history, skills, rules, progressions and sport-specific teaching strategies to promote active participation and experiential learning. (2 hours lecture, 2 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 242', 'Teaching Lifetime Physical Activity', 'Provides history, skills, rules, progressions and sport-specific teaching strategies to promote active participation and experiential learning of lifetime physical activities.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 243', 'Teaching Human Movement Forms in Physical Education', 'Provides history, skills, rules, progressions and sport-specific teaching strategies to promote active participation and experiential learning in dance, combatives and gymnastics. (2 hours lecture, 2 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 246A', 'Basic Hatha Yoga', 'Basic yoga postures, beginning meditation, breathing and relaxation techniques presented from a theoretical and experiential perspective. Awareness, concentration, and other practices that accompany the study of Hatha Yoga. (1 hour lecture, 2 hours activity) (KNES 246A and RLST 246A are the same course)', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 320', 'Exercise Techniques for Strength Training', 'Practical experiences in resistance exercise lifting and spotting techniques. Free-weight exercises, such as squatting and Olympic lifting. Proper set up and execution of machine-based exercises.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 325', 'Techniques of Coaching', 'Factors related to coaching strategies and techniques: philosophy, ethics, legal issues, gender, multicultural and equity issues, leadership, motivation, team management, budget, recruiting, equipment purchase, skill acquisition, season planning, conditioning, nutrition and drugs.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 342', 'Stress Management', 'Nature of stress and physiological and psychological effects of prolonged stress responses. Short- and long-term somatic and behavioral techniques (exercise, relaxation, meditation, nutrition, time management and goal setting) for management of stress. (PUBH 342 and KNES 342 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 348', 'Physiology of Exercise', 'Description and explanation of functional and structural changes in the body brought on by acute exercise and chronic training.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 348L', 'Physiology of Exercise Laboratory', 'Laboratory techniques in physiology of exercise designed to provide students fundamental knowledge of and practical experiences in test methodologies used to evaluate fitness components. (3 hours laboratory) Pre- or', 1, 1, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 349', 'Measurement and Statistics in Kinesiology', 'Measurement theory and statistics used in evaluating health and human performance, focusing on analyzing and interpreting data in different environments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 351', 'Principles of Strength and Conditioning', 'Acute effects and chronic adaptations to various forms of resistance training across the lifespan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 352', 'Principles of Teaching Group Fitness', 'Provide content knowledge and practical experience concerned with teaching group exercise. Emphasis will be placed on teaching principles, techniques, safety and a variety of exercise formats.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 353', 'Physical Activity and Lifelong Well-Being', 'Integrating physiological, psychological and sociological understandings of the human being in relationship to physical activity as a lifelong pursuit. Physical fitness, nutrition, stress reduction, socialization, and individual differences in human behavior. (PUBH 353 and KNES 353 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 354', 'Cardiovascular Exercise Testing and Prescription', 'Methods of graded exercise testing in the apparently healthy adult. Guidelines for aerobic exercise prescription. Cardiovascular disease and identification of risk factors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 363', 'Adapted Physical Education', 'Study of the disabled whose unique needs in motor development determine their least restrictive environment in physical activity. Programs of games, sports and exercise in diversified settings; legally mandated regulations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 364', 'Motor Development', 'Examine changes in human motor behavior across the lifespan, factors that underlie these changes, and the application of theoretical concepts to development of movement-based age appropriate programs.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 365', 'Pathologies in Sport/Exercise', 'Common pathologies seen in sport and/or exercise, including prevention strategies, etiologies, diagnoses, management approaches and possible complications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 371', 'Human Motor Control and Learning', 'Neural, musculoskeletal and psychological mechanisms underlying the control and learning of movement skills across the lifespan.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 375', 'Management of Sport/Exercise Emergencies', 'Catastrophic and life-threatening injuries and illnesses common to sport/exercise. Epidemiology, prevention strategies and management approaches.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 377', 'Principles of Musculoskeletal Rehabilitation', 'Theoretical foundation of the rehabilitation process for musculoskeletal injuries. Topics include the integration of therapeutic exercise and modalities to achieve specific rehabilitation goals across various patient populations and clinical settings.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 380', 'Philosophy of Human Movement', 'The philosophy of human movement in athletics, sport, kinesiology, play, dance and other human movement forms from ancient Greeks to the present. Philosophical theories of human movement relative to personal identity, reality, being, values and nature of competition.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 381', 'History of Sports, Games and Culture', 'Historical interpretations of the role of sport, games, play, dance and recreation in human life. Connections between sporting and movement practices, as well as the broader cultural, political, intellectual and economic patterns that have shaped societies throughout world history.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 383', 'Psychology of Sport and Physical Activity', 'Introduction to theory and research of psychological processes that influence human performance in numerous movement settings including sport, exercise, and rehabilitation. Individual difference variables, social psychological variables and assessment and intervention.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 384', 'Sport Sociology', 'Sport and social institutions and social processes. Understanding sport as a social phenomenon.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 385', 'Instructional Analysis of Human Movement', 'Variables and principles which contribute to effective observation, analysis and instruction of human movement skills across the life span.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 386', 'Movement and the Child', 'Characteristics of the child; physical growth and development; basic mechanical principles related to human movement and motor learning; and concepts related to the design of physical activity programs that are appropriately challenging for children at various developmental levels. SMPP-PE students require KNES 494.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 387', 'Movement and the Adolescent', 'Implement physical education programs at the secondary level. Cognitive, affective and psychomotor development; structure, concepts and principles related to human movement and motor learning; concepts related to the design of secondary school movement programs. SMPP-PE students require KNES 494.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 396', 'Physical Education Tutorial', 'Supervised experience in performance or laboratory situations through tutoring or assisting in instruction. May be repeated for a maximum of 6 units. A maximum of 3 units may be applied toward the major. Requires consent of instructor and tutorial adviser.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PUBH 405', 'Worksite Injury Prevention and Rehabilitation', 'How work style, equipment, and environment contribute to worksite musculoskeletal injuries. Strategies that can minimize human error, injuries, discomfort and dissatisfaction through injury prevention and rehabilitation of the worker.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 410', 'Issues in Youth Sports', 'Interdisciplinary examination of current trends and issues in youth sport, focusing on non-school based community programs. The structural characteristics of sport and physical activity programs as they pertain to proper development of children and adolescents.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 414', 'Legal Issues in Kinesiology', 'Introduction to the legal system and the law as applied to sport and exercise settings, including the areas of sports, fitness and healthcare and recreational activities; understanding the concepts of ethics, negligence and risk management.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 430', 'Applied Sport Psychology', 'Application of principles from sport psychology literature to enhance athletes’ and coaches’ performance.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 432', 'Applied Exercise Psychology', 'Understanding and applying the principles from exercise psychology to the promotion of physical activity in a variety of settings including preventive, clinical, community and rehabilitative programs.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 442', 'Teaching Physical Education', 'Objectives, methods and materials for teaching Physical Education K-12. Required before student teaching. Part of the 12-unit education block and may not be taken separately. A “B” (3.0) or better is required to earn a preliminary Single Subject credential.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 449S', 'Seminar in Secondary Teaching', 'Student teaching in a single subject in public schools. Credit/No Credit only. Requires a “B” (3.0) or better for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 450', 'Program Design for Strength and Conditioning', 'Outcomes associated with different strength training regimens. Periodization and planned variation of the acute program variables of frequency, intensity, volume and rest across cycles of training to prevent overtraining and promote peak performance.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 451', 'Sports Medicine', 'Various general medical pathologies, pharmacological issues and ergogenic aids related to sport/exercise.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 453', 'Clinical Exercise Physiology', 'Applying exercise physiology concepts to clinical/pathological situations in order to determine the therapeutic and functional benefits of physical activity.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 454', 'Physical Dimensions of Aging', 'Scientific evidence concerning the relationship between level of physical activity and physical, cognitive and psychosocial well-being during aging. Changes that occur during aging, changes related to inactive lifestyles, and the positive effects of an active lifestyle on preventing disease and disability.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 455', 'Functional Performance Assessment and Programming for Older Adults', 'Development of technical and personal skills related to functional performance assessment and to the development and implementation of physical activity programs for healthy and frail older adults.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 456', 'Environmental Exercis Physiology', 'Interrelationship between the physical environment and the human while exercising under different states of fitness and acclimatization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 457', 'Practice of Personal Training', 'Physiological responses and adaptations associated with strength and aerobic training to design fitness programs across the lifespan. Scientific foundation, client evaluation, exercise technique, safety and legal issues, program design and special populations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 458', 'Measurement Techniques in Strength and Conditioning', 'Understand theory, operate equipment and analyze resultant data related to endurance, strength and power testing. Exposure to a variety of assessment techniques commonly performed in strength and conditioning, biochemistry, and exercise physiology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 460', 'Worksite Health Promotion', 'Philosophy, rationale and guidelines for developing health promotion programs in the corporate setting. Unique considerations in assessing needs, planning and implementing programs, evaluating effectiveness and coordinating activities in the workplace are discussed. (PUBH 460 and KNES 460 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 461', 'Biomechanical Analysis of Human Movement', 'Analytical approach to mechanics of human motion. Quantitative video analysis techniques are introduced and applied to select movement analysis projects.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 463', 'Biomechanics of Musculoskeletal Injury', 'Biomechanical analysis of human movement patterns and how they are related to the development of various musculoskeletal injuries. Biomechanical assessment and correction for prevention and rehabilitation of musculoskeletal injury will also be developed.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 470', 'Nutrition for Exercise and Performance', 'Role of different nutrients (macro and micro) to provide energy during exercise, enhance performance and support recovery after exercise. Fluid replenishment, nutritional supplements, nutritional immunology and the female athlete.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 471', 'Motor Control and Movement Dysfunction', 'Contemporary motor control theories and how they are applied to the development of therapeutic exercise programs for children and adults with balance and movement disorders caused by disease and/or trauma to the neurological system.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 494', 'Practicum (1-3)', 'Planning, preparing, coaching, teaching in public school, college or community physical education or recreation programs. May be repeated for a maximum of six units. Credits not applicable toward major or graduate program. Credit/No Credit only. Requires consent of faculty sponsor, field supervisor, fieldwork coordinator, and department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 495', 'Internship in Kinesiology', 'Seminar for analysis of field experiences, including appropriate theory, skills and techniques, in addition to supervised experience in an approved fieldwork location agency. Internship must be specific to the discipline of kinesiology. Minimum of 120 hours per semester. Application forms must be completed and approved prior to enrollment. May not be repeated for credit toward the major. Requires consent of faculty sponsor, field supervisor, and fieldwork coordinator.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 499', 'Independent Study (1-3)', 'Topics based on a study plan prepared in cooperation with a faculty supervisor. Culminates in a paper, project, comprehensive examination. Application forms must be completed and approved prior to enrollment. Maximum of three units in any one semester; may be repeated once.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 508', 'Statistical Methods in Kinesiology', 'Statistical theory, data collection procedures, techniques for analysis and interpretation of data.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 510', 'Research Methods in Kinesiology', 'Fundamental tools of research. Types of research, process of scientific inquiry and critical analysis of research. Topic selection and development of a research proposal.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 516', 'Advanced Study of the Philosophical Perspective of Human Movement', 'Methods of the philosophical process of human movement.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 550', 'Graduate Internship', 'On-the-job training experiences supervised by a fully trained practitioner. Minimum of 120 hours per semester plus conferences with faculty sponsor. Application forms must be completed and approved prior to enrollment. Upon completion of the internship, a written evaluation must be submitted. Not open to students on, or subject to, academic notice. Requires consent of faculty sponsor, field supervisor, field coordinator and chair.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 555', 'Applied Strength and Conditioning', 'Anatomical and physiological bases for programs that develop physical fitness and performance.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 558', 'Advanced Study in Teaching Human Movement', 'Historical perspectives and current trends in pedagogical research and the resultant principles that undergird the science of teaching human movement.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 561', 'Advanced Study in Biomechanics', 'Advanced methods and concepts associated with the quantification of human movement. Biomechanical analysis of force plate and three-dimensional video data.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 571', 'Advanced Study in Human Motor Control and Learning', 'In-depth study of contemporary trends and issues in motor control/learning research. Application of research to practice.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 580', 'Advanced Study in Sport and Exercise Psychology', 'Current issues and research in sport and exercise psychology. Topics include motivation, personality, leadership and group dynamics, attention/concentration, exercise adherence/compliance, sport and exercise injury, and behavioral change strategies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 581', 'Consultation in Applied Sport Psychology', 'Factors related to effective consultation for enhancing athletic performance. Knowledge of consultation issues will be derived from the existing best practices and literature with the purpose of drawing practical applications for the new professional. May be repeated once for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 582', 'Advanced Study in Sociocultural Perspectives of Human Movement', 'In-depth study of the theories and methods of the sociocultural perspective and their application to the study of human movement phenomena.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 597', 'Project', 'Directed independent inquiry. Not open to students on, or subject to, academic notice. Requires classified graduate standing, successful completion of an oral presentation of the project, and signature of all committee members on or before the census date of the semester in which the student elects to enroll.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 598', 'Thesis', 'Student will select and have approved a research proposal, conduct the research, and prepare a formal analysis and report. Not open to students on, or subject to, academic probation. Requires classified graduate standing, successful completion of an oral presentation of the thesis, and signatures of all committee members on or before the census date of the semester in which the student elects to enroll.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KNES 599', 'Graduate Independent Research (1-3)', 'Student research in a specific area of human movement studies. Application forms must be completed and approved prior to enrollment. Upon completion of the research, a written report must be submitted. Not open to students on, or subject to, academic notice. May be repeated for a maximum of 3 units. Requires consent of the faculty adviser and chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LTAM 300', 'Topics in Latin America', 'Interdisciplinary examination and discussion of the history, geography, peoples and major issues of Latin America from pre-Colonial times to the present.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LTAM 350', 'Mexican Life and Culture', 'Introduction to Mexican culture and civilization. Contemporary Mexican society with focus on social, political, environmental, cultural and historical issues. Requires travel to La Paz, Baja California, Mexico and will only be offered in summer or intercession. Letter grade or Credit/No Credit. (LTAM 350 and CHIC 350 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LTAM 399', 'Directed Study (1-3)', 'Supervised individual or small group study as an elective. May be repeated with different topics for a maximum of 6 units. Requires approval of program coordinator.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 100', 'Introduction to the Humanities', 'Interdisciplinary introduction to the humanities as a set of related disciplines that apply conceptual, critical, historical and linguistic analyses to advance our understanding of what it means to be human.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 101', 'Introduction to the Social Sciences', 'Major topics in the social sciences in order to understand their systematic study of human behavior, to realize the connections among particular issues and approaches, and to reflect critically on modern life.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 301', 'Inquiry and Composition in Liberal Studies', 'Selected thematic interconnections between the arts and humanities, sciences and social sciences through reading, discussion and composition. Satisfies the upper-division writing course requirement for majors in Liberal Studies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 302A', 'Historical Dimension of Liberal Studies', 'Origins and development of modes of thought and forms of expression in the three core areas of liberal studies, i.e., the natural sciences, social sciences, and arts and humanities. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 302B', 'Historical Dimension of Liberal Studies', 'Origins and development of modes of thought and forms of expression in the three core areas of liberal studies, i.e., the natural sciences, social sciences, and arts and humanities.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 303', 'Liberal Studies in the Humanities and Arts', 'Interdisciplinary approach to the humanities and arts that examines their purposes, structures and major developments since 1900.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 304', 'Liberal Studies in the Sciences', 'Interdisciplinary introduction to the character and aims of 20th-century science, current theories and knowledge, and the role of science and technology in contemporary society.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 305', 'Liberal Studies in the Social Sciences', 'Interdisciplinary introduction to modern social science in which major thinkers, ideas, movements and problems will be approached historically, comparatively and analytically.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 310', 'The California Experience', 'Seven themes in California studies. Explores the California experience through readings, films and music, and three writing assignments that ask them to research one topic each in the arts/humanities, social sciences and natural sciences in California. (LBST 310 and HIST 310 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 315', 'A European Tour', 'Interdisciplinary introduction to the development of European civilization in the pre-modern period through an examination of select sites. The geographical and environmental context, the peopling of Europe and the evolution of cultural, political, economic and religious ideas and institutions. (HIST 315 and LBST 315 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 323', 'Cross-Cultural Humanities', 'Interdisciplinary exploration of the humanities through a series of questions humans have raised across cultures and historical periods. The commonalities of human concerns and the diversity and uniqueness of the answers given to them.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 331', 'History of Science: Copernicus to the Present', 'Science from the 16th century to the present, especially the scientific revolutions of the 17th and 20th centuries and the interaction between science, technology and culture. (HIST 331 and LBST 331 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 333', 'Evolution and Creation', 'Interdisciplinary study of evolutionary biology’s impact on culture in context of religious doctrines of creation. Evolutionary theory and religious and philosophical reactions from Darwin to the present, including relevant educational and legal contexts. (PHIL 333 and LBST 333 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 485', 'Senior Seminar in Cultural Diversity', 'Interdisciplinary study of the historical and cultural experiences of racial and ethnic groups in America. Student-led discussions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 486', 'Senior Seminar in Humanities and Arts', 'Interdisciplinary study of selected topics in the humanities and arts. Integrates and builds upon previous classes in Liberal Studies. Student-led discussions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 489', 'Senior Seminar in Gender Issues', 'Interdisciplinary study of gender issues in the modern period. Student-led discussions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 490', 'Senior Seminar in Great Books', 'Important books from early civilization to the present. Develops critical reading of texts, clear expression of ideas and integration of knowledge. Student-led discussions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 491', 'Senior Seminar in Literature and Sciences', 'Interdisciplinary examination of the relationships between literary and scientific communities, and of literature as a forum for the critique, appraisal and assessment of science in culture.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LBST 499', 'Independent Study (1-3)', 'Individually supervised studies and/or projects. May be repeated for a maximum of 6 units. Department consent and approval by the Liberal Studies department chair required.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 102', 'Languages of the World', 'The world’s 7,000 languages, highlighting their structural variety, history and use. Preserving the endangered languages and the development of language as a universal human cognitive capacity.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 106', 'Language and Linguistics', 'Nature of language, its origin and development; language in culture, the structure of language and its systems of writing and transcription, and its application to other areas of humanistic and scientific knowledge.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 206', 'Introduction to Language Structure and Language Use', 'Introduction to the nature, structure, development and use of English. How sounds are articulated and patterned in meaningful units (phonology); symbolic correspondence (phonics); rules of word formation (morphology); word history (etymology); and language use (pragmatics). (ENGL 206 and LING 206 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 305', 'The English Language in America', 'American English, its origins, regional and social dialects and role in American history and in such institutions as schools, corporations, government and media. Requirement for application to English Teaching Credential. (ENGL 305 and LING 305 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 307', 'Speech/Language Development', 'Normal acquisition of phonology, morphology, semantics, syntax and pragmatics in children. Biological, cognitive and social bases of language acquisition. Meets the requirements for specialized preparation to serve as a teacher of exceptional children. (COMD 307 and LING 307 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 351', 'Introduction to Linguistic Phonetics and Phonology', 'Nature and structure of sound systems in language. Thorough investigation of the International Phonetic Alphabet as applied to many different languages including English. Language Acquisition (L1) and Language Learning (L2); analytic methods and techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 360', 'Nonverbal Communication', 'Physical actions, gestures and changes in the physiognomy that occur together with language and paralanguage in human communication; substitutions for language and modifications of it in varying cultures. (LING 360 and HCOM 360 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 406', 'Descriptive Linguistics', 'Sounds (phonology), forms and meanings (morphology), and syntax of languages. Examples and problem-solving in various languages. (LING 406 and ANTH 406 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 408', 'Syntax', 'Sentence structure in human language. Practice in syntactic analysis in a variety of languages.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 412', 'Sociolinguistics', 'Social dialects in relation to the surrounding communities. Social stratification, acculturation, language maintenance, standardization, language planning and language change.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 413', 'Language Acquisition', 'Child language acquisition from birth to adult proficiency; stages and variation in child language; comparison of first- and second-language acquisition; current theories of language acquisition.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 416', 'Anthropological Linguistics', 'Nature and functions of language; language structure and change; classification of languages; use of linguistic evidence in anthropology. (ANTH 416 and LING 416 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 417', 'Psycholinguistics', 'Theory and research on the psychological processes that make possible language acquisition and written language; speech production; and language acquisition. (PSYC 417 and LING 417 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 430', 'Historical Linguistics', 'Comparative method in diachronic linguistic methodology and theory, graphemics, glottochronology, language families, dialect geography and internal reconstruction. Fulfills the upper-division baccalaureate writing requirement for linguistics majors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 442', 'Changing Words: History, Semantics and Translation', 'Etymology, related problems of lexicography and translation. Recent developments in theory of semantic change as related to cultural shifts. Emphasizes words, collocations, idioms. (LING 442 and ENGL 442 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 492', 'Linguistic Fieldwork', 'Methodology and practice of linguistic analysis and language description as practiced in the field. Data collection and processing of a non-Indo-European linguistic structure using native informants. Students can take a maximum of 6 units as an Undergraduate and 6 units as a Graduate student.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 499', 'Independent Study (1-3)', 'Supervised projects with consent of program coordinator. Topic varies with the student. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 501', 'Research Methods and Bibliography', 'Principal books, periodicals and collections in general linguistics, specific languages and related fields; techniques of preparing research papers and field reports in linguistics. Must be taken prior to LING 597.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 505', 'Phonological Analysis', 'Phonological systems that occur in languages; emphasizes terminology used to describe changes in the system and processes affecting it; problem solving of selected language date.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 507', 'Grammatical Analysis', 'Word formation in a variety of languages with emphasis on the terminology used to describe morphological representation on various levels; problem solving of selected language data. (LING 507 and ANTH 507 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 508', 'Theories of Syntax', 'Contemporary theories of grammar, such as transformational-generative, with emphasis on theoretical problems in the analysis of language structure.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 530', 'Graduate Seminar: Historical Linguistics', 'History of language, including principles and techniques for the historical study and classification of individual languages and language families, writing systems, lexicostatistical methods and linguistic geography.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 597', 'Project', 'Preparation and completion of an approved project', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('LING 599', 'Independent Graduate Research (1-3)', 'May be taken for credit for a maximum of six units. Requires consent of program coordinator.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 246', 'Business and Its Legal Environment', 'Federal, state and international laws and ethical issues affecting business, including the legal system, litigation and alternative dispute resolution, the Constitution, torts, criminal law, contracts, various forms of business organizations, employment laws and discrimination, and consumer and environmental protection.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 335', 'Family Business Dynamics', 'The unique challenge of managing and growing family businesses. Explore strategic, organizational and interpersonal issues associated with family businesses through real-world cases and projects. Requires completion of lower-division business core.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 339', 'Managing Operations', 'Integrates selected general management concepts with operations management concepts and techniques. Emphasizes the development of competencies required for effective planning, designing, operating, controlling and improving processes that produce and deliver quality goods and services. Co-requisites: BUAD 301, ISDS 361A; International Business major - BUAD 301; Business Minor - MGMT 246.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 340', 'Organizational Behavior', 'Individual, group and organizational influences on human behavior in organizations. Topics include personality and emotions, motivation, decision-making, group and team effectiveness, leadership, power and politics, organizational culture and change. Co-requisites: BUAD 301, ISDS 361A; International Business major - BUAD 301; Business Minor - MGMT 246.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 346', 'International Law for Business', 'International laws and ethical issues affecting businesses including: the WTO and UN; international agreements, treaties and regional organizations (e.g., EU, NAFTA); international contracts; and national and international regulation of imports, exports and competition.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 348', 'Commercial Law', 'Philosophy, institutions and role of law and ethical considerations in commercial transactions. Case studies in sales, storage and shipment of goods, commercial paper, debtor and creditor rights and remedies, bankruptcy, secured transactions and suretyship.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 349', 'Law for Small Business', 'Federal and state laws and ethical issues affecting small businesses (e.g., sole proprietorships), including litigation involving negligence, product liability, discrimination, consumer protection and workers’ compensation claims.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 350', 'International Business and Management', 'Fundamental course in international business and international management. Overview of international business, and emphasizes a managerial approach that involves examining the various roles of managers in an international setting. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 422', 'Operations Planning and Control', 'Analytical approach to explore planning and scheduling material, capital and human resources to meet customer demand. Topics include master scheduling, material requirements planning/ERP, production activity control, inventory management, warehouse management and physical distribution.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 423', 'Purchasing and Supply Management', 'Operational and strategic role of purchasing/supply management in organizations. Develops skills and knowledge in supplier selection/evaluation, negotiation, cost/price analysis, contract management, global sourcing, commodity analysis, value analysis. Exercises, cases, guest speakers.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 425', 'Quality Management', 'Measurement and improvement of productivity and quality in organizations. Problem-solving and process management tools. Case analyses and research projects address issues of people and technology. How to improve your organization: manufacturing or service, department or company.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 430', 'Supply Chain Management', 'Managing materials, capital and information flows throughout multiple organizations in a supply chain from acquisition of materials to delivery of finished goods and services to the final customers. Presentation and case studies on various issues in supply chain management.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 432', 'Staffing', 'Theories and techniques related to employee staffing. Topics include the planning, legal issues, job analysis, measurement, internal and external recruitment and selection, and decision-making.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 434', 'Compensation', 'Developing equitable compensation and benefit programs in order to retain a productive workforce. Topics include job analysis and evaluation, pay structures, salary survey, individual compensation, incentive systems and benefits.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 435', 'Management of Service Organizations', 'Develop skills to successfully manage service businesses. Topics include managing service firms through integration with operations, strategy, marketing, technology and organizational issues. Provides theory, tools and experiential insight into how these aspects can be successfully used in a service-oriented business.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 436', 'Training and Development', 'Theoretical and practical issues involved in designing and implementing training and development programs in work organizations. Topics include planning, designing and delivering training interventions, and evaluating training effectiveness.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 440', 'Business and Society', 'Open to nonbusiness majors. Analyze and interpret real-world interrelationships between firms and their external environments. Contemporary and emerging trends in areas, such as technology, politics, economics, natural environment, business ethics and other societal aspects.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 441', 'Labor-Management Relations', 'Impact of labor-management relations upon labor, management and the public. Proper grievance procedure, collective bargaining and settlement of disputes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 443', 'Team Leadership Skills', 'Interpersonal skills required to lead teams effectively. Topics include self-awareness, managing stress, creative problem-solving, communicating supportively, effective use of power and influence, motivating others, managing conflict, empowering employees, building effective teams, leading positive change.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 444', 'Project Management', 'Principles and techniques of effective project management. Managerial, organizational and behavioral concepts, as well as effective tools, techniques and software for planning, communications, coordination and control of the project.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 445', 'Employment Law', 'Federal and state laws, and ethical issues affecting employment relationships and discrimination. Topics include the laws of agency and employees, independent contractors, the hiring process and procedures, wages, hours, benefits, termination of employment, OSHA and workers’ compensation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 446', 'Entertainment Business Law', 'Overview of entertainment industry legal issues in media, publishing, recording and hospitality enterprises. Topics include intellectual property, contracts, labor union representation and government regulation.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 447', 'Internet Legal Issues', 'Federal, state and international laws and ethical issues affecting business and the Internet/information technology, including intellectual property (patents, copyrights, trademarks and trade secrets), e-commerce, online contracting, taxation, privacy, obscenity, defamation, information security and network crimes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 516', 'Operations Management', 'Role of operations function in designing, producing and delivering products and services in manufacturing and service firms. Includes strategy and processes to meet market needs, internal and external coordination in a supply chain, long- and short-term decision-making tools and techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 518', 'Legal and Ethical Environment of Business', 'Federal, state and international laws and ethical issues affecting business, including criminal law, contracts, the Uniform Commercial Code, torts and product liability, employment relationships and discrimination, and various kinds of business organizations, such as corporations, LLC, partnerships and sole proprietorships.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 524', 'Seminar in Organizational Behavior', 'Understanding and predicting human behavior to enhance individual, team and organizational performance. Applying effective principles of motivation, team building, influence, leadership and conflict management.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 525', 'Seminar in Team Leadership Skills', 'Graduate seminar to develop hands-on skills to lead high-performance work teams. Topics include self-awareness, stress management, valuing diversity, supportive communication, creative problem solving, influence and leadership, motivating others, managing conflict, empowering and building effective teams.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 539', 'Supply Chain Management', 'Effective supply chain strategies emphasizing how to plan and integrate supply chain components into a coordinated system. Concepts and models important in supply chain planning. Risk pooling and inventory placement, integrated planning and collaboration and information sharing. Various models and methods for supply chain analysis and optimization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 540', 'Leading and Managing People in Entrepreneurial Organizations', 'Prepares managers to analyze organizational policies, procedures and culture to improve employee productivity and effectiveness. Explores leadership skills needed to execute these changes. Includes a consulting project that applies student learning to a small and/or entrepreneurial organization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 543', 'Seminar in Human Resource Management', 'Cases, problems and significant personnel administration literature in personnel administration and human relations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 582', 'Leading Organizational Change', 'Develop executive-level capabilities to lead, manage and implement organizational change. Build change leadership skills through exposure to a variety of industries, organizations and decision-making scenarios.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 585', 'Negotiation', 'Builds on knowledge of individual behavior and social perception with a key focus on integrative bargaining strategies and tactics. Aims to help argue for goals more persuasively, while also enriching others’ goals.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MGMT 599', 'Independent Graduate Research (1-3)', 'May be repeated for a maximum of 6 units. Not open to students on academic notice. Requires consent of instructor, department chair and associate dean.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 351', 'Principles of Marketing', 'Applying current theories and concepts in effectively marketing goods and services to define target customers from a domestic and global perspective. Includes market research, identifying target customers, developing product offers, branding, pricing, marketing communications and distribution channels.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 443', 'Marketing Analytics: Decision Making in the Information Age', 'Applying analysis and modeling techniques to a broad range of marketing decision making domains. (MKTG 443 and ISDS 443 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 455', 'Digital Marketing', 'Marketing goods, services and ideas on the Internet. Integrating e-commerce into a total marketing strategy for businesses ranging from entrepreneurial to multinational corporations. History and emergence of e-commerce, utility of the Internet as a tool to increase effectiveness, efficacy and competitiveness.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 465', 'Managing Services Marketing', 'Unique marketing needs and challenges faced by service firms in an increasingly challenging global environment. Strategies for marketing services in a variety of industries: entertainment, tourism, hospitality, health care, financial services. Strategies used by manufacturing firms using service as a competitive strategy.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 489', 'Developing Marketing Strategies', 'Developing marketing strategies involving products as well as services. Case analysis and group interaction. Students will finalize and present portfolio of projects and internships completed over the duration of marketing program.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 495', 'Internship (1-3)', 'Planned and supervised work experience. May be repeated once for credit. Consent of department chair and one semester in residence at Cal State Fullerton required.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 499', 'Independent Study (1-3)', 'Open to undergraduate students desiring to pursue directed independent inquiry. May be repeated for a maximum of 6 units. Not open to students on academic notice. Requires approval by Department Chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 519', 'Marketing Management', 'Key marketing concepts and their applications to marketing research, segmentation, selecting target markets, product development, pricing, promotion and distribution. Develops senior-level executive decision-making skills from global, ethical and socially responsible perspectives. Requires understanding and application in a major project.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 565', 'Strategic Market Intelligence', 'Qualitative and quantitative methods for collecting and analyzing information about customers and competitors. Apply these techniques and learn how market information can be leveraged to make better strategic decisions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 596T', 'Contemporary Topics in Marketing', 'Frameworks and practices for the 21st-century U.S. marketer. How to develop brand strategy and drive competitive advantage in an increasingly diverse marketplace through case studies, discussions and guest speakers.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MKTG 599', 'Independent Graduate Research (1-3)', 'May be repeated for a maximum of 6 units. Not open to students on academic notice. Requires consent of instructor, department chair and associate dean.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 115W', 'College Algebra Workshop', 'Supplementary problem-solving workshop in a collegial setting. May be repeated once for credit.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 120', 'Elementary Statistics', 'Explore and analyze data with real-world applications. Design surveys and experiments. Graphical and numerical summaries. Correlation, regression and analysis of contingency tables. Confidence intervals and hypothesis testing via simulation and using normal, t, chi-squared distributions. For students who require a support course:', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 125', 'Precalculus', 'For students planning to take MATH 150A. Functions and their use in mathematical models, including linear functions, polynomial and rational functions, exponential and logarithmic functions, and trigonometric functions. If a student takes MATH 115 and MATH 125 and earns a “C” or better in both courses, the second course receives credit. If the student earns a “C” or better in one of the two courses, credit is given for the course successfully completed. Please see advisor for Math placement if unable to enroll.', 5, 5, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 125W', 'Precalculus Workshop', 'Supplementary problem-solving workshop in a collegial setting.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 130', 'Calculus for the Natural Sciences', 'Survey differential and integral calculus, emphasizing applications for the natural sciences. If a student takes MATH 130 and MATH 135 and receives a “C” (2.0) or better in both courses, the second course receives credit. If the student receives a “C” (2.0) or better in only one of the courses, credit is given for that course.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 130W', 'A Short Course in Calculus Workshop', 'Supplementary instruction student-centered workshop focusing on problem-solving in calculus.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 135', 'Business Calculus', 'Survey of differential and integral calculus with applications, including derivatives, integrals and max-min problems. For students of business and economics. If a student takes MATH 130 and MATH 135 and earns a C or better in both courses, the second course receives credit. If the student only succeeds in one of the two courses, then credit is given for the course successfully completed. Six units of credit are given if both MATH 135 and MATH 150A are taken.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 135W', 'Business Calculus Workshop', 'Supplementary instruction student-centered workshop focusing on problem-solving in business calculus.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 150A', 'Calculus I', NULL, 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 150B', 'Calculus II', 'Techniques of integration, improper integrals and applications of integration. Introduction to differential equations. Parametric equations, sequences and series.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 151A', 'Calculus I Workshop', 'Supplementary problem-solving in a collegial setting.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 151B', 'Calculus II Workshop', 'Supplementary problem-solving in a collegial setting.', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 196', 'Student-to-Student Tutorials (1-3)', 'Consult “Student-to-Student Tutorials” in this catalog for more complete course description. May be taken Credit/No Credit only.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 250A', 'Calculus III', 'Calculus of functions of several variables. Partial derivatives and multiple integrals with applications. Parametric curves, vector-valued functions, vector fields, line integrals, Green’s Theorem, Stokes’ theorem, the Divergence Theorem, vectors and the geometry of 3-space.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 250B', 'Introduction to Linear Algebra and Differential Equations', 'Introduction to the solutions of ordinary differential equations and their relationship to linear algebra. Topics include matrix algebra, systems of linear equations, vector spaces, linear independence, linear transformations and eigenvalues.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 170A', 'Mathematical Structures I', 'First of two semesters of fundamental discrete mathematical concepts and techniques needed in computer-related disciplines. Logic, truth tables, elementary set theory, proof techniques, combinatorics, Boolean algebra, recursion and graph theory. Must have completed four years of high school mathematics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 170B', 'Mathematical Structures II', 'Second of two semesters of fundamental discrete mathematical concepts and techniques needed in computer-related disciplines, focusing on linear algebra.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 280', 'Strategies of Proof', 'Logic, set theory and methods for constructing proofs of mathematical statements. A bridge to the rigors of upper-division mathematics courses containing significant abstract content.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 302', 'Modern Algebra', 'Integers, rational numbers, real and complex numbers, polynomial domains, introduction to groups, rings, integral domains and fields.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 303A', 'Fundamental Concepts of Elementary Mathematics', 'Structure and form of the mathematics that constitutes the core of the K-8 mathematics curriculum, including number sense, number theory and problem solving.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 303B', 'Fundamental Concepts of Elementary Mathematics', 'Structure and form of the mathematics that constitutes the core of the K-8 mathematics curriculum, including the real number system, geometry, probability and statistics and problem solving.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 306', 'Vector and Tensor Analysis', 'Vector analysis, including coordinate bases, gradient, divergence and curl, Green’s, Gauss’ and Stokes’ theorems. Tensor analysis, including the metric tensor, Christoffel symbols and Riemann curvature tensor. Applications will be drawn from differential geometry, continuum mechanics, electromagnetism, general relativity theory.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 307', 'Linear Algebra', 'Theoretical aspects of abstract vector spaces. Linear transformations: isomorphisms, matrix representations, change of coordinates, eigenvalues and eigenvectors, diagonalizability, Jordan canonical form. Theoretical aspects of inner product spaces.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 310', 'Ordinary Differential Equations', 'Theory and methods of solutions for ordinary differential equations, including Laplace transform methods and power series methods. Oscillation theory for second order linear differential equations and/or theory for systems of linear and nonlinear differential equations.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 320', 'Introduction to Mathematical Computation', 'Introduction to problem-solving on the computer using modern interactive software. Numerical and symbolic computation. Variety of problems arising in mathematics, science and engineering. Also serves as preparation for subsequent computer-based courses in mathematical modeling.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 335', 'Mathematical Probability', 'Probability theory; discrete, continuous and multivariate probability distributions, independence, conditional probability distribution, expectation, moment generating functions, functions of random variables and the central limit theorem.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 338', 'Statistics Applied to Natural Sciences', 'Introduction to the theory and application of statistics. Elementary probability, estimation, hypothesis testing, regression, variance analysis, non-parametric tests. Computer-aided analysis of real data. Graphical techniques, generating and interpreting statistical output, presentation of analysis.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 340', 'Numerical Analysis', 'Approximate numerical solutions of systems of linear and nonlinear equations, interpolation theory, numerical differentiation and integration, numerical solution of ordinary differential equations. Computer coding of numerical methods.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 350', 'Advanced Calculus I', 'Development of the theoretical foundations of calculus with an emphasis on mathematical rigor and formal proof. Algebraic and topological properties of the real numbers; limits of sequences and functions; continuity, differentiation and integration of functions of one variable; infinite series.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 370', 'Mathematical Model Building', 'Introduction to mathematical models in science and engineering. Dimensional analysis, discrete and continuous dynamical systems, and numerous other topics. Emphasizes deriving equations and using mathematical tools to make predictions.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 380', 'History of Mathematics', 'History of mathematics through its methods and concepts. Designed to help the student become proficient in writing and reading mathematical literature. Satisfies the upper-division writing requirement for mathematics majors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 401', 'Algebra and Probability for the Secondary Teacher', 'Mathematical topics relevant to the teacher of secondary mathematics. Problem-solving approach to different areas including algebra, number theory, combinatorics and probability, while maintaining a historical perspective.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 402', 'Logic and Geometry for the Secondary Teacher', 'Parallel to MATH 401, but emphasizing Euclidean geometry, logic and problem-solving from a historical perspective.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 403A', 'Fundamental Concepts of Middle School Mathematics I', 'Content background in mathematics to help satisfy credentialing requirements for teaching mathematics at the middle school level. Gaining a thorough understanding of algebra, including patterns, functions and the use of technology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 403B', 'Fundamental Concepts of Middle School Mathematics II', 'Content background in mathematics to help satisfy credentialing requirements for teaching mathematics at the middle school level. Focuses on gaining a thorough understanding of advanced algebra, geometry, probability and statistics and the use of technology.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 406', 'Introduction to Partial Differential Equations', 'First order linear and quasi-linear partial differential equations. Classification of second order linear partial differential equations. Divergence theorem, Green’s identities, Fourier analysis, Sturm-Liouville theory, integral transforms and their application to boundary-value problems for the potential, wave, and diffusion equations.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 407', 'Abstract Algebra', 'Sets, mappings, groups, rings, modules, fields, homomorphisms, advanced topics in vector spaces and theory of linear transformations, matrices, algebras, ideals, field theory, Galois theory.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 412', 'Complex Analysis', 'Complex differentiation and integration, Cauchy’s theorem and integral formulas, maximum modulus theorem, harmonic functions, Laurent series, analytic continuation, entire and meromorphic functions, conformal transformations and special functions.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 414', 'Topology', 'Topological spaces and continuous functions, connectedness and compactness, metric spaces and function spaces.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 417', 'Foundations of Geometry', 'Foundations of Euclidean and non-Euclidean geometries through transformations and formal axiomatics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 425', 'Differential Geometry', 'Differential geometry of curves and surfaces. Frenet-Seret formulas, Gauss-Weingarten equations, Gauss-Bonnet theorem.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 430', 'Number Theory', 'Basic concepts of classical number theory with modern applications. Divisibility, congruences. Diophantine approximations and equations, primitive roots, continued fractions. Applications to public key cyprotography, primality testing, factoring methods and check digits.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 435', 'Mathematical Statistics', 'Introduction to mathematical statistics, emphasizing statistical estimation and hypothesis testing. Theory and applications. Begin with a condensed review of fundamental concepts from MATH 335; particularly, important discrete and continuous probability distributions.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 438', 'Introduction to Stochastic Processes', 'Stochastic processes, including Markov chains, Poisson Process, Wiener Process. Applications to birth and death processes and queuing theory.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 439', 'Intermediate Data Analysis', 'Simple and multiple linear regression, testing hypotheses, dummy variables, ANOVA, ANCOVA, confounding and interaction, diagnostics, influence and outliers, transformation and weighting and model selection. Introductory nonlinear and logistic regression. Use R statistical software.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 440', 'Advanced Numerical Analysis', 'Advanced topics in numerical analysis selected from iterative methods for linear systems, approximation of eigenvalues and eigenvectors, numerical methods for ordinary and partial differential equations, optimization methods and approximation theory, emphasizing error and convergence analysis and computer coding.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 450', 'Advanced Calculus II', 'Sequences and series of functions. Continuity, differentiation and integration of functions of several variables. Advanced topics in analysis, such as Lebesgue integration or the theory of metric spaces.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 470', 'Advanced Mathematical Model Building', 'Capstone course for students with strong mathematical preparation. Stochastic processes, Monte Carlo integration, differential equations, nonlinear dynamics, perturbation methods, and/or numerical techniques. Develops mathematical tools and approaches for modeling phenomena observed in applications.', 4, 4, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 471', 'Combinatorics', 'Analyze discrete structures, including existence, enumeration, and optimization. Permutations and combinations, combinatorial identities, the inclusion-exclusion principle, recurrence relations, Polya counting. Basic definitions and properties of graphs, Eulerian and Hamiltonian graphs, trees, graph colorings and chromatic number, planar graphs.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 480M', 'MARC Proseminar', 'Intended to increase the contact of MARC Fellows with minority scientists of national repute who will present seminars. Fellows will read and discuss relevant primary literature, attend the seminars, and meet with speakers before and after the seminars. May be repeated for a maximum of 4 units. Requires selection as a MARC Fellow. (BIOL 480M, CHEM 480M and PSYC 480M are the same course.)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 500A', 'Advanced Linear Algebra and Applications', 'Topics and computational methods from linear algebra useful in graduate studies in applied mathematics. Finite and infinite dimensional vector spaces, linear transformations and matrices. Introduction to Hilbert spaces. Projection theorem and some of its applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 500B', 'Applied Analysis', 'Topics from analysis useful in graduate studies in applied mathematics. Topics may include initial and boundary value problems, including series solutions, eigenvalues and eigenfunctions, Fourier analysis, generalized functions, an introduction to the calculus of variations, and transform methods.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 495', 'Internship in Applied Mathematics (1-3)', 'Work experience in advanced mathematics through positions in business, industry or government. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 496', 'Student-to-Student Tutorials (1-3)', 'Consult “Student-to-Student Tutorials” in this catalog for more complete course description. May be repeated for a maximum of 3 units. May be taken Credit/No Credit only.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 497', 'Undergraduate Research (1-3)', 'Methods of research in the mathematical sciences through a research project supervised by a departmental faculty member. May be repeated for a maximum of 9 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 498', 'Senior Thesis', 'Preparation, presentation and defense of a thesis. Topic approved by the undergraduate research committee. Thesis formatted in accordance with journal in field. May not be repeated for credit.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 499', 'Independent Study (1-3)', 'Special topic in mathematics, selected in consultation with and completed under supervision of instructor. May be repeated for a maximum of 9 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 501A', 'Foundations of Numerical Analysis', 'Numerical methods for linear and nonlinear systems of equations, eigenvalue problems. Interpolation and approximation, spline functions, numerical differentiation, integration and function evaluation. Error analysis, comparison, limitations of algorithms.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 501B', 'Scientific Computing and Applications', 'Numerical methods for initial and boundary-value problems for ordinary and partial differential equations. The finite element method. Error analysis, comparison, limitations of algorithms.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 502A', 'Foundations of Probability and Statistics', 'Theory and applications of probability models including univariate and multivariate distributions; expectations and transformations of random variables.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 502B', 'Computational Statistics and Data Analysis', 'Theory and applications of sampling theory, statistical estimation and hypothesis testing. Topics may include machine learning and data analysis techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 503A', 'Mathematical Modeling', 'Mathematical modeling concepts. Topics may include: dimensional analysis, scaling and sensitivity; system concepts, state space, observability, controllability and feedback; dynamical systems, models and stability analysis; optimization models.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 503B', 'Parameter Estimation and Inverse Problems', 'Development and analysis of mathematical models in such areas as mechanics, economic planning, operations management, environmental and ecological sciences, biology and medicine.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 534', 'Statistical Computing', 'Numerical methods in linear and nonlinear regression including Gauss-Jordan, QR, and Gauss-Newton algorithms. Maximum likelihood computation, including Newton, Fisher-scoring, quasi-Newton, and EM algorithms. Bayesian computations, including numerical integration, Monte-Carlo integration, and Markov chain Monte Carlo. Nonparametric inference including Bootstrap.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 536', 'Categorical Data Analysis', 'Inference for two-way contingency tables, generalized linear models, logistic regression, logit and probit models, log-linear models, model fitting and estimation of log-linear parameters, strategies in model selection, log-linear models for ordinal variables, Poisson regression and Poisson log-linear models.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 537', 'Multivariate Analysis', 'Multivariate normal distribution, comparison of several multivariate means, multivariate linear regression models, elliptically contoured distributions, estimation of orthogonal and oblique factors, inference for structured covariance matrices, simultaneous equation models, classification functions, procrustes analysis and graphical models.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 538', 'Bayesian Statistics', 'Fundamentals of Bayesian inference including informative and noninformative priors for single and multiparameter models, Bayesian asymptotics, hierarchical models, Metropolis Hastings and Gibbs sampler algorithms, model checking, Bayesian design of experiments, Bayesian linear models and generalized linear models, and neural networks.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 539', 'Statistical Consulting', 'Ethics, the communication aspects of consulting with clients, the formulation of statistical problems, recommendations of design protocols, selection of appropriate statistical methods, data analysis and interpretations of results including writing proper reports. Course based on case studies.', 6, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 581', 'Studies in Geometry', 'Topics relating to the high school curriculum from an advanced standpoint, including the axiomatic method and non-Euclidean geometry.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 582', 'Studies in Algebra', 'Topics relating to the high school curriculum from an advanced standpoint including algorithms, fields and polynomials.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 583', 'Studies in Statistics', 'Calculus-based course designed to teach appropriate strategies and tools to effectively address problems in statistics. Project design, exploratory data analysis and interpretation, and effective communication of results.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 584', 'Studies in Analysis', 'Topics relating to the high school curriculum from an advanced standpoint, including limits, continuity, differentiation and integration.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 586', 'Studies in Discrete Mathematics', 'Topics relating to the high school curriculum from an advanced standpoint, including induction, recursion, probability and combinatorics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 587', 'Studies in Mathematical Problem Solving', 'Problem solving via non-routine and enrichment-type problems from several different branches of mathematics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 597', 'Industrial Project in Computational Applied Mathematics (3-6)', 'May be repeated for credit. Students in the Applied Master’s Program may take for credit for a maximum of 6 units.', 3, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MATH 599', 'Independent Graduate Research (1-3)', 'Normally taken in conjunction with required graduate courses. Also offered without being attached to any course. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MAED 442', 'Teaching Mathematics in Secondary School', 'Research, standards, objectives, technology and methods for teaching mathematics. Required of mathematics majors for the general single subject credential. (2 hours lecture, 2 hours activity)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MAED 449S', 'Seminar in Secondary Teaching', 'See description under Department of Secondary Education.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MAED 499', 'Independent Study (1-3)', 'Special topic in mathematics education, selected in consultation with and completed under supervision of the instructor. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MAED 532', 'Teaching Problem Solving in Middle School Mathematics', 'Seminar to explore techniques of problem-solving for mathematics teachers of grades 5-9. Review of research on problem solving at the middle school level. Review of state and national documents on middle school mathematics education. Emphasis on problem-solving in algebra, geometry, and probability.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MAED 542', 'Teaching Mathematics at the College Level', 'Strengthens student effectiveness in teaching mathematics at the college level. Strategies that promote student engagement, collaboration, retention and success, as well as appropriate use of technologies.', 0, 0, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 102', 'Engineering Graphics', 'Sketching, Visualization, Geometry, CAD principles and applications. Orthographic projections, pictorials. Multiview drawing, including auxiliary, section and detail views. Standards and conventions. Dimensioning, tolerances, GDT. Design processes, cost analysis and freshman project. (1 hour lecture, 3 hours laboratory).', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 205', 'Digital Computation', 'Computers and their numerical applications. Programming languages, MathCAD, spreadsheet, digital computation methods in statistics and solving algebraic equations. Applications of general purpose software for engineering analysis. (EGME 205 and EGGN 205 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 304', 'Thermodynamics', 'Energy and its transformation; heat and work; conservation of mass and energy, system properties, irreversibility and availability. Ideal gases, heat engines and refrigeration (both ideal and actual), equipment selection and sizing.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 306A', 'Solid Mechanics Laboratory', 'Static and dynamic measurements (tension and strain test tension beams, columns, charpy, gyroscopes) using mechanical and electrical transducers. Using computers in data acquisition, reduction and analysis. Requires a complete set of reports, and must be passed with a “C” (2.0) or better. (3 hours laboratory)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 306B', 'Fluids and Thermal Laboratory', 'Continuation of EGME 306A. Flow, temperature and pressure measurement. Experimental studies of fluid friction and heat exchanger performance. Using computers in data acquisition, reduction and analysis. Requires a complete set of technical reports, and must be passed with a “C” (2.0) or better. (3 hours laboratory)', 1, 1, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 308', 'Engineering Analysis', 'Fundamentals and engineering applications of Fourier transforms, Laplace transforms, complex analysis, vector analysis; engineering applications. (EGCE 308, EGEC 308, EGGN 308 and EGME 308 are the same course.)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 315', 'Basic Fabrication Techniques and Manufacturing Practices', 'Conventional fabrication techniques, measuring, referencing and tolerances applied to manufacturing such as tooling, computer numerical control machining and process indices. Safety instruction for use of campus machine shop equipment. (2 hours discussion and 2 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 322L', 'Introduction to Computer-Aided Design', 'Introduction to modeling, assembly, design documentation and analysis using typical commercial CAD/CAE software. Using online resources in the collaborative design process. Design file transfer protocols. Design project using a technology based team environment. CAD/CAE system selection criteria. (1 hour discussion, 5 hours laboratory)', 3, 3, TRUE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 331', 'Solid Mechanics', 'Mechanical properties of materials. Stress and strain. Elastic, plastic and thermal deformation, and failure criteria. Stress-strain relationships, stress-strain transformation, principal stresses, Mohr’s circle. Analysis and design of beams for bending. Buckling of columns. Pressure vessels.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 333', 'Fluid Mechanics', 'Principles of fluid mechanics and their applications; fluid properties; fluid statics; one-dimensional incompressible flow; concepts of multi-dimensional flows including conservation principles; similitude and dimensional analysis; internal and external viscous flow; elements of compressible flow; design considerations in fluid mechanics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 335', 'Kinematics of Mechanisms', 'Kinematics and dynamics of mechanisms; design and analysis of linkages, gears, and cams through the use of analytical, graphical and computer-aided techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 407', 'Heat Transfer', 'Principles of heat transfer and their applications: introduction to conductive, convective and radiation heat transfer; one-dimensional heat conduction; concepts of multi-dimensional conduction; convective heat transfer for internal and external viscous flows; cross-flow and shell and tube heat exchangers; thermal system design.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 410', 'Introduction to the Finite Element Method and Applications', 'Basic concepts of integral and matrix formulation of boundary value problems. One dimensional finite element formulation of heat transfer, truss beam and vibration problems. Applications of commercial finite element programs. Selection criteria for code, element and hardware. CAD system interfaces.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 411', 'Mechanical Control Systems', 'Mechanical control system design and analysis. Pneumatic, hydraulic, electromechanical actuators and devices. Stability criteria, root locus plots, frequency response analysis and design, transfer functions, introduction to feedback control and microprocessor applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 414', 'Design Project I', 'Design methodology, CAD/CAE philosophy, optimization, product liability, probability/statistical principles, ASME codes, safety, human factors, material selection, legal aspects of design, professional ethics. Design project to be constructed in EGME 419, but feasibility study, preliminary design, assembly drawings, interim and final written project reports, interim and final oral presentations are required for EGME 414. (1 hour lecture and 6 hours laboratory)', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 417', 'Computational Heat Transfer', 'Computer visualization of 2-D/3-D temperature fields. Steady and unsteady conduction heat transfer. Incompressible free and forced convective boundary layer flows. Multiple surface radiation analysis. Boiling and condensation. Design aspects of computational heat transfer and use of CFD codes.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 418', 'Space and Rocket Engineering', 'Principles of rocket propulsion systems. Single and multi-stage rockets. Theory and application of orbital mechanics. Space flight maneuvers. Boosting a satellite into orbit. Spacecraft guidance and control. Trajectories to Moon and Mars.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 419', 'Design Project II', 'Complete design project initiated in EGME 414. Construct prototype, model or components. Test proposed design and prepare a final design report. Teamwork and communications skills. Requires interim and final oral presentation. (6 hours laboratory)', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 421', 'Machine Design', 'Reliable design of machine components such as gears, springs, screws, fasteners, bearings, welded joints. Analysis techniques that are used to predict a component’s failure with/without factor of safety.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 422', 'Advanced Computer-Aided Design', 'Modeling, assembly and design documentation using current CAD software (e.g. CATIA or Creo). Design mechanical components and assemblies using advanced CAD software features - blends, drafts, user defined features, relations, family tables, assembly management. Collaborative design project, utilizing online resources. May be repeated for a maximum of 6 units.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 424', 'Data Acquisition and Instrumentation', 'Graphical programming; design and development of virtual instruments using LabVIEW programming environment; building applications for data acquisition and data reduction, measurement, testing and control of engineering systems; collaborative term project. May be repeated once for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 426', 'Design of Thermal and Fluid Systems', 'Integration of fundamental principles of thermodynamics, fluid mechanics, heat transfer and related subjects in the design of thermal and fluid systems. Design process and economics are applied to pumps, fans, turbines, boilers, piping systems, cross-flow and shell and tube heat exchangers.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 431', 'Mechanical Vibrations', 'Model and analyze single and multiple degrees of freedom systems. Response to forcing functions. Vibrations of machine elements. Design vibration isolation systems. Balance rotating machinery. Random excitation and response of mechanical structures.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 438', 'Analytical Methods in Engineering', 'Ordinary and partial differential equations with constant and variable coefficients; orthogonal functions; conformal mapping; potential theory; engineering applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 451', 'Heating, Ventilating and Air Conditioning Systems', 'Fundamentals of controlling heating, ventilating and air conditioning systems. Theory and analysis of fundamental thermodynamics relating to these systems. Laboratory demonstrations of actual systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 452', 'Fluid Machinery', 'Thermal and hydraulic design and analysis of pumps, fans, turbines and compressors. Component selection, system design and performance evaluations.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 454', 'Optimization of Engineering Design', 'Applying analytical and computer optimization techniques to engineering design problems. Present design as an optimization task. One dimensional minimization. Unconstrained and constrained nonlinear programming. Approximation concepts. Duality. Computer applications to design problems using a general purpose optimization program.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 456', 'Introduction to Mechatronics for Engineers', 'Introduction to mechatronics. Design issues. Sensors, actuators, programmable controllers. Hardware components for control systems. System performance. Data acquisition and control. Mechatronic control in automated manufacturing. Advanced applications and case studies. Design project.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 459', 'Plastics and Other Non-Metallics', 'Simplified chemistry of plastics. Applications. Manufacturing processes. Methods for preventing deterioration of nonmetallic materials. Composites. Ceramics. Refractories. Wood. Destructive and nondestructive testing of nonmetallic materials.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 460', 'Failure of Engineering Materials', 'Imperfections in solids; fracture initiation and crack propagation; dislocations; yield point phenomenon; fatigue; creep; ultrasonic effects; radiation damage; stress corrosion; hydrogen embrittlement; failure of composite materials.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 461', 'Manufacturing Processes', 'Manufacturing processes. Metal joining processes. Casting, forging, powder metallurgy, machining and machining tools, finishing, coating, plating, non-metallic materials inspection and gaging, and tolerances.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 462', 'Composite Materials', 'Application, mechanical properties and fabrication studies of fiber reinforced composite materials, stress analysis of laminated anisotropic composite structures. Studies of special problems unique to composites.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 463', 'Introduction to Robotics', 'Kinematic, dynamic, control and programming fundamentals associated with industrial robots and programmable manipulators. Trajectory planning, application of robotics in manufacturing and integration of robots into flexible manufacturing systems.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 475', 'Acoustics and Noise Control', 'Basic phenomena on the propagation, absorption and generation of acoustic waves, specification and measurement of noise, effects of noise on speech and behavior, legal aspects of industrial and building noise, principles and application of noise control.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 476A', 'Dynamic Systems and Controls Laboratory', 'Dynamic systems, vibration, acoustics, other mechanical components; computer simulation of dynamic systems (Simulink and computer-aided data acquisition); robotics, computer controlled machining, automatic data acquisition. Computers in data acquisition, reduction, analysis. Requires a complete set of individual engineering laboratory reports. Must pass with a “C” (2.0) or better to count towards the upper-division writing requirement. (6 hours laboratory)', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 476B', 'Energy and Power Laboratory', 'Mass transfer, heat transfer and thermodynamic phenomena and their interaction with mechanical systems. Team experiment. Using computers in data acquisition, reduction and analysis. Requires a complete set of individual engineering laboratory reports. Must be passed with a “C” (2.0) or better to count towards the upper-division writing requirement. (C- is not a passing grade). (6 hours laboratory)', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 480', 'Human Factors in Engineering', 'Principles of design for making products and systems faster, easier and more effective to use. Design project using these principles that consider human capabilities and limitation of senses and responses to sensory stimuli. Physiological, psychological and work factors are evaluated for design of equipment, work methods, environments and standards.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 483', 'Computer-Integrated Manufacturing', 'Introduction to computer-aided manufacturing processes. CNC machines, robot and PLC programming. Design for CIM. Fixed and flexible manufacturing systems. Process planning and scheduling. Simulation software for manufacturing systems. Laboratory experiments.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 497', 'Undergraduate Project', 'Directed independent research or design project. Requires consent of instructor, adviser and, department head.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 499', 'Independent Study (1-3)', 'Specialized topics in engineering, selected in consultation with and completed under the supervision of the instructor. May be repeated for a maximum of 6 units. Requires approval of study plan by adviser and department head.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 508', 'Advanced Inviscid Fluid Flow', 'Two- and three-dimensional potential flow theory. Sources, sinks, vortices, Rankine bodies, free jets, channel flow, air foils. Introduction to computational fluid dynamics. Complex potential and various transformation techniques.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 511', 'Advanced Mechanical Vibrations', 'Vibrations in rotating and reciprocating machines; noise and vibration in fluid machinery; continuous systems; random vibrations; transient and nonlinear vibration, computer applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 512', 'Advanced Mechanical Design and Management', 'Advanced modern mechanisms. Analysis and synthesis of mechanisms. Advanced topics in computer-aided design of mechanical, thermal and fluid systems. Methodology of modern design. Optimization in design.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 516', 'Advanced Radiation Heat Transfer', 'Radiation heat transfer, including the study of the geometric shape factors, ideal (black) and real systems, and energy transfer in absorbing, scattering and emitting media, and radiation combined with other modes of energy transfer.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 520', 'Advanced Viscous Fluid Flow', 'Fundamental equations of viscous fluid flow. Viscous drag estimation. Drag reduction methods. Laminar and turbulent internal and external flows. Introduction to instability and transition.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 526', 'Advanced Convective Heat Transfer', 'Convective heat transfer; heat transfer in external and internal flow fields for both laminar and turbulent fluid flow, applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 530', 'Advanced Strength of Materials', 'Energy methods. Castilian’s theorem. Curved beams, beams on elastic supports, thick wall cylinders, shrink fits, localized stress, column instability, failure theories, bearings.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 536', 'Advanced Conduction Heat Transfer', 'Conduction heat transfer; Bessel and Legendre functions, Laplace transforms, eigenfunctions, Fourier series solutions, heat sources and sinks, multidimensional problems, transient systems and numerical methods (finite difference and finite element methods).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 538', 'Advanced Engineering Analysis', 'Partial differential equations in engineering, numerical techniques, integral equations, engineering applications.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 540', 'Computer Applications In Engineering Design', 'Computers and microprocessors in engineering design. Design methodology, modeling and simulation. Geometric modeling. Design optimization. Expert systems in engineering design. Generalized programs and simulation languages are emphasized.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 541', 'Finite Element Method for Mechanical Engineers', 'Matrix formulation of basic equations in steady state and transient heat conduction. Elements and interpolation functions. Non-linear problem formulation. Finite element computer programs in heat transfer, fluid dynamics and design.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 576', 'Advanced Dynamics and Control of Mechanical Systems', 'Advanced study of the dynamics and control of mechanical systems including: state space modeling, Lyapunov stability, modern design techniques and case studies.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 597', 'Project (1-6)', 'May be repeated for a maximum of 6 units. Requires consent of Graduate Program Adviser.', 1, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 598', 'Thesis (1-6)', 'May be repeated for a maximum of 6 units. Requires consent of Graduate Program Adviser.', 1, 6, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('EGME 599', 'Independent Graduate Study (1-3)', 'Open to graduate students only by consent of Mechanical Engineering graduate program adviser. May be repeated for a maximum of 6 units only upon approval by the graduate program adviser. Requires classified graduate status.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLSC 101', 'Leadership and Personal Development', 'Introduces personal challenges and competencies that are critical for effective leadership. How personal development of life skills such as critical thinking, goal setting, time management, physical fitness and stress management relate to leadership, officership and the Army profession. Group Physical Training (PT) three days a week to build muscular endurance and unit cohesion. (1.5 hours of lecture, 3 hours laboratory, 3 hours PT).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLSC 102', 'Introduction to Tactical Leadership', 'Leadership fundamentals, such as setting direction, problem solving, listening, presenting briefs, providing feedback and using effective writing skills. Dimensions of leadership values, attributes, skills and actions in the context of practical, hands-on and interactive exercises. Group Physical Training (PT) three days a week to build muscular endurance and unit cohesion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLSC 201', 'Innovative Team Leadership', 'Dimensions of creative and innovative tactical leadership strategies and styles by examining team dynamics and two historical leadership theories that form the basis of Army leadership framework: trait and behavioral theories. Practice aspects of personal motivation and team building in the context of planning, executing and assessing team exercises. Group Physical Training (PT) three days a week to build muscular endurance and unit cohesion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLSC 202', 'Foundations of Tactical Leadership', 'Challenges of leading tactical teams in the complex Contemporary Operating Environment (COE). Dimensions of terrain analysis, patrolling and operation orders. Theoretical basis of the Army leadership framework explores the dynamic of adaptive leadership in the context of military operations. Group Physical Training (PT) three days a week to build muscular endurance and unit cohesion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLSC 301', 'Adaptive Tactical Leadership', 'Challenges cadets to study, practice and evaluate adaptive tactical leadership skills as they are presented with challenging scenarios related to squad tactical operations. Students receive systematic and specific feedback on their leadership attributes and actions. Group Physical Training (PT) three days a week to build muscular endurance and unit cohesion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLSC 302', 'Leadership in Changing Environments', 'Increasingly intense situational leadership challenges to build cadet awareness and skills in leading tactical operations up to platoon level. Combat, stability and support operations. Explore, evaluate and develop skills in decision-making, persuading and motivating team members in the contemporary operating environment (COE). Group Physical Training (PT) three days a week to build muscular endurance and unit cohesion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLSC 401', 'Developmental Leadership', 'Develop proficiency in planning, executing and assessing complex operations, functioning as a member of a staff and providing performance feedback to subordinates. Situational opportunities to assess risk, make ethical decisions and lead fellow ROTC cadets. Lessons on military justice and personnel processes to prepare for transition to becoming Army officers. Group Physical Training (PT) three days a week to build muscular endurance and unit cohesion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLSC 402', 'Adaptive Leadership', 'Dynamics of leading in the complex situations of current military operations in the contemporary operating environment (COE). Differences in customs and courtesies, military law, principles of war and rules of engagement in the face of international terrorism. Aspects of interacting with non-governmental organizations, civilians on the battlefield and host nation support. Group Physical Training (PT) three days a week to build muscular endurance and unit cohesion.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLSC 450', 'Military History Seminar', 'Selected case studies in military history as they relate to the modern challenges facing the American profession of arms. Written reports, oral presentations, discussion and field study. Satisfies commissioning requirements.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ARAB 101', 'Fundamental Arabic-A', 'Introduction to essentials of Modern Standard Arabic vocabulary and structures. Basic reading, writing, and conversational skills using culturally appropriate language. Conducted primarily in Arabic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ARAB 102', 'Fundamental Arabic-B', 'Continuation of systematic introduction of fundamental vocabulary and grammatical structures of Modern Standard Arabic. Sustained development of reading, writing and speaking skills with a focus on culture. Conducted primarily in Arabic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ARAB 203', 'Intermediate Arabic-A', 'Instruction in listening and reading comprehension, and oral and writing practice, in Arabic based on cultural and literary materials, with further development in vocabulary and grammar. Conducted primarily in Arabic.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ARAB 299', 'Directed Study (1-3)', 'Supervised research projects in Arabic language, literature, culture, linguistics or business, to be taken with consent of instructor and department chair. May be repeated for credit for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 101', 'Fundamental Chinese-A', 'For non-native Chinese speakers. Develop listening and reading comprehension and speaking. Introduces writing and develops cultural awareness to communicate on a basic level. Conducted primarily in Chinese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 102', 'Fundamental Chinese-B', 'For non-native speakers of Chinese. Continue developing listening and reading comprehension, speaking and writing to communicate on a basic level. Conducted primarily in Chinese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 201', 'Mandarin Chinese for Chinese Speakers-A', 'Expands oral competencies and develops reading and writing up to 800 characters. Conducted primarily in Chinese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 202', 'Mandarin Chinese for Chinese Speakers-B', 'Expands oral competencies and develops reading and writing up to 1,200 characters. Conducted primarily in Chinese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 203', 'Intermediate Chinese-A', 'Listening and reading comprehension, and oral and writing practice in Chinese based on cultural and literary materials, with further development in vocabulary and grammar. Conducted primarily in Chinese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 204', 'Intermediate Chinese - B', 'Continued development of communicative competence in Mandarin Chinese with a focus on listening, speaking, reading, writing, and culture. Vocabulary building and developing grammatical accuracy. Conducted primarily in Chinese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 299', 'Directed Study (1-3)', 'Supervised research projects in Chinese language, literature, culture, linguistics, or business, with consent of instructor and department chair. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 310', 'The Art of War and Intercultural Management Strategies', 'Develop an understanding of Chinese ancient strategies for understanding and managing people in dynamic cultural environments, from an organizational and intercultural management perspective. Requires intermediate to low competency in reading, writing, and speaking Mandarin Chinese (testing may be required). Conducted primarily in Chinese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 311', 'Silk Roads and Ancient Globalization', 'Practice Mandarin Chinese and learn about Chinese culture in the context of studying the Silk Roads and ancient globalization. Conducted primarily in Chinese. Requirement: Intermediate to low competency in reading, writing, and speaking Mandarin Chinese (testing may be required).', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 315', 'Introduction to Chinese Civilization', 'Social, intellectual and artistic heritage of Chinese civilization. Reading and discussion of characteristics of Chinese civilization while strengthening linguistic facility in Mandarin Chinese. Conducted in Chinese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 325', 'Contemporary Chinese Culture', 'Reading and discussion to develop understanding of the social, political, economic and intellectual problems, trends and issues of present-day China while strengthening linguistic ability in Mandarin Chinese. Conducted in Chinese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('CHIN 499', 'Independent Study (1-3)', 'Supervised research projects in Chinese language, literature, culture, linguistics, or business, with consent of instructor and department chair. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 101', 'Fundamental French-A', 'Introduces essentials of the French language: fundamental vocabulary and grammatical structures. Conversational and reading/writing skills are equally stressed, and relevant cultural aspects are considered. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 102', 'Fundamental French-B', 'Continuation of systematic introduction of fundamental vocabulary and grammatical structures. Maintains equal emphasis on speaking and reading/writing skills, along with the study of French culture. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 203', 'Intermediate French-A', 'Intensive practice in conversation and composition involving intermediate-level use of language and further exploration of French culture. Practice in the language laboratory is required. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 204', 'Intermediate French-B', 'Intensive review of grammatical structures; develop mastery of conversational and compositional skills at the intermediate level. Practice in the language laboratory is required. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 300', 'Advanced Oral Expression and Phonetics', 'Developing oral control of the language through discussions, oral presentations, dialogues/ debate and further study of phonetics. Vocabulary development in areas of student concerns. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 307', 'Advanced Composition and Grammar', 'Helps achieve advanced levels of oral and written expression. Literary materials provide a basis for discussions, systematic study of complex modes of expression and thoughtful compositions. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 308', 'Advanced Composition and Grammar (3)', 'Helps achieve advanced levels of oral and written expression. Literary materials provide a basis for discussions, systematic study of complex modes of expression and thoughtful compositions. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 310', 'French in the Professional World', 'Working knowledge of spoken and written professional language usage in the French-speaking world. Cultural and sociological contexts of professional interaction. Use of appropriate current periodicals and electronic resources. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 311', 'French for International Business', 'Provides experience in reading comprehension and analyzing materials dealing with economic and political realities of international trade in the French-speaking world. Use of appropriate current periodicals and electronic resources. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 315', 'Origins of Modern France', 'Social, intellectual and artistic origins of French civilization. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 325', 'Contemporary French Civilization', 'Contemporary French culture organized along the lines of economics, geography, political life, social and artistic institutions. Current events are illustrated by recent documents (TV news, internet, videos, articles, films) and activities, including group presentations and debates. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 375', 'Explorations in Literature', 'Promotes deeper understanding and appreciation of French literary texts. Each genre (narrative, dramatic, poetic) introduces great writers. In-depth study of selected works initiates students to critical modes of reading and tools for literary analysis. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 407', 'French Film', 'Developing art of the French film, with special emphasis on the many roles of language. Montage, visual/verbal meaning, literary/cinematic narrative, non-realistic language, read language, non-narrative continuity. Conducted in English.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 408', 'Advanced Writing: French Syntax and Morphology', 'Mastery of forms and structure of the French language. Analysis and guided composition of various styles of discourse. Mood, sequence of tenses, voice, aspects and nuances of meaning. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 409', 'Techniques of French-English Translation', 'Overview of theories of translation; examines several types and examples of translation (technical to literary). Actual translation from English to French and French to English.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 435T', 'Topics in French/Francophone Culture', 'Different “texts” (cinema, the media, internet, literature, art) centered around cultural topics (e.g., “City and Country,” “The Outsider”). Tools to understand French-speaking culture(s), from recent social issues to classic art and literature. Course may be repeated with different topics for a maximum of 9 units. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 466', 'Introduction to French Linguistics', 'Analytical procedures of general linguistics applied to French. Structural contrasts between French and English. Applying linguistic analysis to teaching modern foreign languages. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 470', 'French Literature and Power', 'Socio-political dimensions of French literature throughout its history. Expressions of alliance with, or resistance to, the established political order, from the medieval epic through 20th century literary texts. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 471', 'Literature and the Human Psyche', 'Psychological explorations in French literature - from the Renaissance through the 20th century - through texts, which provide insights into the human psyche and shape our notion of the self at different moments of French cultural history. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 472', 'Philosophical Exploration in Literature', 'Philosophical dimensions of French literature throughout its history. Interrogations about the human condition, and the role and place of human consciousness in the universe will be guiding theme in texts ranging from the Renaissance through the 20th century. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 485', 'Senior Seminar in French Studies', 'Students analyze and synthesize, debate and evaluate their own and other students’ individualized research projects on social, literary, linguistic, cultural and/or philosophical issues related to the French-speaking world. Conducted in French.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('FREN 499', 'Independent Study (1-3)', 'Supervised projects in French language, linguistics, culture, or literature. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 101', 'Fundamental German-A', 'Develop listening and reading comprehension, speaking and cultural awareness to communicate on a basic level. Introduction to customs and culture of German-speaking countries. Conducted primarily in German.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 102', 'Fundamental German-B', 'Continued development of listening and reading comprehension, speaking, writing and cultural awareness to communicate on a basic level. Further study of customs and culture of German-speaking countries. Conducted primarily in German.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 203', 'Intermediate German-A', 'Develop listening comprehension and speaking. Vocabulary building and developing conversational skills. Conducted in German. May be taken concurrently with GRMN 204 or GRMN 214.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 204', 'Intermediate German-B', 'Develop listening and reading comprehension and writing. Vocabulary building and developing writing competency. Conducted in German. May be taken concurrently with GRMN 203 or GRMN 214.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 214', 'Intermediate Reading-B', 'Continued refinement of reading comprehension based on authentic materials. Conducted in German. May be taken concurrently with GRMN 203 or 204.', 2, 2, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 299', 'Directed Study (1-3)', 'Supervised study projects in the German language. May be repeated for a maximum of 6 units. Requires consent of instructor and department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 300', 'German Conversation', 'Open to lower-division students with consent of instructor. Develop oral competencies in the context of students’ own or contemporary concerns. Conducted in German.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 305', 'Advanced Conversation and Composition', 'Open to lower-division students with consent of instructor. Free oral and written expression. Conducted in German.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 310', 'German in the Business World', 'Working knowledge of business language in the German-speaking world. Business correspondence, conversation between business partners and the language of advertising. Conducted in German.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 311', 'German for International Business', 'Expands reading comprehension through authentic texts and on building vocabulary of the German business world; overview of the German economy and business practices. Conducted in German. Requires intermediate competency; GRMN 310 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 315', 'Introduction to German Civilization', 'Readings and discussions in German literature, arts and institutions to develop insights into German culture. Conducted in German.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 325', 'Current Trends in Culture of German-Speaking Peoples', 'Readings and discussion of German contributions to present-day civilization while strengthening facility with German language. Conducted in German.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 335', 'Introduction to Literature', 'Introduction to the art of literature in a cultural context. Analyze and interpret various texts. Conducted in German. Requires advanced competency.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 399', 'German Phonetics', 'Analysis of pronunciation and intensive practice of phonetic patterns, including intonation. Develop conversational competency. May be repeated for credit, but only three units may count toward German major.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 400', 'Advanced Conversation Practice and Vocabulary Expansion', 'Intensive oral practice with emphasis on vocabulary expansion. Conducted in German.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 405', 'Advanced Writing and Speaking', 'Practice writing on various topics in detail, expressing hypotheses and presenting arguments or points of view accurately and effectively. Development differences of formal and informal style. Conducted in German.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('GRMN 499', 'Independent Study (1-3)', 'Supervised research projects in German language or literature to be taken only with consent of instructor and department chair. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ITAL 101', 'Fundamental Italian-A', 'Develop listening and reading comprehension, speaking and writing, and cultural awareness to communicate on a basic level with a focus on oral expression. Introduction to Italian customs, culture and civilization. Conducted primarily in Italian.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('ITAL 102', 'Fundamental Italian-B', 'Continued development of listening and reading comprehension, speaking and writing, and cultural awareness to communicate on a basic level with an emphasis on oral expression. Further study of Italian customs, culture and civilization. Conducted primarily in Italian.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 100', 'Japanese Conversation for Beginners', 'Introduction to spoken Japanese, with emphasis on vocabulary development at the beginning levels. For students who would like to learn conversational Japanese without having to learn the writing system.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 101', 'Fundamental Japanese-A', 'Develop listening and reading comprehension, speaking, writing, and cultural awareness to communicate on a basic level in Japanese. Introduction to Japanese customs, culture and civilization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 102', 'Fundamental Japanese-B', 'Continued development of listening and reading comprehension, speaking, writing, and cultural awareness to communicate on a basic level in Japanese. Further study of Japanese customs, culture and civilization.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 203', 'Intermediate Japanese-A', 'Develop listening and reading comprehension, and oral and written proficiency in Japanese based on cultural and literary materials. Review and introduce grammar. Conducted primarily in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 204', 'Intermediate Japanese-B', 'Continued development of listening and reading comprehension, and oral and written proficiency in Japanese based on cultural and literary materials. Review and introduce grammar. Conducted primarily in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 299', 'Directed Study (1-3)', 'Supervised study projects in Japanese language or literature. May be repeated for a maximum of 6 units. Requires consent of instructor and department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 305', 'Advanced Japanese-A', 'Practice in four skills of advanced Japanese, emphasizing reading comprehension in the context of contemporary concerns. Conducted in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 306', 'Advanced Japanese-B', 'Practice in four skills of advanced Japanese, emphasizing reading comprehension in the context of contemporary concerns. Conducted in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 307', 'Advanced Spoken Japanese', 'Spoken aspect of advanced Japanese through dialogues, discussions and oral presentations in the context of contemporary concerns. Conducted in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 308', 'Advanced Grammar and Composition', 'Helps achieve an advanced level of written expression in Japanese and cultural awareness through reading and writing on various topics. Further develop writing skills in Japanese using “kyoiku-kanji” with accurate grammar. May be repeated once for credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 310', 'Japanese for Business', 'The practical vocabulary and structure of business language, as well as the cultural background of business procedures in the Japanese business world. Conducted in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 311', 'Japanese for International Business', 'Vocabulary and language structures for Japanese in the international business world and related economic situations. Comprehension of business terminology through conversation, reading and writing. Conducted in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 390', 'Japanese Culture and Society: Anime', 'Japanese culture and society, as well as multicultural analysis of global issues as reflected in Japanese animated films. Conducted in English.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 420', 'Medieval Japanese Literature', 'Masterpieces of Japanese literature from eighth to 16th centuries and their relationship to cultural, historical and intellectual developments in these eras. Conducted primarily in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 440', 'Modern and Contemporary Japanese Literature', 'Literary use of language, cultural production, reading and critical evaluation of literary works. Reading excerpts of modern Japanese literature on various topics. Conducted primarily in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 466', 'Introduction to Japanese Linguistics', 'Analytical procedures of general linguistics as applied to phonological, semantic, morphological, syntactic and discourse aspects of Japanese. Conducted primarily in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 467', 'Japanese Language and Society', 'Introduces the methodology for analyzing the Japanese language in its social dimension. Major dialectal areas in Japan and their linguistic characteristics, social class and language, and language and gender. Conducted primarily in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 468', 'Japanese-English Contrastive Analysis', 'Contrastive analysis of phonological, lexical, syntactic and discourse aspects of Japanese and English. Conducted primarily in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 485T', 'Senior Seminar: Variable Topics in Japanese', 'Research and discussion of a cultural, literary or linguistic theme. Subject varies and is announced in the class schedule. May be repeated once for credit with different topic. Conducted primarily in Japanese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('JAPN 499', 'Independent Study (1-3)', 'Supervised projects in Japanese language or literature to be taken with consent of instructor and department chair. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KORE 101', 'Fundamental Korean-A', 'Develop listening and reading comprehension, speaking and writing, and cultural awareness to communicate on a basic level. Introduction to Korean customs, culture and civilization. Conducted primarily in Korean.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KORE 102', 'Fundamental Korean-B', 'Continued development of listening and reading comprehension, speaking and writing, and cultural awareness to communicate on a basic level. Further study of Korean customs, culture and civilization. Conducted primarily in Korean.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KORE 203', 'Intermediate Korean-A', 'Listening and reading comprehension, as well as oral and writing competence in Korean involving intermediate level language based on cultural materials with further exploration of Korean culture. Conducted primarily in Korean.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('KORE 299', 'Directed Study (1-3)', 'Supervised research projects in Korean language, literature, culture, linguistics or business. May be repeated for a maximum of 6 units. Requires consent of instructor and department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLNG 301', 'Writing in an Intercultural Context', 'Expository writing and research writing related to intercultural themes. Meets the classroom portion of the upper-division writing requirement for foreign language majors.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLNG 495', 'Internship in Modern Languages', 'Supervised field experience related to Modern Languages at a public or private institution. Requires using the target language at the placement site. Credit/No Credit.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('MLNG 496', 'Student-to-Student Tutorials (1-3)', 'Consult Student-to-Student Tutorials in this catalog for more information. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PERS 102', 'Fundamental Persian-B', 'Continued introduction to Persian culture. Students express themselves in oral and written forms at a basic/intermediate level about cultural topics, such as technology, art, daily activities, work environment, leisure, travel and multiculturalism. Conducted primarily in Persian.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PERS 299', 'Directed Study (1-3)', 'Supervised research projects in Persian language, literature, culture, linguistics or business. May be repeated for a maximum of 6 units. Requires consent of instructor and department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PERS 499', 'Independent Study (1-3)', 'Supervised research projects in Persian language, literature, culture, linguistics or business. May be repeated for a maximum of 6 units. Requires consent of instructor and department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PORT 320', 'Introduction to Luso-Brazilian Culture and Civilization', 'Main currents of Portuguese culture and civilization and Brazil’s intellectual and artistic development from discovery to independence. Conducted in Portuguese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('PORT 499', 'Independent Study (1-3)', 'Supervised projects in Portuguese language or literature to be taken with consent of instructor and department chair. May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 101', 'Fundamental Spanish-A', 'Develop listening and reading comprehension, speaking, writing and cultural awareness to communicate on a basic level. Introduction to customs, culture and civilization of Spanish-speaking communities. Conducted primarily in Spanish.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 102', 'Fundamental Spanish-B', 'Continued development of listening and reading comprehension, speaking, writing and cultural awareness to communicate on a basic level. Introduction to customs, culture and civilization of Spanish-speaking communities. Conducted primarily in Spanish.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 202', 'Spanish for Spanish Speakers', 'Intermediate course designed to further develop existing communicative skills in Spanish. May not receive credit for both SPAN 202 and SPAN 204. Conducted in Spanish.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 203', 'Intermediate Spanish-A', 'Develop listening and reading comprehension, speaking and writing Spanish based on cultural and literary materials. Oral expression and developing correct pronunciation. Conducted in Spanish. Concurrent enrollment in SPAN 213 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 204', 'Intermediate Spanish-B', 'Continued development of listening and reading comprehension, practice in speaking and writing Spanish based on cultural and literary materials. Vocabulary building and developing grammatical accuracy. Conducted in Spanish. Concurrent enrollment in SPAN 214 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 213', 'Intermediate Conversation', 'Practice in oral expression. Not open to students with native-speaking proficiency in Spanish. Conducted in Spanish. Concurrent enrollment in SPAN 203 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 214', 'Intermediate Composition', 'Practice in written expression based on cultural and literary materials. Conducted in Spanish. Concurrent enrollment in SPAN 204 recommended.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 556', 'Graduate Seminar: Spanish Poetry', 'Chronological overview of Peninsular poetry with special attention on specific authors and movements. Conducted in Spanish.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 557', 'Graduate Seminar: Spanish-American Poetry', 'Chronological overview of Spanish-American poetry from 1888 (Latin American Modernism) to Vanguardist and present day poetry and “Anti-Poetry.” Conducted in Spanish.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 567', 'Graduate Seminar: Spanish-American Novel', 'Historical overview of the development of the Spanish- American novel from the Colonial period (picaresque) to the Modern Experimental Novel. Conducted in Spanish.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 571', 'Graduate Seminar: Spanish Prose and Narrative Fiction', 'An in-depth study of major prose and narrative works from various historical periods of Spanish literature. Conducted in Spanish.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 575', 'Graduate Seminar: Spanish Drama', 'Chronological overview of Peninsular drama, emphasizing major authors and their most representative works. Conducted in Spanish.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 576T', 'Graduate Seminar: Hispanic Topics', 'Contemporary Spanish culture, contemporary Spanish-American culture, El Ensayo y La Critica Literaria Hispano-Americana. May be repeated once with different subject matter. Conducted in Spanish.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('SPAN 599', 'Independent Graduate Research (1-3)', 'Supervised research projects in Spanish language or literature. May be repeated for a maximum of 6 units. Requires fluency in Spanish and consent of instructor.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 500', 'Fundamentals in TESOL', 'Prepares for coursework offered in the M.S. TESOL and TESOL Certificate Programs and for careers in TESOL. Learn requisite skills for teaching ESL/EFL classes at all levels of instruction and to be professionals in the field. May be repeated once for credit. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 509', 'Advanced Principles of TESOL: Listening/Speaking Focus', 'Theories, methods and procedures for teaching listening and speaking skills to second language learners. Planning and delivering communicative ESL/EFL lessons.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 510', 'Advanced Principles of TESOL: Reading/Writing Focus', 'Theories, methods and procedures for teaching functional and academic reading and writing skills to second language learners. Planning and delivery of content-based ESL/EFL lessons.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 511', 'Teaching English Abroad', 'Understanding the cultural and socio-political significance of teaching English outside the U.S. Methods, techniques, materials, classroom management and evaluation in programs abroad. Create or adapt materials for a selected country or region.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 515', 'Pedagogical Grammar in TESOL', 'Systematic approach to the theories and practical aspects of teaching grammar to non-native speakers of English within a communicative framework. Ordering, selecting and preparing appropriate materials and activities. Expands on concepts introduced in TESL 500.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 520', 'Teaching Pronunciation and Oral Discourse in TESOL', 'Prepares teacher trainees with a working knowledge of phonological and oral discourse terms and concepts; and explores strategies for designing and teaching ESL/EFL lessons that include attention to oral communication and pronunciation enhancement.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 525', 'Teaching Vocabulary in the ESL/EFL Classroom', 'Complexities of vocabulary knowledge and the linguistic and cultural aspects of vocabulary learning. Applies theories and research findings to the classroom. Instruction in contextualized vocabulary learning and appropriate dictionary use.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 527', 'Second Language Acquisition', 'Methodology for research in second language acquisition and development; socio-linguistic and psycholinguistic patterns in bilingualism; interactions of language and culture in the language acquisition process.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 530', 'Research Methods for TESOL and Applied Linguistics', 'Basic familiarity with aspects of research design, and develop an understanding of quantitative and qualitative research methods. Training in becoming more effective consumers of research, and in conducting original empirical research. Pre- or', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 532', 'Technology in Second Language Learning', 'Key concepts and issues in educational technology relevant to teaching second languages. Theories, practices, and equipment currently used. Uses of computers, the internet, videos, etc.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 560', 'Second Language Assessment', 'Theories, issues, basic statistical concepts in second language testing and techniques for second language assessment. Practice analyzing commercial language tests and constructing tests for classroom use.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 595', 'Curriculum and Program Design for TESOL', 'Approaches for curriculum planning in TESOL. Needs assessment, goal setting, syllabus design and program evaluation. Produce projects for a specific group and setting.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 596', 'TESOL Practicum', 'Teaching English to speakers of other languages at Cal State Fullerton or other schools. Supervised by instructor and supervisors. Seminar meetings by arrangement. Requires appropriate program core courses (TESOL Certificate or M.S. Education-TESOL); consent of instructor or adviser.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('TESL 599', 'Independent Graduate Research (1-3)', 'Supervised research projects in teaching English to speakers of other languages (TESOL). May be repeated for a maximum of 6 units.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 101', 'Fundamntal Vietnamese - A', 'Develop listening and reading comprehension, speaking and writing, and cultural awareness to communicate on a basic level, with a focus on oral expression. Introduction to Vietnamese customs, culture and civilization. Conducted primarily in Vietnamese. Intended for beginners with no background in the language.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 102', 'Fundamntal Vietnamese - B', 'Continued development of listening and reading comprehension, speaking and writing, and culture awareness to communicate on a basic level. Further study of Vietnamese customs, culture and civilization. Conducted primarily in Vietnamese. Not open to students with significant proficiency in Vietnamese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 201', 'Vietnamese for Vietnamese Speakers-A', 'Intermediate course to develop communication through reading and writing, and to improve oral communication. Requires conversational proficiency.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 202', 'Vietnamese for Vietnamese Speakers-B', 'Develop reading/writing skills. Study broad range of topics; write articles and letters, as well as essays and reports on cross-cultural topics.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 203', 'Intermediate Vietnamese-A', 'Listening and reading comprehension, and oral and writing competence in Vietnamese involving intermediate level language based on cultural materials; further exploration of Vietnamese culture. Conducted primarily in Vietnamese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 204', 'Intermediate Vietnamese - B', 'Continued development of communicative competency in Vietnamese, focusing on listening, speaking, reading, writing and culture at the intermediate level. Building vocabulary and developing grammatical accuracy. Conducted primarily in Vietnamese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 299', 'Directed Study (1-3)', 'Supervised research projects in Vietnamese language, literature, culture, linguistics or business. May be repeated for a maximum of 6 units. Requires consent of instructor and department chair.', 1, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 310', 'Vietnamese for Business', 'Improve oral and written Vietnamese communication skills in business settings, as well as foster their understanding of the cultural background of the Vietnamese business environment. Conducted in Vietnamese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 311', 'Vietnamese for International Business', 'Develop competency needed for communication in various business settings, focusing on international business issues such as import, export, foreign investment, and marketing.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 315', 'Vietnamese Civilization', 'Chronological review of Vietnamese civilization from its earliest history to the 16th century, focusing on ideologies, institutions, literature, and arts. Conducted in Vietnamese', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 325', 'Vietnamese Culture', 'Vietnamese culture since the 17th century to the present day. Ideologies, institutions, literature and arts. Conducted primarily in Vietnamese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 375', 'Introduction to Vietnamese Literature', 'Introduction to Vietnamese literature throughout its history, focusing on prose and poetry. Develops understanding of Vietnamese literature and culture, and strengthens ability to analyze literary texts using various literary theories. Conducted in Vietnamese.', 3, 3, FALSE, FALSE);
INSERT INTO courses (course_code, course_name, course_description, units_min, units_max, has_lab, includes_lab) VALUES ('VIET 499', 'Independent Study (1-3)', 'Supervised research projects in Vietnamese language, literature, culture, linguistics or business. May be repeated for a maximum of 6 units. Requires consent of instructor and department chair.', 1, 3, FALSE, FALSE);
